-- Poems batch 238
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('3bf17c58-59bf-4cf2-ac42-65997c237bac','毛竹山四首  其一','蕭立之','宋','宋诗','song-poetry','','[]','租地編茅且數椽，孤懸浮寄亦堪憐。',32,'全唐诗/poet.song.217000.json','["租地編茅且數椽，孤懸浮寄亦堪憐。", "山深無復農桑事，別有人間種藥田。"]'),
('d58f92ac-584b-419d-89e2-04bb5c1f44ea','毛竹山四首  其二','蕭立之','宋','宋诗','song-poetry','','[]','山圍水匝徑百里，樹老苔封知幾春。',32,'全唐诗/poet.song.217000.json','["山圍水匝徑百里，樹老苔封知幾春。", "誰遣五丁開棧徑，當時疑有避秦人。"]'),
('9380e5ea-1c2a-4f0d-8044-d9c6440d1633','毛竹山四首  其三','蕭立之','宋','宋诗','song-poetry','','[]','雲間樵子罕曾逢，時有携鑱採藥翁。',32,'全唐诗/poet.song.217000.json','["雲間樵子罕曾逢，時有携鑱採藥翁。", "樹樹山猿摇落日，榧林無實老秋風。"]'),
('ef020336-6775-4484-ad9f-d565d2409622','毛竹山四首  其四','蕭立之','宋','宋诗','song-poetry','','[]','道傍虎迹大如盌，落日平林客子驚。',32,'全唐诗/poet.song.217000.json','["道傍虎迹大如盌，落日平林客子驚。", "問宿轉灣知有店，山根一路筧泉聲。"]'),
('22f79500-465c-486d-a1de-cd3a7455e961','一翠亭二首  其一','蕭立之','宋','宋诗','song-poetry','','[]','隔水山青欲染衣，一簷雲影樹高低。',32,'全唐诗/poet.song.217000.json','["隔水山青欲染衣，一簷雲影樹高低。", "白鷗似笑客塵土，飛過亭前却下溪。"]'),
('14711b7d-3006-4665-829a-4ef3d7e185fe','一翠亭二首  其二','蕭立之','宋','宋诗','song-poetry','','[]','緣雲覓路石鈎衣，山谷曾來尚有碑。',32,'全唐诗/poet.song.217000.json','["緣雲覓路石鈎衣，山谷曾來尚有碑。", "黄帽打船催客去，一欄秋思是誰詩。"]'),
('abe920ab-6dc7-43dd-81f3-ed96b5744f60','失題  其一','蕭立之','宋','宋诗','song-poetry','','[]','涿水茫茫何處邊，此臺名姓爲誰傳。',32,'全唐诗/poet.song.217000.json','["涿水茫茫何處邊，此臺名姓爲誰傳。", "未論跨鯉當年事，有許溪山意亦仙。"]'),
('e551663a-7d31-46e1-b673-3bc25a94bdcf','失題  其二','蕭立之','宋','宋诗','song-poetry','','[]','臺上秋風草木疏，臺前清泚數遊鱼。',32,'全唐诗/poet.song.217000.json','["臺上秋風草木疏，臺前清泚數遊鱼。", "謫仙他日騎鯨去，未必三生不是渠。"]'),
('b8caee64-ea27-480d-8d17-d0f0d8f868f0','題揭梅窗詩卷二首  其一','蕭立之','宋','宋诗','song-poetry','','[]','吟得秋痕入鬢髭，梅花窗下一編詩。',32,'全唐诗/poet.song.217000.json','["吟得秋痕入鬢髭，梅花窗下一編詩。", "梅花奇處君知否，不在春風爛熳時。"]'),
('800b58ad-15cd-4052-b775-9994304836fe','題揭梅窗詩卷二首  其二','蕭立之','宋','宋诗','song-poetry','','[]','金膏水碧須滄海，萬里揚帆東更東。',32,'全唐诗/poet.song.217000.json','["金膏水碧須滄海，萬里揚帆東更東。", "我輩欲爲千歲計，古人還是幾生功。"]'),
('5203a236-36b4-4d3b-b839-748fbb330613','題東畈陳上舍吟稿二首  其一','蕭立之','宋','宋诗','song-poetry','','[]','后山詩法似參禪，參到無言意已傳。',32,'全唐诗/poet.song.217000.json','["后山詩法似參禪，參到無言意已傳。", "莫以家鷄疏野鶩，短檠疏雨月光前。"]'),
('6fd3558d-8b84-495d-aabc-edafe717e66a','題東畈陳上舍吟稿二首  其二','蕭立之','宋','宋诗','song-poetry','','[]','君家詩有簡齋翁，南渡流離語更工。',32,'全唐诗/poet.song.217000.json','["君家詩有簡齋翁，南渡流離語更工。", "好繼翁詩致華要，墨梅題入御屏風。"]'),
('72b2c6fd-0adc-4ac1-bf55-a04f9d87ee6f','題黄立軒西湖百詠三首  其一','蕭立之','宋','宋诗','song-poetry','','["\u897f\u6e56"]','東南詩境有湖山，愛子敲成百詠看。',32,'全唐诗/poet.song.217000.json','["東南詩境有湖山，愛子敲成百詠看。", "歷歷眼中都過盡，一檠風雨客窗寒。"]'),
('361cee9d-a283-44d9-a6c0-42c4f6d92541','題黄立軒西湖百詠三首  其二','蕭立之','宋','宋诗','song-poetry','','["\u897f\u6e56"]','欲雕好句老經行，讀子清吟客夢醒。',32,'全唐诗/poet.song.217000.json','["欲雕好句老經行，讀子清吟客夢醒。", "意象見前無筆力，一如前輩說西銘。"]'),
('6e06e823-20f0-4b46-9c7b-76ee44a1b12b','題黄立軒西湖百詠三首  其三','蕭立之','宋','宋诗','song-poetry','','["\u897f\u6e56"]','王氣隨潮到海壖，出湖車馬下湖船。',32,'全唐诗/poet.song.217000.json','["王氣隨潮到海壖，出湖車馬下湖船。", "可憐萬事如春夢，艷舞清歌過百年。"]'),
('a7a062a8-64a4-42c5-98a9-0c656abe85d3','題危定之芳洲吟卷','蕭立之','宋','宋诗','song-poetry','','[]','篝燈細讀芳洲卷，清似江南雪外枝。',32,'全唐诗/poet.song.217000.json','["篝燈細讀芳洲卷，清似江南雪外枝。", "吟到蛾燈最奇崛，猩毛筆後有君詩。"]'),
('b991d493-ede1-482d-b785-e21674232412','題穆叔晦雨凈風香亭三首  其一','蕭立之','宋','宋诗','song-poetry','','[]','壓簷秋影玉參差，小小游亭面面詩。',32,'全唐诗/poet.song.217000.json','["壓簷秋影玉參差，小小游亭面面詩。", "扁著凈香堪一笑，渠香元不要人知。"]'),
('bf56c5ea-b8b8-4845-837d-a476cd3bd2d5','題穆叔晦雨凈風香亭三首  其二','蕭立之','宋','宋诗','song-poetry','','[]','風標王謝佳子弟，氣岸夷齊舊典刑。',32,'全唐诗/poet.song.217000.json','["風標王謝佳子弟，氣岸夷齊舊典刑。", "騎馬紛紛塵及腹，幾人愛此竹間亭。"]'),
('006db383-e765-4e8a-871c-499fe38f477d','題穆叔晦雨凈風香亭三首  其三','蕭立之','宋','宋诗','song-poetry','','[]','別久重來有此亭，鳴球敲筑碎風櫺。',32,'全唐诗/poet.song.217000.json','["別久重來有此亭，鳴球敲筑碎風櫺。", "却憐客鬢垂垂白，不奈霜枝冉冉青。"]'),
('415e8494-5ecb-4834-b147-494fb510af3c','老嘆','蕭立之','宋','宋诗','song-poetry','','[]','學不前人生謾前，老來嫌怕占人先。',32,'全唐诗/poet.song.217000.json','["學不前人生謾前，老來嫌怕占人先。", "只便歲晚屠蘇酒，後飲翻成最少年。"]'),
('34b00cd2-07f0-4738-982f-b9ff868c5b74','寄題鄒氏觀梅亭二首  其一','蕭立之','宋','宋诗','song-poetry','','[]','歲晚纔花花已遲，於春何意獨先知。',32,'全唐诗/poet.song.217000.json','["歲晚纔花花已遲，於春何意獨先知。", "由來遲底應偏耐，不看南枝看北枝。"]'),
('7493744c-cd57-4795-b002-38d2ee38ef53','寄題鄒氏觀梅亭二首  其二','蕭立之','宋','宋诗','song-poetry','','[]','詩人愛梅說道理，弄影團香未覺難。',32,'全唐诗/poet.song.217000.json','["詩人愛梅說道理，弄影團香未覺難。", "枝上乾坤參得透，不妨來此倚闌干。"]'),
('c850a09c-aa13-4782-ba98-1e27b04acccf','次韻鄭琴山併謝中書君之貺三首  其一','蕭立之','宋','宋诗','song-poetry','','[]','詩來執熱濯寒淙，剪剪西風破玉蓉。',32,'全唐诗/poet.song.217000.json','["詩來執熱濯寒淙，剪剪西風破玉蓉。", "二十年間四方恨，不教東野化爲龍。"]'),
('cddffeef-edc0-43a8-b5c6-55412bb3ce63','次韻鄭琴山併謝中書君之貺三首  其二','蕭立之','宋','宋诗','song-poetry','','["\u897f\u6e56"]','我屋梅花爲客栽，吟梅君獨未能來。',32,'全唐诗/poet.song.217000.json','["我屋梅花爲客栽，吟梅君獨未能來。", "山中欠了連床約，却對西湖笑口開。"]'),
('354fcdb8-d812-47f0-9f6a-b3e9f12c7649','次韻鄭琴山併謝中書君之貺三首  其三','蕭立之','宋','宋诗','song-poetry','','[]','落筆何能觀堵牆，山間只合傲羲皇。',32,'全唐诗/poet.song.217000.json','["落筆何能觀堵牆，山間只合傲羲皇。", "慚君遺我湘枝束，愁與吟䯲一樣霜。"]'),
('8457afe9-15e7-4fbe-8708-6728a67a73f4','送雪溪徐高士之越三首  其一','蕭立之','宋','宋诗','song-poetry','','[]','清吟未了又成行，是處青山入瘦藤。',32,'全唐诗/poet.song.217000.json','["清吟未了又成行，是處青山入瘦藤。", "兩袖曉風荷葉露，自摇明月渡西興。"]'),
('f5ed2db8-d903-4e9d-901b-563526a97278','送雪溪徐高士之越三首  其二','蕭立之','宋','宋诗','song-poetry','','[]','雁雁欲啼江上秋，舊題詩在水邊樓。',32,'全唐诗/poet.song.217000.json','["雁雁欲啼江上秋，舊題詩在水邊樓。", "潮風一夜移帆去，明日書來是越州。"]'),
('e35bd1ae-71c4-4bf5-be1f-98d5f692e25f','送雪溪徐高士之越三首  其三','蕭立之','宋','宋诗','song-poetry','','[]','團扇應堪障夕暉，曉凉猶嫩且綀衣。',32,'全唐诗/poet.song.217000.json','["團扇應堪障夕暉，曉凉猶嫩且綀衣。", "去時寬著秋風擔，留貯千岩萬壑歸。"]'),
('c86cb62f-7a07-4dab-866a-ee676bd81e13','題楊達可梅樓二首  其一','蕭立之','宋','宋诗','song-poetry','','[]','何掾向來吟有閣，楊家今日築爲樓。',32,'全唐诗/poet.song.217000.json','["何掾向來吟有閣，楊家今日築爲樓。", "看他壓盡凡花倒，只放詩人出一頭。"]'),
('44cb2025-1273-4ca0-af90-b7f2f1a4aaec','題楊達可梅樓二首  其二','蕭立之','宋','宋诗','song-poetry','','[]','先生豪氣元龍似，眉骨凜凜閩山秋。',32,'全唐诗/poet.song.217000.json','["先生豪氣元龍似，眉骨凜凜閩山秋。", "從渠俗子卧地下，不是梅花不上樓。"]'),
('1f4f5a57-a1b4-46ee-b39c-98e7774836e5','校文京庠呈黄立軒朱南湖十首  其一','蕭立之','宋','宋诗','song-poetry','','[]','十日工夫不到詩，繩床兀兀夕陽低。',32,'全唐诗/poet.song.217000.json','["十日工夫不到詩，繩床兀兀夕陽低。", "黄昏幾點敲窗雨，又是西風趲木犀。"]'),
('83a9e8ef-529b-44fb-be60-1e5099dd42d6','校文京庠呈黄立軒朱南湖十首  其二','蕭立之','宋','宋诗','song-poetry','','["\u897f\u6e56"]','舊嫌詩被西湖隔，一笑誰教却此同。',32,'全唐诗/poet.song.217000.json','["舊嫌詩被西湖隔，一笑誰教却此同。", "爲有簡書閑不得，不知吟鬢又秋風。"]'),
('cb1ba4b1-a47a-4a5f-94de-b8df890b0e48','校文京庠呈黄立軒朱南湖十首  其三','蕭立之','宋','宋诗','song-poetry','','[]','西山南浦住經時，又住吳山送落暉。',32,'全唐诗/poet.song.217000.json','["西山南浦住經時，又住吳山送落暉。", "燕子不知家近遠，年年秋社一番歸。"]'),
('df041003-5a69-40bb-96b7-11d333b85111','校文京庠呈黄立軒朱南湖十首  其四','蕭立之','宋','宋诗','song-poetry','','["\u897f\u6e56"]','獨自携文校短長，隔簾人靜雨滄浪。',32,'全唐诗/poet.song.217000.json','["獨自携文校短長，隔簾人靜雨滄浪。", "龍公倒捲西湖水，一夜滿城荷氣香。"]'),
('cbb94021-4e08-4c03-b88d-128e13f3cff3','校文京庠呈黄立軒朱南湖十首  其五','蕭立之','宋','宋诗','song-poetry','','[]','遠枕驚回昨夜秋，月痕依約去年愁。',32,'全唐诗/poet.song.217000.json','["遠枕驚回昨夜秋，月痕依約去年愁。", "移牀欲避梧桐去，誰有西風背處樓。"]'),
('e236d1d6-2896-42d8-a4c6-776345e50351','校文京庠呈黄立軒朱南湖十首  其六','蕭立之','宋','宋诗','song-poetry','','[]','籠鼕飯鼓動回廊，乍換生綀浴晚凉。',32,'全唐诗/poet.song.217000.json','["籠鼕飯鼓動回廊，乍換生綀浴晚凉。", "雙鵲自閑來又去，不知簾底有人忙。"]'),
('f92a2a35-cc7d-41bf-9a61-a0c94b748768','校文京庠呈黄立軒朱南湖十首  其七','蕭立之','宋','宋诗','song-poetry','','[]','雪繞冰圍不可支，輕紈那得敵炎威。',32,'全唐诗/poet.song.217000.json','["雪繞冰圍不可支，輕紈那得敵炎威。", "雷公惡發夜來雨，試問熱官何處歸。"]'),
('777b7547-b86a-45d1-8174-37d80950c921','校文京庠呈黄立軒朱南湖十首  其八','蕭立之','宋','宋诗','song-poetry','','[]','山水宜秋風雨後，坐窗得瘦奈愁何。',32,'全唐诗/poet.song.217000.json','["山水宜秋風雨後，坐窗得瘦奈愁何。", "傳聞近長湖船價，天氣乍凉遊子多。"]'),
('537111b8-6384-4aa7-8f07-9ea9cbcb5512','校文京庠呈黄立軒朱南湖十首  其九','蕭立之','宋','宋诗','song-poetry','','[]','頭腦涔涔醉夢中，起梳短髮受西風。',32,'全唐诗/poet.song.217000.json','["頭腦涔涔醉夢中，起梳短髮受西風。", "青綀要換秋來著，自汲寒泉濯軟紅。"]'),
('812e7bc7-3424-4866-b721-1bf927137c74','校文京庠呈黄立軒朱南湖十首  其一○','蕭立之','宋','宋诗','song-poetry','','[]','月過闌干客睡遲，官河桐葉學鴉飛。',32,'全唐诗/poet.song.217000.json','["月過闌干客睡遲，官河桐葉學鴉飛。", "鬢絲不了三千丈，也費秋蟲促夜機。"]'),
('30262a23-490b-4330-a59c-5b8b101d8f5c','題修水黄公端梅溪二首  其一','蕭立之','宋','宋诗','song-poetry','','[]','種近春風鼎鼐家，竹籬茅舍亦光華。',32,'全唐诗/poet.song.217000.json','["種近春風鼎鼐家，竹籬茅舍亦光華。", "開時不作尋常實，著眼溪頭看此花。"]'),
('97ff6b01-2684-4701-9734-31ed74fafab3','題修水黄公端梅溪二首  其二','蕭立之','宋','宋诗','song-poetry','','[]','此地梅花非隠淪，向來雙井屬詩人。',32,'全唐诗/poet.song.217000.json','["此地梅花非隠淪，向來雙井屬詩人。", "如今添著調梅手，却與江南作好春。"]'),
('e9b53764-729a-4ac0-8fb0-7a8c2f2edfc4','偶成','蕭立之','宋','宋诗','song-poetry','','[]','雨妬遊人故作難，禁持閑了下湖船。',32,'全唐诗/poet.song.217000.json','["雨妬遊人故作難，禁持閑了下湖船。", "城中豈識農耕好，却恨慳晴放紙鳶。"]'),
('f4edba9e-0b6a-4385-b556-8bd4c7f8a717','絕句四首  其一','蕭立之','宋','宋诗','song-poetry','','[]','月落雲窗黑如漆，一紙家書燈下筆。',32,'全唐诗/poet.song.217000.json','["月落雲窗黑如漆，一紙家書燈下筆。", "不知昨夜秋淺深，五更枕前啼蟀蟋。"]'),
