('4c03ec4b-612a-4261-b5aa-8e1ca55d8160','題劍江姚叔宏吟卷三首  其一','蕭立之','宋','宋诗','song-poetry','','[]','寶劍能神雙玉龍，地靈人亦萬夫雄。',32,'全唐诗/poet.song.217000.json','["寶劍能神雙玉龍，地靈人亦萬夫雄。", "千年紫氣不消歇，吐向筆頭生白虹。"]'),
('92c160f9-4143-4a0e-867b-980e56e4956a','題劍江姚叔宏吟卷三首  其二','蕭立之','宋','宋诗','song-poetry','','[]','一編鼻祖晚唐詩，姚許齊名岱華低。',32,'全唐诗/poet.song.217000.json','["一編鼻祖晚唐詩，姚許齊名岱華低。", "天外鳳凰須得髓，可嗔兒輩厭家鷄。"]'),
('19e1fa2b-7c7d-4219-8cf6-d2c003d1f311','題劍江姚叔宏吟卷三首  其三','蕭立之','宋','宋诗','song-poetry','','[]','薄飯不羹春薺老，枉君遠道轡玲瓏。',32,'全唐诗/poet.song.217000.json','["薄飯不羹春薺老，枉君遠道轡玲瓏。", "金膏冰碧須滄海，萬里揚帆東更東。"]'),
('24fbe8ec-7b3c-461a-9582-ae6d3166f0bc','題劍江甘元英詩號溪山畫譜','蕭立之','宋','宋诗','song-poetry','','[]','一幅亭前溪與山，畫無好手記蒼寒。',32,'全唐诗/poet.song.217000.json','["一幅亭前溪與山，畫無好手記蒼寒。", "如今有問名亭意，只就君家畫譜看。"]'),
('b876f02f-1e55-4098-b8dd-109dbbaf9eeb','開元天寶雜詠 妖燭','蕭立之','宋','宋诗','song-poetry','','[]','燭似無情還有情，酒邊故故弄昏明。',32,'全唐诗/poet.song.217000.json','["燭似無情還有情，酒邊故故弄昏明。", "宴酣盡道誰能覺，□□□□玉笛聲。"]'),
('31558ae7-a167-450d-9265-6e6eac92eb2a','開元天寶雜詠 燈婢','蕭立之','宋','宋诗','song-poetry','','[]','風流看盡當時事，夜夜擎燈繡帳前。',32,'全唐诗/poet.song.217000.json','["風流看盡當時事，夜夜擎燈繡帳前。", "野草荒田自他日，斷無外傳與伶玄。"]'),
('c06f0c74-43db-4f43-b0d7-844fe0682b8c','開元天寶雜詠 冰山','蕭立之','宋','宋诗','song-poetry','','[]','冰山難倚子能知，如此嵩山只合歸。',32,'全唐诗/poet.song.217000.json','["冰山難倚子能知，如此嵩山只合歸。", "莫恨有頭擡不得，得擡頭處更危機。"]'),
('9a1d2bfe-38d7-4ebc-9477-2c290c2bcfb4','開元天寶雜詠 玉有太平字','蕭立之','宋','宋诗','song-poetry','','[]','瑞玉天開此日奇，分明中有篆文題。',32,'全唐诗/poet.song.217000.json','["瑞玉天開此日奇，分明中有篆文題。", "翠華不作西南幸，肯信漁陽有鼓鼙。"]'),
('6c409dc8-a83d-47cb-af54-bb9851500096','開元天寶雜詠 美人呵筆','蕭立之','宋','宋诗','song-poetry','','[]','凍筆能回雪殿春，君恩珍重遣宮嬪。',32,'全唐诗/poet.song.217000.json','["凍筆能回雪殿春，君恩珍重遣宮嬪。", "金花牋上清平樂，倚得詞工却誤人。"]'),
('9797906a-3ed9-481d-83f2-b7cc85b4382e','開元天寶雜詠 射團','蕭立之','宋','宋诗','song-poetry','','[]','四海昇平征戰息，宮中行樂外間無。',32,'全唐诗/poet.song.217000.json','["四海昇平征戰息，宮中行樂外間無。", "粉團滑膩猶□□，愁殺胡兒憶塞酥。"]'),
('791dc815-d767-4778-a7f9-4405427d5de8','開元天寶雜詠 風流陣','蕭立之','宋','宋诗','song-poetry','','[]','兩陣雌雄禁掖間，紛紛攻擊寸心寒。',32,'全唐诗/poet.song.217000.json','["兩陣雌雄禁掖間，紛紛攻擊寸心寒。", "風流天子貪行樂，不作伊川被髮看。"]'),
('2e06193c-03a4-4a6c-93c1-f41e8df922eb','開元天寶雜詠 失題','蕭立之','宋','宋诗','song-poetry','','[]','膩粉勻成玉筯垂，春風面面曉妝遲。',32,'全唐诗/poet.song.217000.json','["膩粉勻成玉筯垂，春風面面曉妝遲。", "妝成圖得君王顧，却爲君王讖別離。"]'),
('0e82d3d6-c5d4-4255-b202-faa1b0cb08c2','開元天寶雜詠 遊仙枕','蕭立之','宋','宋诗','song-poetry','','[]','一枕仙遊足自娛，蕭然清思離塵區。',32,'全唐诗/poet.song.217000.json','["一枕仙遊足自娛，蕭然清思離塵區。", "十洲三島經行處，知有岷峨劍閣無。"]'),
('ad594657-6fc4-462c-b36d-2ab51caf327e','開元天寶雜詠 失題','蕭立之','宋','宋诗','song-poetry','','[]','六軍難解驛門圍，此日回頭事事非。',32,'全唐诗/poet.song.217000.json','["六軍難解驛門圍，此日回頭事事非。", "千炬摇紅成底用，腥魂夜逐月明歸。"]'),
('85549aa8-4df9-4a1c-aff9-d33e201c0ea4','開元天寶雜詠 金函','蕭立之','宋','宋诗','song-poetry','','[]','山水有圖無逸換，錦坊興廢變初終。',32,'全唐诗/poet.song.217000.json','["山水有圖無逸換，錦坊興廢變初終。", "咸陽父老能言語，不在金函諫疏中。"]'),
('77a75c9a-a0a6-455f-9d15-8818980f7972','開元天寶雜詠 移春檻','蕭立之','宋','宋诗','song-poetry','','[]','東來西去木爲輪，異草名花易地春。',32,'全唐诗/poet.song.217000.json','["東來西去木爲輪，異草名花易地春。", "未必乾坤關氣數，世間何事不由人。"]'),
('7517fe05-50c1-4a65-a58c-fc180a93761a','開元天寶雜詠 辟寒犀','蕭立之','宋','宋诗','song-poetry','','[]','迢迢交趾到長安，黄色如金眼不看。',32,'全唐诗/poet.song.217000.json','["迢迢交趾到長安，黄色如金眼不看。", "闔殿春回人未覺，外間何處不風寒。"]'),
('e68baf62-1fd0-4e28-a548-c363b493e09f','開元天寶雜詠 有脚陽春','蕭立之','宋','宋诗','song-poetry','','[]','有脚□□□□□，開元人物曉天星。',32,'全唐诗/poet.song.217000.json','["有脚□□□□□，開元人物曉天星。", "滿頤雪刺歸何處，坐看秋風入禁庭。"]'),
('f6d781f6-6c6a-4cd3-92f0-d746436053c8','開元天寶雜詠 紅冰','蕭立之','宋','宋诗','song-poetry','','[]','當年召入即承恩，何事登車却斷魂。',32,'全唐诗/poet.song.217000.json','["當年召入即承恩，何事登車却斷魂。", "只道紅冰生別淚，不知殺氣滿乾坤。"]'),
('6e15d510-2303-4335-9374-16a0ac338dd0','開元天寶雜詠 失題','蕭立之','宋','宋诗','song-poetry','','[]','六宮粉黛謾三千，妃子椒房寵自專。',32,'全唐诗/poet.song.217000.json','["六宮粉黛謾三千，妃子椒房寵自專。", "應恨長門鎖秋鬢，君恩也賜洗兒錢。"]'),
('255db03b-a41d-44c3-89dc-a098edddef63','開元天寶雜詠 長湯十六所','蕭立之','宋','宋诗','song-poetry','','[]','賜浴華清總有名，長湯十六更泠泠。',32,'全唐诗/poet.song.217000.json','["賜浴華清總有名，長湯十六更泠泠。", "可憐洗□□□□，□洗胡塵一點腥。"]'),
('0ee29248-2e54-4f61-ba43-340a30c83981','開元天寶雜詠 失題','蕭立之','宋','宋诗','song-poetry','','[]','蛛絲卜巧對西風，歲歲佳期此夕同。',32,'全唐诗/poet.song.217000.json','["蛛絲卜巧對西風，歲歲佳期此夕同。", "誰道禁宮天共遠，他時言語出臨邛。"]'),
('8cb258bc-387c-4d15-bcab-367b35f282ce','贈鄧景憲','蕭立之','宋','宋诗','song-poetry','','[]','兩山不隔一層雲，金鯽池邊夜打門。',64,'全唐诗/poet.song.217000.json','["兩山不隔一層雲，金鯽池邊夜打門。", "袖有新詩期短鬢，室無奇字枉芳樽。", "客程懷抱仍春潦，人事間關可夢魂。", "離合悠悠自生理，別情吟恨不堪論。"]'),
('5be7912b-4157-4e35-8a94-ed483bf484ac','次李玉峰見寄','蕭立之','宋','宋诗','song-poetry','','[]','四方上下忽相從，君信西來我信東。',64,'全唐诗/poet.song.217000.json','["四方上下忽相從，君信西來我信東。", "剡雪不乘清夜興，軍山依舊夢魂中。", "合離有數機如髮，歲月無情鬢欲翁。", "斜照一林雲百樹，吟筒翻作遞愁筒。"]'),
('8dc060f2-9eca-48e6-a7b4-76b65301b03b','赴官舟中','蕭立之','宋','宋诗','song-poetry','','[]','蟄龍初動雨崢嶸，黄濁連宵與樹平。',64,'全唐诗/poet.song.217000.json','["蟄龍初動雨崢嶸，黄濁連宵與樹平。", "路入峽頭天一握，夢回蓬背月三更。", "江村無復魚鹽市，客飯初嘗菌蕨羹。", "小泊橋南沽斗酒，一街燈火灌嬰城。"]'),
('446c4da9-3675-4a51-9ead-fa7ec7328944','柬邵中立','蕭立之','宋','宋诗','song-poetry','','[]','金鯽池邊傷晚風，蓮花峯下倚長松。',64,'全唐诗/poet.song.217000.json','["金鯽池邊傷晚風，蓮花峯下倚長松。", "水程半月孤蓬雨，客飯渾家野寺鍾。", "心事歲寒詩眷屬，鬢根秋色老形容。", "片雲影裏湖湘隔，莫愛新吟寄短封。"]'),
('29859129-c2bd-432e-81dc-24a4c5f490fa','遊蘇仙山','蕭立之','宋','宋诗','song-poetry','','[]','壇下松聲江上潮，壇前天近北風高。',64,'全唐诗/poet.song.217000.json','["壇下松聲江上潮，壇前天近北風高。", "山腰洞黑藏丹竈，雲頂秋深落石桃。", "逆理偷生雖世論，離群獨立亦人豪。", "仙家儘有青精飯，不與吟翁綠鬢毛。"]'),
('833e0212-367d-4ee0-81d5-7f3e7bc26843','至日次韻','蕭立之','宋','宋诗','song-poetry','','[]','混闢無窮運以剛，積陰打底有微陽。',64,'全唐诗/poet.song.217000.json','["混闢無窮運以剛，積陰打底有微陽。", "驅馳道路年光晚，收拾身心意味長。", "三日南風天不雨，一編周易鬢微霜。", "乾坤只在梅花上，梅不能言心自香。"]'),
('4563c7b7-8459-4290-bb96-9c837748cf33','次府教一覽亭韻','蕭立之','宋','宋诗','song-poetry','','[]','秋膺重疊有誰編，客意難憑燕子傳。',64,'全唐诗/poet.song.217000.json','["秋膺重疊有誰編，客意難憑燕子傳。", "欲送寒衣仍冷雨，稍疑飛霧近南天。", "楊花舞歇春無力，湖水空明晚自烟。", "日日詩筒星火急，吟窗禿盡筆鋒尖。"]'),
('2508d708-3c84-45bf-bccb-f7c3b6debdd9','興寧界上','蕭立之','宋','宋诗','song-poetry','','[]','壓腦文書坐得牢，偶然散誕此江臯。',64,'全唐诗/poet.song.217000.json','["壓腦文書坐得牢，偶然散誕此江臯。", "一春冷雨鶑花老，十日新晴麻麥高。", "鳥跡窵留倉頡字，草香擷出屈平騷。", "不知何許繅車動，又送新絲入鬢毛。"]'),
('12ff4dc4-155d-45f1-bdb5-3a0c4d10953d','縣圃白蓮','蕭立之','宋','宋诗','song-poetry','','["\u897f\u6e56"]','四柱茅亭秋一間，礲冰琢玉照乾坤。',64,'全唐诗/poet.song.217000.json','["四柱茅亭秋一間，礲冰琢玉照乾坤。", "香分韓壽春衫味，花带萇弘冷袖痕。", "奔月蛻餘仙去骨，凌波招得別來魂。", "今宵睡足敲窗雨，家在西湖水滿門。"]'),
('65334d40-57eb-4416-a210-196e622ed9f9','丁巳除夕','蕭立之','宋','宋诗','song-poetry','','[]','攽春過了雪猶勍，枝北枝南開未曾。',64,'全唐诗/poet.song.217000.json','["攽春過了雪猶勍，枝北枝南開未曾。", "風雨閉門人守歲，江淮斷道士椎冰。", "說三生夢溪橋酒，抄一年詩紙帳燈。", "世事正長雙鬢短，客床無寐曲寒肱。"]'),
('13b9854d-be68-441b-98d6-db4a2a61d840','贈人','蕭立之','宋','宋诗','song-poetry','','[]','湘野源頭筇一枝，黄雲黑霧雨淋漓。',64,'全唐诗/poet.song.217000.json','["湘野源頭筇一枝，黄雲黑霧雨淋漓。", "天公有眼能青白，世路無情謾嶮巘。", "場屋秋風三島夢，江湖夜雨四愁詩。", "蒼苔翠竹簷聲裏，重瀹茶甌當酒巵。"]'),
('2e7e185f-7f25-4df4-9e51-938a85c95e54','過衡山','蕭立之','宋','宋诗','song-poetry','','["\u8861\u5c71", "\u6d1e\u5ead\u6e56"]','此是湘南第幾程，楚天空曠入深溟。',64,'全唐诗/poet.song.217000.json','["此是湘南第幾程，楚天空曠入深溟。", "九千丈月照衡嶽，八百里程歸洞庭。", "恨入江蘺騷骨冷，夢回湘竹淚花青。", "客中總爲貪程熟，落棗風高我自醒。"]'),
('1168bc08-1295-44be-a4c5-81167d010200','次丁宣尉韻','蕭立之','宋','宋诗','song-poetry','','[]','城郭秋深鵲樹空，練衣不抵夜來風。',64,'全唐诗/poet.song.217000.json','["城郭秋深鵲樹空，練衣不抵夜來風。", "雁何去處有書下，蟹幾時來無酒中。", "生事比梅仍向北，歸心如水只流東。", "蒼崖翠竹雲根屋，擘畫殘年飯韭菘。"]'),
('9a1f82b6-2763-4b9a-af83-015a095af645','題雲心適楚吟稿','蕭立之','宋','宋诗','song-poetry','','[]','𪳁翠重陰一握天，舊來此地著吟仙。',64,'全唐诗/poet.song.217000.json','["𪳁翠重陰一握天，舊來此地著吟仙。", "自題淮海短長句，又□郴江二百年。", "夜雨滋蘭深屈畹，春風種橘長蘇泉。", "監州文采推南阮，夔後留看適楚編。"]'),
('43fb1a85-15f9-41b9-a382-d121801c4d58','報恩荷池納凉呈雲心','蕭立之','宋','宋诗','song-poetry','','[]','重入僧窗聽雨眠，藕花只在客床前。',64,'全唐诗/poet.song.217000.json','["重入僧窗聽雨眠，藕花只在客床前。", "囊空不欠蘇秦舌，口渴頻呼陸羽泉。", "十里湖光天半席，一闌秋影月初弦。", "新凉風物無人共，坐聽微鍾祇自憐。"]'),
('81f5e84d-08b4-475c-8e26-1cd61da29df5','七月十五夜雲心邀泛北湖','蕭立之','宋','宋诗','song-poetry','','[]','凉透秋衣不忍眠，更何處覓蕊珠仙。',64,'全唐诗/poet.song.217000.json','["凉透秋衣不忍眠，更何處覓蕊珠仙。", "水光夜氣無三伏，人影花陰共一船。", "菱藻有香風四合，地天無際月雙圓。", "碧筒賸對青山吸，此樂人間幾百年。"]'),
('3f3c88ea-a06f-480f-8774-49a768f15281','再韻呈雲心','蕭立之','宋','宋诗','song-poetry','','[]','西風日日枕書眠，自笑仙城著懶仙。',64,'全唐诗/poet.song.217000.json','["西風日日枕書眠，自笑仙城著懶仙。", "溧水已無東野俸，剡溪空趁子猷船。", "詩名入社平生欠，鄉夢驚秋昨夜圓。", "念我衰頹君萬里，可憐懷抱更中年。"]'),
('1e219deb-e7c2-4945-a839-d26f62012ece','次趙東林韻','蕭立之','宋','宋诗','song-poetry','','[]','錦袍公子三生夢，又墮歌羅古驛中。',64,'全唐诗/poet.song.217000.json','["錦袍公子三生夢，又墮歌羅古驛中。", "天上無情覆手雨，人間有恨打頭風。", "晚花留日明深樹，枯澤回潮起蟄龍。", "草草官稱今髮白，年時悔不事猿公。"]'),
('ee3f4a93-2c12-4578-9d6d-0fa25e1d4afb','寄曾翠屏','蕭立之','宋','宋诗','song-poetry','','[]','天亦何曾忘此翁，頰紅留待醉春風。',64,'全唐诗/poet.song.217000.json','["天亦何曾忘此翁，頰紅留待醉春風。", "剩吟詩在何妨老，只欠官稱未是窮。", "五夜月痕雲一角，十年風物鬢雙蓬。", "□□□□□□□，倘有江船吾亦東。"]'),
('4ea08089-07a3-4c39-98f6-9db77a02d454','梅','蕭立之','宋','宋诗','song-poetry','','[]','不受世間塵土涴，山之南北水之涯。',64,'全唐诗/poet.song.217000.json','["不受世間塵土涴，山之南北水之涯。", "識中庸裏有素隠，怪小雅中無白華。", "半點精神春滴淅，一寒風骨雪槎牙。", "淡妝人去羅浮遠，腸斷東風璧月斜。"]'),
('c159935c-d9f3-4163-aeff-fd89f1f16249','再爲梅賦','蕭立之','宋','宋诗','song-poetry','','[]','誰遣巫陽招爾魂，春從九地到孤根。',64,'全唐诗/poet.song.217000.json','["誰遣巫陽招爾魂，春從九地到孤根。", "靈均清節離騷囷，司馬深衣獨樂園。", "吟客謾能工水月，先儒曾此識乾坤。", "雁行却以山礬進，未許涪翁謂至言。"]'),
('25b64b73-283f-4344-b9c6-f75e0d3bb36d','雪','蕭立之','宋','宋诗','song-poetry','','[]','吹萬不同無數風，人間遂有水晶宮。',64,'全唐诗/poet.song.217000.json','["吹萬不同無數風，人間遂有水晶宮。", "玉龍夜戰三更月，鐵馬秋行萬里空。", "老盡蓬心松柏獨，起來蒿目地天通。", "蘭亭儘足方金谷，只詫粗人論未公。"]'),
('e27e500f-9d71-4c49-9561-1e22b3d43935','挽彭復雅二首  其一','蕭立之','宋','宋诗','song-poetry','','[]','已哭芸兄又哭君，眼中何得更沾巾。',64,'全唐诗/poet.song.217000.json','["已哭芸兄又哭君，眼中何得更沾巾。", "死無家貨營磚甓，生有詩名動縉紳。", "豈亦雕鎪傷你壽，不然溟漠妬斯人。", "不忘有子今傳業，依舊寒林一氣春。"]'),
('e1751fa1-49f8-427a-beb8-661ac5c05aa8','挽彭復雅二首  其二','蕭立之','宋','宋诗','song-poetry','','[]','隔月日前猶得書，說貧說病兩劬媮。',64,'全唐诗/poet.song.217000.json','["隔月日前猶得書，說貧說病兩劬媮。", "祗言未晚休文瘦，不料竟成長吉殂。", "空有淚花愁宿草，可無哀些折生芻。", "平生交舊銘幽筆，今代蕭臺有大蘇。"]'),
('b5958e91-0807-43a7-bf43-603f24df4aa0','送呂秘書中歸清凉二首  其一','蕭立之','宋','宋诗','song-poetry','','[]','曾剔寒燈讀奏篇，先生有膽大如天。',64,'全唐诗/poet.song.217000.json','["曾剔寒燈讀奏篇，先生有膽大如天。", "忠言流落古無此，佳士行藏今偶然。", "諸老與公扶一世，十圖爲世作千年。", "向來魂夢江閩隔，信有三生問字緣。"]'),
('245d80d6-b7de-44ca-a3e4-555437ab0f0d','送呂秘書中歸清凉二首  其二','蕭立之','宋','宋诗','song-poetry','','[]','蒼玉亭邊借屋居，春風忽許賦歸歟。',64,'全唐诗/poet.song.217000.json','["蒼玉亭邊借屋居，春風忽許賦歸歟。", "鄰翁爭挈葫蘆酒，息女催擎篛籠書。", "百世不磨公論在，一城相語笑顔舒。", "茲行奇絕君恩重，壓落梅花照笋輿。"]'),
('bf9c9246-b984-4637-adc0-8549b6cbb409','次龔象湖韻二首  其一','蕭立之','宋','宋诗','song-poetry','','[]','一盂野飯落閩州，篁竹烟莎屋壓頭。',64,'全唐诗/poet.song.217000.json','["一盂野飯落閩州，篁竹烟莎屋壓頭。", "學問無窮吾輩老，乾坤能大此身浮。", "客窗書傳青燈雨，故國溪山黄葉秋。", "羨子清吟如玉雪，枯腸塵土不堪搜。"]'),
('d2ae8ba0-25a6-43c9-8460-856fdd43522b','次龔象湖韻二首  其二','蕭立之','宋','宋诗','song-poetry','','[]','剩水殘山欲盡頭，肯披蓬藋訪深幽。',64,'全唐诗/poet.song.217000.json','["剩水殘山欲盡頭，肯披蓬藋訪深幽。", "買鹽沽酒三家市，劈箭驚雷一水秋。", "袖裏我無區冊序，脚跟君有子長遊。", "是間尚有堪吟處，莫向西風怨滯留。"]'),
('119570de-7f0f-463e-901d-faaf2452b18f','送易齋何倅官滿歸括蒼','蕭立之','宋','宋诗','song-poetry','','[]','壁立屏星照古鄞，兩年霹靂快嚬呻。',64,'全唐诗/poet.song.217000.json','["壁立屏星照古鄞，兩年霹靂快嚬呻。", "圓珠山下月初曉，蒼玉洞前梅自春。", "冰雪要教醒醉眼，乾坤何可少斯人。", "葛强舊是樽前客，欲化爲龍奈此身。"]'),
('d441731c-e45a-402d-b8c5-648dde121413','歸自城外','蕭立之','宋','宋诗','song-poetry','','[]','山圍不斷似勾闌，路入蒼雲八百盤。',64,'全唐诗/poet.song.217000.json','["山圍不斷似勾闌，路入蒼雲八百盤。", "塔頂受風鈴語急，樓高有日鵲巢寒。", "簿書衮衮蟻旋磨，歲月匆匆船下灘。", "兩度梅花猶是客，夢隨飛翼度巑岏。"]'),
('ad237445-ed2c-49a1-9877-5833de491027','次使長勸農喜晴韻','蕭立之','宋','宋诗','song-poetry','','[]','日日巡簷聽雨聲，春郊忽爲使車晴。',64,'全唐诗/poet.song.217000.json','["日日巡簷聽雨聲，春郊忽爲使車晴。", "醉翁之意不在酒，造物於人亦有情。", "天日開明吾道泰，詩書談笑孽囚驚。", "吟成自對春風笑，却恐高瓊意未平。"]'),
('307efe2f-56d0-4d6b-99ce-a79c395c2675','山下','蕭立之','宋','宋诗','song-poetry','','[]','山下人門白板扉，畦蔬繞屋水田肥。',64,'全唐诗/poet.song.217000.json','["山下人門白板扉，畦蔬繞屋水田肥。", "五更花信雷初動，一月春晴燕未歸。", "官滿不儲囊粟俸，兒寒猶補海圖衣。", "山禽不語如相好，聽我勞歌賦式微。"]'),
('0d07bf21-19bf-467c-91b1-0be61fcfaedc','次使長蒼玉亭','蕭立之','宋','宋诗','song-poetry','','[]','詩律崢嶸壓島郊，險如百二據秦殽。',64,'全唐诗/poet.song.217000.json','["詩律崢嶸壓島郊，險如百二據秦殽。", "鄒枚一座風流集，陳郭千年道義交。", "公筆欲傾河漢倒，我才如種石田磽。", "山城斗大春風足，阿閣終須著鳳巢。"]'),
('b7732496-fb7c-491f-ba1d-5aba6f96aaba','使長初約客觀文殊寺牡丹忽有走數種自小洛陽來者觴于東山堂席上賦','蕭立之','宋','宋诗','song-poetry','','[]','野寺留花待使君，山堂忽放洛陽春。',64,'全唐诗/poet.song.217000.json','["野寺留花待使君，山堂忽放洛陽春。", "數根綠護封枝蘚，一騎紅飛置驛塵。", "金带巧傳天上信，玉酥終作鼎中珍。", "預愁幾日都飛去，定□梁公是正人。"]'),
('7f3aabc9-1419-4994-b4b7-20ec32983033','使長遣和再韻','蕭立之','宋','宋诗','song-poetry','','[]','胡床少住許諸君，綵服移來有脚春。',64,'全唐诗/poet.song.217000.json','["胡床少住許諸君，綵服移來有脚春。", "濃露洗空妝带酒，暖風吹動襪生塵。", "聖賢清濁杯中物，賓主東南席上珍。", "品格只從根撥見，先生端是識花人。"]'),
('d0eab3b4-7493-409a-b102-9e2818ee96b6','和張倅韻','蕭立之','宋','宋诗','song-poetry','','[]','微官元不療寒饑，憂樂相從頼有詩。',64,'全唐诗/poet.song.217000.json','["微官元不療寒饑，憂樂相從頼有詩。", "萬里功名看末路，百年事業有殘碑。", "文嫌累氣傷雕組，語要驚人欠崛奇。", "湖海平生有今日，白頭何處覓新知。"]'),
('491ddd72-ba68-41da-8573-27e0a9bffc45','睡起','蕭立之','宋','宋诗','song-poetry','','[]','薄酒匆匆與睡謀，夜長無寢怯更籌。',64,'全唐诗/poet.song.217000.json','["薄酒匆匆與睡謀，夜長無寢怯更籌。", "要嗔早起還多事，浩笑春來失自由。", "雪禁好花偏耐晚，雨肥枯澗已堪舟。", "自憐跬步元嬰閣，未有新詩續舊遊。"]'),
('82c9f35c-0184-4e31-80b5-3fb6ba3eda14','和孫竹雲道士先墳種松韻','蕭立之','宋','宋诗','song-poetry','','[]','秦嶺蒼髯鐵色仙，却將翁仲作忘年。',64,'全唐诗/poet.song.217000.json','["秦嶺蒼髯鐵色仙，却將翁仲作忘年。", "移將根去親陪土，化作楊公種玉田。", "客子有懷悲故壟，清明無酒哭蒼天。", "感君此計能千載，獨立斜陽詠此篇。"]'),
('85ae7ea7-bb8d-45d3-9664-362e86e1d18a','孺子亭','蕭立之','宋','宋诗','song-poetry','','[]','湖上花藤絡樹身，傍湖鷗鳥識遊人。',64,'全唐诗/poet.song.217000.json','["湖上花藤絡樹身，傍湖鷗鳥識遊人。", "兩京寂寞有前哲，一榻風流無後塵。", "史牒不名爲隠逸，公心豈自少經綸。", "卷藏獨向茲丘老，歲歲祠前荷芰春。"]'),
('01a79990-291d-427a-b95d-76635bc1f2e4','送實堂吳帥歸天台二首  其一','蕭立之','宋','宋诗','song-poetry','','[]','歸韉忽報出山城，笳鼓旌旗送若迎。',64,'全唐诗/poet.song.217000.json','["歸韉忽報出山城，笳鼓旌旗送若迎。", "滿擔圖書仍語錄，全家風雨又山程。", "行須有用藏非損，來本無心去亦輕。", "家裏湖山元不惡，知公久矣憶蓴羹。"]'),
('a48eb324-a6af-434e-9c53-8249efc87b2c','送實堂吳帥歸天台二首  其二','蕭立之','宋','宋诗','song-poetry','','[]','天台一萬八千丈，玉立人間第一流。',64,'全唐诗/poet.song.217000.json','["天台一萬八千丈，玉立人間第一流。", "士要著書歸亦樂，道堪傳世外何求。", "能令不作三公耳，且共相看一笑休。", "渺渺層雲雙目短，幾時歸雁落滄洲。"]'),
('f2f5b9f4-cf8e-4936-b270-ecccb68a3ecf','次黄園漕幕韻','蕭立之','宋','宋诗','song-poetry','','[]','花如墮珥草遺簪，次第東風轉作南。',64,'全唐诗/poet.song.217000.json','["花如墮珥草遺簪，次第東風轉作南。", "巢鷇欲飛看八八，徑香不斷勝三三。", "著亭屈折誰心計，隔竹推敲客手談。", "安得身閑携斗酒，趁他姚魏戰紅酣。"]'),
('7d5a87a8-0a8d-4542-8f1b-010bda40cf7f','蘇雲卿','蕭立之','宋','宋诗','song-poetry','','[]','洪崖仙人舊隠處，繞舍畦蔬藤一枝。',64,'全唐诗/poet.song.217000.json','["洪崖仙人舊隠處，繞舍畦蔬藤一枝。", "君房自致台鼎位，伯也差爲兒女知。", "鴻飛千里避弋繳，魚潜九淵驚釣絲。", "歆寧優劣金在地，世上只賞桐江祠。"]'),
('c02eabdd-0c9d-4dd0-846f-bcbb1762e44a','和晏司法吳城山道中韻三首  其一','蕭立之','宋','宋诗','song-poetry','','[]','椎鼓發船催出城，平安街子報歸程。',64,'全唐诗/poet.song.217000.json','["椎鼓發船催出城，平安街子報歸程。", "紅闌碧水旗招醉，綠樹黄鸝畫寫生。", "爲有詩情渾不惡，便無官事也堪行。", "一樽細共燈前說，此夕星河爛熳明。"]'),
('b63d42eb-7e6b-45ce-8e5b-970371cb6f6d','和晏司法吳城山道中韻三首  其二','蕭立之','宋','宋诗','song-poetry','','[]','十幅風帆十丈桅，空明雙眼洗塵開。',64,'全唐诗/poet.song.217000.json','["十幅風帆十丈桅，空明雙眼洗塵開。", "壓枝梅大宜羹鼎，貫柳魚肥更酒杯。", "檣燕可能留客住，沙鷗只道爲詩來。", "剡舟不作興盡返，見說龍公也自猜。"]'),
('ec48de1e-aad8-467f-9a12-892cee2c410a','和晏司法吳城山道中韻三首  其三','蕭立之','宋','宋诗','song-poetry','','[]','蹴天浪入白雲層，四野都無一寸青。',64,'全唐诗/poet.song.217000.json','["蹴天浪入白雲層，四野都無一寸青。", "挾萬斛行風有力，著千人聚地成形。", "廬峯映日開天繪，石砮沉淵記廟靈。", "欲洗吏塵何日得，摩挲坡句傍危亭。"]'),
('66b6dd1a-000e-4075-a133-6f5bee81f0bc','和李後林賀黄後谷漕薦韻','蕭立之','宋','宋诗','song-poetry','','[]','愛君滿腹貯精神，王翰當年願卜鄰。',64,'全唐诗/poet.song.217000.json','["愛君滿腹貯精神，王翰當年願卜鄰。", "一日雄文諠上國，三生太史屬前身。", "獵心勃鬰驚殘夢，新榜誇張說古人。", "早作功名歸舘閣，詩情莫涴簿書塵。"]'),
('303f6ff6-0b2d-4efb-ad18-432ee5f532fc','送孫竹雲住浮雲觀','蕭立之','宋','宋诗','song-poetry','','[]','城郭塵埃心自村，一生吟褐任乾坤。',64,'全唐诗/poet.song.217000.json','["城郭塵埃心自村，一生吟褐任乾坤。", "江湖處處客曾席，風雨瀟瀟人閉門。", "蕙帳曉空雲出岫，蕪城春老竹生孫。", "詩囊挑入蒼烟去，誰管斜陽到韻軒。"]'),
('76a76901-fd35-4f1c-b84f-d5a62fd46a47','豐城慮囚和滕倅壁間韻','蕭立之','宋','宋诗','song-poetry','','[]','畧彴橫波壓石安，小亭誰占此溪灣。',64,'全唐诗/poet.song.217000.json','["畧彴橫波壓石安，小亭誰占此溪灣。", "晨裝带月猶長道，久夢隨雲又別山。", "不敢告勞憐歲晚，未能免俗覺詩慳。", "梅花樹下春風酒，小醉歸來未掩關。"]'),
('a3f2c034-2c5a-40a7-abd6-38b2ba1ddaa3','次滕倅夜登樓韻','蕭立之','宋','宋诗','song-poetry','','[]','湖邊四面小雲樓，城上三更漏鼓秋。',64,'全唐诗/poet.song.217000.json','["湖邊四面小雲樓，城上三更漏鼓秋。", "月淡無痕詩共好，官清有味境能幽。", "人間路絕蓬瀛近，木末天低宇宙浮。", "喚醒塵勞椀中茗，西風黄葉正颼颼。"]'),
('0b76c689-6156-4044-9006-70ee4c3997c6','題王衡甫吟稿','蕭立之','宋','宋诗','song-poetry','','[]','君家冠冕半山翁，晚唱漓波一洗空。',64,'全唐诗/poet.song.217000.json','["君家冠冕半山翁，晚唱漓波一洗空。", "萬世尚須觀往復，一江元不隔西東。", "松精入地千年魄，鵬翼垂雲萬里風。", "安得共君秋月底，朗吟峯頂撼松公。"]'),
('16379a8b-3b0e-4127-a904-bf53c68a79c0','漕園古梅','蕭立之','宋','宋诗','song-poetry','','[]','花身怪怪復奇奇，幾度春風未入詩。',64,'全唐诗/poet.song.217000.json','["花身怪怪復奇奇，幾度春風未入詩。", "列璺有文蛇蛻殻，刳心不死豹留皮。", "風流不在宮妝稱，冷淡偏於晚歲宜。", "爲怕清寒欺客袖，一簷斜月立多時。"]'),
('9b0e2544-9335-4759-9a5b-3f42aa810a6c','代同官送方蛟峰二首  其一','蕭立之','宋','宋诗','song-poetry','','[]','除書飛舞下元正，人在金鰲背上行。',64,'全唐诗/poet.song.217000.json','["除書飛舞下元正，人在金鰲背上行。", "班笋步聯黄閣近，橐荷先照綵衣明。", "文章華國三千牘，樽俎籌帷十萬兵。", "宣室席前應有問，願培元氣厚蒼生。"]'),
('dd399244-e818-42cb-8cdc-2b7e539fd3e3','代同官送方蛟峰二首  其二','蕭立之','宋','宋诗','song-poetry','','[]','蟠木離奇誰是客，詎圖燕谷亦春風。',64,'全唐诗/poet.song.217000.json','["蟠木離奇誰是客，詎圖燕谷亦春風。", "方臯相馬驪黄外，康節識花根撥中。", "投士泥途公爲國，讀書城旦我何功。", "只今一瓣南豐在，夾袋他年願始終。"]'),
('e86c2d79-b60b-419b-ae58-d61954fa7866','贈張南溪','蕭立之','宋','宋诗','song-poetry','','[]','長鬣張郎詩骨□，幅巾藜杖氣仇仇。',64,'全唐诗/poet.song.217000.json','["長鬣張郎詩骨□，幅巾藜杖氣仇仇。", "老坡言語妙百世，子美經行半九州。", "自笑我猶爲口累，不應君亦有覊愁。", "眼看塵土羞形穢，夢拗梅花雪上頭。"]'),
('d5da1da2-a630-4760-a8d8-5245d6186365','輅新帥出城見梅','蕭立之','宋','宋诗','song-poetry','','[]','城裏康衢三寸埃，出城江上有疏梅。',64,'全唐诗/poet.song.217000.json','["城裏康衢三寸埃，出城江上有疏梅。", "問公安在見何晚，似客可人期不來。", "質白不隨玄令改，枝南還受北風開。", "花前不作匆匆醉，却有新詩藉手回。"]'),
('807ec32c-0bfa-4dfa-bbcb-46a081582f16','送婁高士歸渝','蕭立之','宋','宋诗','song-poetry','','[]','我無可送全椒酒，君有堪傳石鼎詩。',64,'全唐诗/poet.song.217000.json','["我無可送全椒酒，君有堪傳石鼎詩。", "客裏歸忙雲亦散，吟邊相憶月明知。", "出山似已鑄成錯，煮石尤來療得饑。", "別挹未成先一笑，湖元交割付他誰。"]'),
('84d6a2dc-be02-48b0-ac21-81c59c2edce3','送黄仲與之崆峒任','蕭立之','宋','宋诗','song-poetry','','[]','平生場屋幾秋風，三尺詞綾上界中。',64,'全唐诗/poet.song.217000.json','["平生場屋幾秋風，三尺詞綾上界中。", "筆力健凌黄鷂子，劍心雄邁白猿公。", "羞交人指原夫輩，早慕史稱儒者功。", "夜半南雲瞻紫氣，知君長劍倚崆峒。"]'),
('330b3f09-b9db-4099-915f-b14f9ec74c53','送曾寺簿知南安二首  其一','蕭立之','宋','宋诗','song-poetry','','[]','倦隨龍尾踏□檛，却愛山城放早衙。',64,'全唐诗/poet.song.217000.json','["倦隨龍尾踏□檛，却愛山城放早衙。", "官好何曾嘯篁竹，州清第一管梅花。", "濂翁道脈猶今日，鐵漢風聲想故家。", "君去我留人自恨，春風祖帳滿東華。"]'),
('8f2d813b-a23c-4fab-8acd-f9bd76b42765','送曾寺簿知南安二首  其二','蕭立之','宋','宋诗','song-poetry','','[]','南豐事業炳如丹，振起斯文一代看。',64,'全唐诗/poet.song.217000.json','["南豐事業炳如丹，振起斯文一代看。", "霄漢行飛上鴻雁，畫圖盛事入衣冠。", "旌幢有喜春郊滿，劍槊無聲夜峒寒。", "小試淮陽君且召，金狨湖外等歸鞍。"]'),
('ebe8bd64-d1ad-4360-b6a7-b10360d56d8f','李鶴林田惠詩有孤山探梅之句用韻爲謝','蕭立之','宋','宋诗','song-poetry','','[]','向來山裏讀書房，便是人間白玉堂。',64,'全唐诗/poet.song.217000.json','["向來山裏讀書房，便是人間白玉堂。", "地有梅花三百本，春回紙帳五更霜。", "山林有約狐淘令，歲月無情老子長。", "欲起林逋說香影，急須同買月中航。"]'),
('1302d6c2-e895-4c15-8858-6cf83f87d38d','陳蒲塘送端硯用韻爲謝  其一','蕭立之','宋','宋诗','song-poetry','','[]','龍淵打底爲誰來，半瓦殘磚愧不才。',64,'全唐诗/poet.song.217000.json','["龍淵打底爲誰來，半瓦殘磚愧不才。", "天上分星涵水鏡，人間有石等輿臺。", "忽驚萬里詩翁眼，如發千年地媼胎。", "鬼奪客偷關夢寐，吟邊時與理烟煤。"]'),
('986c461d-b2e0-4388-86f9-8aa028178cc2','陳蒲塘送端硯用韻爲謝  其二','蕭立之','宋','宋诗','song-poetry','','[]','真鹽鐵使有雲來，多少人憐白樸才。',64,'全唐诗/poet.song.217000.json','["真鹽鐵使有雲來，多少人憐白樸才。", "合趁閨班高處籍，尚携檄筆外間臺。", "勞君海怪探龍頷，贈我厨珍得豹胎。", "又俸前詩清似水，通群辟盡鎖窗煤。"]'),
('a2adfe84-3c63-498a-9950-fd17e2c8fb7a','再韻賀得闕','蕭立之','宋','宋诗','song-poetry','','[]','日日邊書带羽來，時艱撐拓正需才。',64,'全唐诗/poet.song.217000.json','["日日邊書带羽來，時艱撐拓正需才。", "我猶不定轉五木，君已高翔長一臺。", "此日知心魚在水，他時得路鶴離胎。", "江東日暮深雲裏，人醉冰臺擁麝煤。"]'),
('d288ed86-04bc-4083-9463-1775a6fdacaf','和蒲塘鄉飲酒席上韻','蕭立之','宋','宋诗','song-poetry','','[]','洛社當年留樣子，客中正可飲亡何。',64,'全唐诗/poet.song.217000.json','["洛社當年留樣子，客中正可飲亡何。", "樽前聊復會真率，殿上相期侍馺娑。", "事意舊遊忘鬢改，坐分前席覺年多。", "西風管取都長健，更插茱萸上嵬峩。"]'),
('2c5d3cad-b952-409f-8a1f-288b3943585a','和羅澗谷寄以姑蘇舊遊韻','蕭立之','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','爲雲舊欠四方從，投老相逢稇載空。',64,'全唐诗/poet.song.217000.json','["爲雲舊欠四方從，投老相逢稇載空。", "吟榻幾時今雨客，塵襟一夏故人風。", "長江秋色烟波外，落日漁家醉夢中。", "無計事君吟得好，詩來面摺欲生紅。"]'),
('9a169c97-5e72-4885-809b-362ce4353307','送官出守平江二首  其一','蕭立之','宋','宋诗','song-poetry','','[]','天上紅雲第二班，乞身祗要覓祠官。',64,'全唐诗/poet.song.217000.json','["天上紅雲第二班，乞身祗要覓祠官。", "清朝得路古來有，晚節全名人所難。", "歇馬重來森戟近，携龜已放去船寬。", "待公過闕爭留相，溫國風流此日看。"]'),
('9a43e1c4-9672-4856-ae8d-70456cd1bd82','送官出守平江二首  其二','蕭立之','宋','宋诗','song-poetry','','[]','班玉通明散早朝，春風桃李滿江臯。',64,'全唐诗/poet.song.217000.json','["班玉通明散早朝，春風桃李滿江臯。", "自然著我塵勞沒，安得如公勇退高。", "地近黄扉纔一武，天教清夢更三刀。", "儀刑渴想催歸衮，只借闌門水半篙。"]'),
('2b9914b2-c32e-4bf8-b37c-ed7bd2e34b6f','同林城山楊學舟遊虎丘','蕭立之','宋','宋诗','song-poetry','','[]','虎踞名丘往事賒，勝遊千載梵王家。',64,'全唐诗/poet.song.217000.json','["虎踞名丘往事賒，勝遊千載梵王家。", "山靈舊出點頭石，地妬曾埋解語花。", "佛國憑空雲入座，劍池共汲水隨車。", "吟人謾有興亡感，雪壁淋漓落陣鴉。"]'),
('9fef1c51-6435-4a07-9b66-b29e760a508d','九日拉管西窗諸丈游鳳石洞天酒邊用草堂韻','蕭立之','宋','宋诗','song-poetry','','[]','巨靈擘畫境能寬，吟似追隨亦可歡。',64,'全唐诗/poet.song.217000.json','["巨靈擘畫境能寬，吟似追隨亦可歡。", "地有此山開宇宙，天留今日會衣冠。", "石交可與論千載，歲晚相期共一寒。", "山外黄塵深沒馬，澄潭聊復倚闌看。"]'),
('12e67057-c53a-4195-9d45-defcd8522b19','寄曾牧菴','蕭立之','宋','宋诗','song-poetry','','[]','丹林自語葉騷騷，寒入江南入縕袍。',64,'全唐诗/poet.song.217000.json','["丹林自語葉騷騷，寒入江南入縕袍。", "丘壑風流須我輩，弓刀事業付兒曹。", "神靈助晉天機轉，姙姒興周廟算高。", "相不當侯吾事了，不妨羹泡煮溪毛。"]'),
('83ce3d4b-b8c9-47e1-a7c7-f2bc33e92f09','次曾漁磯賀得士贇音問韻','蕭立之','宋','宋诗','song-poetry','','[]','時危多難合驅除，安見嬌兒競挽鬚。',64,'全唐诗/poet.song.217000.json','["時危多難合驅除，安見嬌兒競挽鬚。", "支厦可能扶緒漢，誓江猶欲活全吳。", "疑從馬革無還璧，忽得蠅頭似串珠。", "君有詩來逾骨肉，爲君吟罷酒三呼。"]'),
('338dbec0-6c0d-40a6-9df3-89ca7a9be407','請兵道中作','蕭立之','宋','宋诗','song-poetry','','[]','八表同昏草露深，西風愁絕不成吟。',64,'全唐诗/poet.song.217000.json','["八表同昏草露深，西風愁絕不成吟。", "申包胥有傷時淚，南霽雲無食肉心。", "日月重光天與子，山河正統古猶今。", "微生千里間關意，凈洗妖氛待相霖。"]'),
('674b2704-e29a-4ff2-b44b-ad15fc325a47','漁磯惠詩適聞王師過邑次韻作歡喜口號','蕭立之','宋','宋诗','song-poetry','','[]','不是逃名韓伯休，避兵聊欲蔽林丘。',64,'全唐诗/poet.song.217000.json','["不是逃名韓伯休，避兵聊欲蔽林丘。", "天公悔禍有今日，臣子扶顛無半籌。", "蒼玉硤鳴春意動，紅綿襖出霧痕收。", "詩來適喜王師至，醉插梅花舞白頭。"]'),
('6548b926-0c92-4385-9db1-c0a930c43c6b','春晴試筆','蕭立之','宋','宋诗','song-poetry','','[]','爲喜逢春亦自憐，新晴風物此花前。',64,'全唐诗/poet.song.217000.json','["爲喜逢春亦自憐，新晴風物此花前。", "蝶狂有意如耽色，樹老無枝莫記年。", "鍾虡塵深唐九廟，金銅淚盡漢中天。", "二三豪俊今何在，愁絕孤臣雪滿天。"]'),
('b07fb997-0a1f-4e2e-a4fb-d0700f2179b0','和本縣黎月罔勸農韻','蕭立之','宋','宋诗','song-poetry','','[]','白髮衰翁且翠顛，傷心難問屈原天。',64,'全唐诗/poet.song.217000.json','["白髮衰翁且翠顛，傷心難問屈原天。", "當時一聚如金谷，此日數間惟玉川。", "勸諫只今猶樂土，耕犂何地不炊烟。", "欲親偃室無公事，一段阻心似壅泉。"]'),
('207955e1-162c-4e2b-af28-f0a32a884a36','再韻謝黎月罔筆墨丹砂之貺','蕭立之','宋','宋诗','song-poetry','','[]','今君好賜及層顛，憐我幽篁不見天。',64,'全唐诗/poet.song.217000.json','["今君好賜及層顛，憐我幽篁不見天。", "束縛遣前浮月窟，品題稱絕重黟川。", "藥來南海增新價，劑入西窗煮晚烟。", "惟有吟哦相報答，爲君滌硯試新泉。"]'),
('996b7f70-6cc8-4486-af2f-8c6e35d1c465','寄羅澗谷  其一','蕭立之','宋','宋诗','song-poetry','','[]','同是人間七十餘，相思無地問何如。',64,'全唐诗/poet.song.217000.json','["同是人間七十餘，相思無地問何如。", "倉皇空憶歸時別，契闊都無落□書。", "□去避兵長蓐食，邇來古地且巢居。", "題詩甲子應同集，便雁相逢頼啟予。"]'),
('2e15415e-2a35-4920-a015-184bd00d576a','寄羅澗谷  其二','蕭立之','宋','宋诗','song-poetry','','[]','詩去詩來只月餘，渴心頓解沃心如。',64,'全唐诗/poet.song.217000.json','["詩去詩來只月餘，渴心頓解沃心如。", "居然咫尺有萬里，如此亂離無一書。", "山裏黄虀猶可飽，天涯白草更堪居。", "漢宮舊日烟花繞，造化胡寧亦忍予。"]'),
('2310e537-30a1-4d25-b46b-c32c5975e4ba','又和','蕭立之','宋','宋诗','song-poetry','','[]','東南文物古遺餘，不料冠紳忽棄如。',64,'全唐诗/poet.song.217000.json','["東南文物古遺餘，不料冠紳忽棄如。", "門外逢人作胡跪，官中投牒見番書。", "誰教天女解作俑，欲倩漁郎尋卜居。", "更欲久留觀此世，昌黎此語倍愁予。"]'),
('e2980c54-83ac-47d8-bac3-49220372e620','次黎宰併柬曾楚山二首  其一','蕭立之','宋','宋诗','song-poetry','','[]','誰道行年值小遊，轉添白髮上人頭。',64,'全唐诗/poet.song.217000.json','["誰道行年值小遊，轉添白髮上人頭。", "檀公上計無多子，潘令吟情第一流。", "四海交遊驚鬼錄，一身生死寄岑樓。", "因公喚醒推敲夢，此夕燈前忘却愁。"]'),
('50f67f41-f490-4d38-8a32-d03d3292459d','次黎宰併柬曾楚山二首  其二','蕭立之','宋','宋诗','song-poetry','','[]','我耕枯旱不逢年，君解翻瓢漲九淵。',64,'全唐诗/poet.song.217000.json','["我耕枯旱不逢年，君解翻瓢漲九淵。", "道義相忘床上下，詩書有味蜜中邊。", "向來湖海魚千里，此去功名馬一鞭。", "坐想晝簾公事少，時將詩遞破蒼烟。"]'),
('c609cce1-09d0-483e-8371-16455129b668','讀文山詩','蕭立之','宋','宋诗','song-poetry','','[]','退未能休進未前，英雄到此亦堪憐。',64,'全唐诗/poet.song.217000.json','["退未能休進未前，英雄到此亦堪憐。", "此心耿耿赤如日，吾道悠悠蒼若天。", "顧我尚堪輸九死，觀公端可愧諸賢。", "新詩讀罷無誰語，欲折梅花意不傳。"]'),
('0f45bae5-3b95-4bf8-afcc-b1a96290bfff','和周平洲韻','蕭立之','宋','宋诗','song-poetry','','[]','此日舊無靈運屐，參差今有蓋頭茅。',64,'全唐诗/poet.song.217000.json','["此日舊無靈運屐，參差今有蓋頭茅。", "自憐後死罹兵革，枉有閑愁上鬢毛。", "淚盡不堪懷故國，詩來端喜得同袍。", "梅花夾雪無饒景，惜許吟情與病遭。"]'),
('2a514689-c94f-4c25-9577-dc55bae037a3','左臂痛','蕭立之','宋','宋诗','song-poetry','','[]','人生兩臂重天下，濠上仙翁語意高。',64,'全唐诗/poet.song.217000.json','["人生兩臂重天下，濠上仙翁語意高。", "不以拾遺曾墜馬，可教吏部廢持螯。", "風寒欠護知誰過，藥裹頻更藉汝曹。", "安得慈悲有千手，一枝才是九牛毛。"]'),
('721c421b-afae-4543-a729-250bc8706f19','與劉兩峰','蕭立之','宋','宋诗','song-poetry','','[]','可竹詩來爲說君，采蘋宮冷尚疑塵。',64,'全唐诗/poet.song.217000.json','["可竹詩來爲說君，采蘋宮冷尚疑塵。", "人生不幸有奇禍，天道終當與善人。", "蔡琰援琴應製曲，壽昌見母足娛親。", "兩峯座上客常滿，芋栗杯盤日夜春。"]'),
('30abcf91-0f77-472d-a5d7-e442e7484970','贈道士湖古澹','蕭立之','宋','宋诗','song-poetry','','[]','江湖千載吊沉筒，楚俗今仍楚節供。',64,'全唐诗/poet.song.217000.json','["江湖千載吊沉筒，楚俗今仍楚節供。", "已分三生委魚鼈，肯爭一飽爲蛟龍。", "憐君客死非吾土，顧此首丘猶故封。", "試問厭厭曹李輩，人間膏沐若爲容。"]'),
('f164fc21-c321-44db-8e66-3da6f2f2044f','江行得水壓青天下小橋一句足成唐律','蕭立之','宋','宋诗','song-poetry','','[]','老去無心任一瓢，意行聊復侶漁樵。',64,'全唐诗/poet.song.217000.json','["老去無心任一瓢，意行聊復侶漁樵。", "雲迷遠樹昏殘照，水壓青天下小橋。", "物我境空鷄已木，功名夢斷鹿猶蕉。", "插秧綠遍江南岸，又送年光入畫橈。"]'),
('2e64a2a7-2453-471c-a187-fc1fba9274d7','次曾楚山','蕭立之','宋','宋诗','song-poetry','','[]','自笑憂兵閲四州，此身只爲苦吟留。',64,'全唐诗/poet.song.217000.json','["自笑憂兵閲四州，此身只爲苦吟留。", "林棲幾見蘆穿膝，室毀欲無茅蓋頭。", "歲月巧將吾輩老，江山喚起故人愁。", "詩來忽作山陰想，問字敲門可得不。"]'),
('46f167b8-c1bc-4119-8ea8-25d9ccc44e27','早起','蕭立之','宋','宋诗','song-poetry','','[]','參差曙色走歸雲，落月猶高欲近人。',64,'全唐诗/poet.song.217000.json','["參差曙色走歸雲，落月猶高欲近人。", "客鬢已隨時事改，風光猶逐世情新。", "孔方不是折簡客，白墮真成入幕賓。", "忽有微吟生眼界，山光遥映雨如塵。"]'),
('8b543c23-e5c9-4b31-8b19-563bdc78d4df','次楚山見寄','蕭立之','宋','宋诗','song-poetry','','[]','穿青度密且衡門，剪紙誰招客子魂。',64,'全唐诗/poet.song.217000.json','["穿青度密且衡門，剪紙誰招客子魂。", "少不若人傷老大，死無容力爲乾坤。", "一枰孰與危機活，千古難磨此道存。", "前有長蛇後猛虎，少陵只合老羌村。"]'),
('3410868b-c47f-422f-b490-a012abd5b12e','觀楚山關廟長篇記舊讀史成唐律','蕭立之','宋','宋诗','song-poetry','','[]','振世威名一寶刀，紫髯鬰鬰見人豪。',64,'全唐诗/poet.song.217000.json','["振世威名一寶刀，紫髯鬰鬰見人豪。", "受恩劉氏心非二，報效曹公義亦高。", "須信千年存廟食，不應一死誤兒曹。", "江南處處新祠屋，可使雄兵歎不遭。"]'),
('cc8f70ce-6806-4c56-92fb-74339ff37e87','次使長蒼玉洞韻','蕭立之','宋','宋诗','song-poetry','','[]','不是仙源不是村，千年霜壁樹蟠根。',64,'全唐诗/poet.song.217000.json','["不是仙源不是村，千年霜壁樹蟠根。", "半山魚鼓動城郭，一日龍雷出洞門。", "雲似世情翻覆變，石如尊宿典刑存。", "摩挲蘚刻無窮意，時聽遊人自細論。"]'),
('ec06dc24-58ab-4e15-91d8-20ee84e0edc7','書罷偶成','蕭立之','宋','宋诗','song-poetry','','[]','書眼猶明返照窗，西風籬落已啼螿。',64,'全唐诗/poet.song.217000.json','["書眼猶明返照窗，西風籬落已啼螿。", "放慵自覺閑居好，涉難爭期末路長。", "稍解忍饑知道進，未能守口坐詩狂。", "世間萬事如蓬轉，且對青山進晚凉。"]'),
('4d9213cb-f80c-4d53-a8ff-8138bce6e2a5','己卯秋社','蕭立之','宋','宋诗','song-poetry','','[]','社公水又一番新，陣陣秋風入白蘋。',64,'全唐诗/poet.song.217000.json','["社公水又一番新，陣陣秋風入白蘋。", "歸燕去如秦逐客，覊鴻哀似楚纍臣。", "青山有約堪娛老，紅樹無情强作春。", "好爲麻姑問人世，如今幾見海揚塵。"]'),
('3029e82d-7a44-4a69-8d81-c4a7d4cca62b','寄楚山','蕭立之','宋','宋诗','song-poetry','','[]','別後梅花幾度春，催人年紀亦匆匆。',64,'全唐诗/poet.song.217000.json','["別後梅花幾度春，催人年紀亦匆匆。", "長如此日易百歲，未覺吾衰成兩翁。", "曉鏡拂鬚無可白，霜顔壓酒不□紅。", "莫看談笑封侯得，留眼江臯送斷鴻。"]'),
('db82d010-4d2f-4888-890e-2159bb7d1c8b','寄題崇仁吳甫伯壽康堂','蕭立之','宋','宋诗','song-poetry','','[]','五福難并壽且康，如君有此扁斯堂。',64,'全唐诗/poet.song.217000.json','["五福難并壽且康，如君有此扁斯堂。", "喬松歲晚不改色，佳菊霜寒彌有香。", "身健清樽供笑詠，眼明細字辨毫芒。", "風流萬一成圖畫，容兩詩翁作雁行。"]'),
('ab335f1e-c736-41d8-a7dc-a8906f639731','次劉蒼涯見訪','蕭立之','宋','宋诗','song-poetry','','[]','山裏清懷人得知，地爐灰冷雪來時。',64,'全唐诗/poet.song.217000.json','["山裏清懷人得知，地爐灰冷雪來時。", "七年有別君仍壯，一事無成我自悲。", "履豨應爲天下計，縛鷄曾見故人詩。", "欲談世事難相就，不爲衝寒脚力疲。"]'),
('e45ddd65-e6be-43ce-9398-8d10dac2c3d5','和燒榾柮韻','蕭立之','宋','宋诗','song-poetry','','[]','樵子歸來頳擔肩，長鑱作我地爐緣。',64,'全唐诗/poet.song.217000.json','["樵子歸來頳擔肩，長鑱作我地爐緣。", "深山大澤蟄蛇虺，冷窗凍壁生雲烟。", "暗室長明天不夜，團茶自煮客堪延。", "窮吟自笑成寒色，不到琉璃玳瑁邊。"]'),
('091a93ef-dede-4864-906d-5e921fa83aab','題陳氏西園','蕭立之','宋','宋诗','song-poetry','','[]','舊賦西園墨尚新，西園風物又精神。',64,'全唐诗/poet.song.217000.json','["舊賦西園墨尚新，西園風物又精神。", "子孫相望百年事，宇宙重回一氣春。", "獨樂風流今寂寞，平泉言語謾悲辛。", "兩家子弟材智下，撞破烟樓有幾人。"]'),
('071c6b70-b3c6-4681-90fc-676fefd8ae5f','壬午元日試筆有懷十翁楚山先生兩章奉寄  其一','蕭立之','宋','宋诗','song-poetry','','[]','年似渭濱人樣子，竹房深夜一燈青。',64,'全唐诗/poet.song.217000.json','["年似渭濱人樣子，竹房深夜一燈青。", "老來有婦能言語，元亮無言亦典刑。", "詩到夔州尊絕倡，人瞻魯殿兀蒼冥。", "寫添澗谷成三老，洛下風流可得成。"]'),
('c9279507-d563-4840-b833-1ca4254b20cf','壬午元日試筆有懷十翁楚山先生兩章奉寄  其二','蕭立之','宋','宋诗','song-poetry','','[]','記前壬午甫能冠，甲子周回有此年。',64,'全唐诗/poet.song.217000.json','["記前壬午甫能冠，甲子周回有此年。", "方寸可耕寧要地，須臾毋死尚觀天。", "史無一事賢黄憲，士有終身感魯連。", "萬里梅花一樽酒，青山不盡水無邊。"]'),
('2cce5ebe-7418-4624-a5ac-bd1ca2dd6ae1','秋燕','蕭立之','宋','宋诗','song-poetry','','[]','猶記東風社雨晴，步欄辛苦得巢成。',64,'全唐诗/poet.song.217000.json','["猶記東風社雨晴，步欄辛苦得巢成。", "依劉信美非吾土，去魯雖遲在此行。", "生也有涯同是客，逝將去汝得無情。", "烏衣巷陌休回首，興廢人間又一枰。"]'),
('cf083c45-dc83-4550-b049-f185a307abe4','壬午九日士資自廣運鐵南雄歸途過家士贄士贇有詩因用韻','蕭立之','宋','宋诗','song-poetry','','[]','驚心節物首重回，尚覺昏雲黯未開。',64,'全唐诗/poet.song.217000.json','["驚心節物首重回，尚覺昏雲黯未開。", "舊向醉餘狂客帽，今猶健在倒蓮臺。", "菊如杜老開偏晚，客勝后山期不來。", "碌碌阿奴俱在目，剩鋤菘韭種蒿萊。"]'),
('28ccf6f6-dc92-4c51-8d16-628e28355efb','遊鳳石道院','蕭立之','宋','宋诗','song-poetry','','[]','山外西風掣大船，懸崖一席鏡中天。',64,'全唐诗/poet.song.217000.json','["山外西風掣大船，懸崖一席鏡中天。", "鳳何年化石班駁，龍有時回潭碧鮮。", "礨空似經靈運鑿，蒼筤競著祖生鞭。", "人知魚樂誰知我，度度歸時月滿川。"]'),
('c502886c-d926-41ab-ae02-db1830f3f292','寄彭梅莊','蕭立之','宋','宋诗','song-poetry','','[]','懶似嵇康多幾分，緘情久不報殷勤。',64,'全唐诗/poet.song.217000.json','["懶似嵇康多幾分，緘情久不報殷勤。", "人言歲暮於吾子，今見梅花疑是君。", "歲月尚須留我輩，乾坤何可少斯文。", "相期不作草中腐，付與後來楊子雲。"]'),
('15405e9a-1e01-4944-a6cc-68c8d6bfd156','次韻答徐毅齋','蕭立之','宋','宋诗','song-poetry','','[]','文印詩燈自正宗，不忘生死訪衰翁。',64,'全唐诗/poet.song.217000.json','["文印詩燈自正宗，不忘生死訪衰翁。", "樽前談笑有此客，眼底輪囷亡是公。", "兩世交遊明月共，百年人物大江東。", "吾生榮悴乖逢爾，昨夜春風梅信中。"]'),
('46ac8144-8363-4f6f-acd7-4f272332e71c','溪行見落梅爲賦','蕭立之','宋','宋诗','song-poetry','','[]','玉龍輕軟雪能乾，好在晴沙野水看。',64,'全唐诗/poet.song.217000.json','["玉龍輕軟雪能乾，好在晴沙野水看。", "舞翠夢回仙袂遠，射鵰人去露簷寒。", "連環骨冷香猶暖，如意痕輕補未完。", "花自年年人自老，春風滿袖獨凭闌。"]'),
('19931569-df60-4a2e-b21d-771c4b31cca9','桃源','蕭立之','宋','宋诗','song-poetry','','[]','桃源花發幾番春，聞說漁郎此問津。',32,'全唐诗/poet.song.217000.json','["桃源花發幾番春，聞說漁郎此問津。", "秦帝漫勞方士遣，神仙已是避秦人。"]'),
('45fb366c-9ded-4f5a-ac99-cc865b8e6352','杜鵑','蕭立之','宋','宋诗','song-poetry','','[]','思歸言語苦悲辛，啼老江南綠樹春。',32,'全唐诗/poet.song.217000.json','["思歸言語苦悲辛，啼老江南綠樹春。", "莫倚巴西君故土，巴西風景近愁人。"]'),
('71641552-e2c7-42f6-94b8-760b2ddc408a','秋日','蕭立之','宋','宋诗','song-poetry','','[]','野店聊爲一枕謀，五更歸夢入鄉愁。',32,'全唐诗/poet.song.217000.json','["野店聊爲一枕謀，五更歸夢入鄉愁。", "溪流清淺舂鋤曉，籬落荒凉絡緯秋。"]'),
('28a1cc0c-9e9c-4028-8ea1-ae298f45c198','書燈蛾','危涴','宋','宋诗','song-poetry','','[]','三生炙手權門者，此日趨炎態未除。',32,'全唐诗/poet.song.217000.json','["三生炙手權門者，此日趨炎態未除。", "汝自燃臍何所恨，可憐遺臭入詩書。"]'),
('95e8f6b4-cc24-4d91-bf7c-f7b7bee98ab1','遊麻姑山','陳宗道','宋','宋诗','song-poetry','','[]','千秋雲氣龍猶在，午夜松聲鶴自寒。',32,'全唐诗/poet.song.217000.json','["千秋雲氣龍猶在，午夜松聲鶴自寒。", "仙子偶來成夢事，至今遊客未嘗閒。"]'),
('c019d463-37ac-44cb-a1d3-844b291f5764','旅懷','陳宗道','宋','宋诗','song-poetry','','[]','清波渺前灘，白鳥下寒渚。',48,'全唐诗/poet.song.217000.json','["清波渺前灘，白鳥下寒渚。", "樵斧空山鳴，歸舟夕陽暮。", "去來風中人，明滅雲外樹。", "雙輪何時休，愁心此羈旅。"]'),
('6ab1ea98-6e5f-4b84-95bd-79020ee04ff7','送別','陳宗道','宋','宋诗','song-poetry','','[]','江邊出相送，君去我當返。',24,'全唐诗/poet.song.217000.json','["江邊出相送，君去我當返。", "徘徊未忍還，孤帆夕陽遠。"]'),
('ee4b97d7-d9e2-4a79-afb9-4109a2894867','洗馬行','陳宗道','宋','宋诗','song-poetry','','[]','玉谿谿頭波綠玉，玉谿谿上沙金粟。',96,'全唐诗/poet.song.217000.json','["玉谿谿頭波綠玉，玉谿谿上沙金粟。", "曉營出馬五花雲，鳴榜齊首橋南浴。", "馬高如屋長如龍，四蹄如鐵聲如鐘。", "青芻幾束粟幾斗，豢汝愛汝爭奇功。", "編騣抹刷解色罷，黑面雄兒齊上馬。", "就中一馬不敢騎，云是將軍臨陳者。"]'),
('f352074a-2c76-4039-957c-54b9292fa804','送戴石屏歸天台','陳宗道','宋','宋诗','song-poetry','','[]','天台四萬八千丈，一根直下寒銀浪。',224,'全唐诗/poet.song.217000.json','["天台四萬八千丈，一根直下寒銀浪。", "青蓮老子夜不眠，往往飛魂到其上。", "詩情不減流白雲，千載重見戴叔倫。", "蓮花峰下赤城洞，芒鞵翻笑山中人。", "秋風孤篁八九尺，老面百摺赬銅色。", "田文席上摩吟髭，鶻立蒼苔烟雨黑。", "我家竹屋棲龍岡，夜搗孤月餐寒霜。", "醉騎白鹿軍峰下，一見贈我青瑶璫。", "南山臺前春正好，萬壑千涯清夢曉。", "蒼苔石磴撫闌干，往事飛鴻天亦笑。", "君今東首回牙檣，我亦西去凌蒼蒼。", "截江橋南春水急，酒酣不記攀垂楊。", "軍峰江南最高處，我上峰頭望君去。", "歸時定入天台山，舉首雲間一相顧。"]'),
('f0285cdc-9253-4c48-b194-ce324a9c2b48','題謝氏西谷','陳宗道','宋','宋诗','song-poetry','','[]','江東風流會稽伯，玉壺貯香傾琥珀。',96,'全唐诗/poet.song.217000.json','["江東風流會稽伯，玉壺貯香傾琥珀。", "春風十里東山雲，一局寒楸晚空碧。", "盤盤石磴紅泉仙，春夢草斷瑶池箋。", "蒙茸曲笠雨花濕，老屐踏損蒼苔錢。", "雙鸞翩翩跨元島，月白香魂翠山杳。", "玉蘭千載流芳馨，清風凌厲連紅曉。"]'),
('16bd783c-dd6e-4f1e-b024-32ad799aaa4d','送寧都陳令','陳宗道','宋','宋诗','song-poetry','','[]','梅花樓頭立晴雪，松葉亭根聽夜雨。',32,'全唐诗/poet.song.217000.json','["梅花樓頭立晴雪，松葉亭根聽夜雨。", "鼪鼯息響月千山，桃李無言春萬樹。"]'),
('d5673edb-8d15-46d0-98ce-aa5cb6a11ccf','題虞帝廟','陳宗禮','宋','宋诗','song-poetry','','[]','南國熏風入帝歌，至今遺廟只嵯峨。',64,'全唐诗/poet.song.217000.json','["南國熏風入帝歌，至今遺廟只嵯峨。", "一天曉色懷明哲，四野春光想太和。", "存古尚瞻虞衮冕，撫時幾換禹山河。", "海濱樂可忘天下，解寫靈明是老軻。"]'),
('65fbcec6-353f-4515-a3ce-6f245302ec5b','山行','陳宗禮','宋','宋诗','song-poetry','','[]','川原綠已張，春去今何在。',48,'全唐诗/poet.song.217000.json','["川原綠已張，春去今何在。", "深樹涵幽姿，微雲弄晴態。", "禽聲互酬應，林霏閒明晦。", "漸遠人蹟稀，清音自虛籟。"]'),
('2b37c1df-a142-4210-8a80-a81d3bea03f0','晚出','陳宗禮','宋','宋诗','song-poetry','','[]','落日山氣清，歸禽噪林杪。',48,'全唐诗/poet.song.217000.json','["落日山氣清，歸禽噪林杪。", "意行忘遠近，吟過深烟表。", "㶁㶁水縈田，幽幽雲反嶠。", "忽聞隣寺鐘，沿途發長嘯。"]'),
('56a7bc4d-24f3-4702-9f73-c9030a1d993c','曉行','陳宗禮','宋','宋诗','song-poetry','','[]','披衣起遐征，微茫認前路。',24,'全唐诗/poet.song.217000.json','["披衣起遐征，微茫認前路。", "哀鴻天際雲，殘月水邊樹。"]'),
('20c8e6ad-b540-4f96-be0b-7f4d7379a661','偕彭雅林游翠即席求和','陳宗禮','宋','宋诗','song-poetry','','[]','往事鎸鑱一夢同，遊人聊此可從容。',64,'全唐诗/poet.song.217000.json','["往事鎸鑱一夢同，遊人聊此可從容。", "神仙已逝境猶在，洞府雖深戶不封。", "閲遍古今雲木老，洗空塵土石泉舂。", "此懷清白堪超世，何必星精特地逢。"]'),
('a2471015-022f-4f7c-8125-5022794b5596','玉巖  其一','陳宗禮','宋','宋诗','song-poetry','','[]','山蹊屈曲石玲瓏，今古遊人興不窮。',32,'全唐诗/poet.song.217000.json','["山蹊屈曲石玲瓏，今古遊人興不窮。", "一一圓明人不識，却尋石□任中通。"]'),
('a6e5eb92-73b0-4668-a958-5f1b3e19cb34','玉巖  其二','陳宗禮','宋','宋诗','song-poetry','','[]','翠屏青紫互高低，清凈仙人薜荔衣。',32,'全唐诗/poet.song.217000.json','["翠屏青紫互高低，清凈仙人薜荔衣。", "正好觀心坐巖下，忘歸却是不忘歸。"]'),
('e0cb1c92-284b-4859-8228-cc1ceeb7712e','石仙觀','陳宗禮','宋','宋诗','song-poetry','','[]','千丈飛崖倚半空，火雲時節此清風。',32,'全唐诗/poet.song.217000.json','["千丈飛崖倚半空，火雲時節此清風。", "身閑一日俱仙思，何用藏形古木中。"]'),
('354451fd-a38a-4db0-91a9-87e64109d1df','澹山巖','陳宗禮','宋','宋诗','song-poetry','','[]','永州澹巖天下稀，山靈妙斲涪翁知。',64,'全唐诗/poet.song.217000.json','["永州澹巖天下稀，山靈妙斲涪翁知。", "蹲猊翔鳳獻穎異，中有僊佛來娛嬉。", "我生骨相□冰雪，心境相□生懌悅。", "緣輕自笑來已遲，猶見巖前古時月。"]'),
('bad38439-516c-44f5-b9f9-512303b804e1','紫霄觀','陳宗禮','宋','宋诗','song-poetry','','[]','平陂復峻坂，曲折勞攀躋。',72,'全唐诗/poet.song.217000.json','["平陂復峻坂，曲折勞攀躋。", "中道忽孤絕，恍然遇安期。", "授以度世術，呼吸隨風飛。", "長跪受隠文，三復歎且疑。", "變化豈不神，勾譎莫予期。", "回鞭指故山，從此問所歸。"]'),
('3455be43-c8ba-4c6c-af27-bf62e44f3e4e','句','陳宗禮','宋','宋诗','song-poetry','','[]','山川半爲蠻烟纍，人物多因謫籍香。',16,'全唐诗/poet.song.217000.json','["山川半爲蠻烟纍，人物多因謫籍香。"]'),
('937f4059-af8d-43f1-b156-bec64a024c29','梅巖','程夢子','宋','宋诗','song-poetry','','[]','烟中修竹列千竿，空裏疎花未可扳。',32,'全唐诗/poet.song.217000.json','["烟中修竹列千竿，空裏疎花未可扳。", "喚醒羅浮山下夢，江南還有廣南山。"]'),
('d494deda-a424-4154-9847-b2e6c0565266','梅巖','程夢子','宋','宋诗','song-poetry','','[]','進步如升百尺竿，夕陽儘我此躋攀。',32,'全唐诗/poet.song.217000.json','["進步如升百尺竿，夕陽儘我此躋攀。", "梅花落盡雨初歇，猶有餘香染碧山。"]'),
('97dde5ec-aba7-4d4d-9b98-3a5a5f09cd0f','遊鼓山','鄭應開','宋','宋诗','song-poetry','','[]','兩峯峻上半天開，一水爭奔急雪來。',64,'全唐诗/poet.song.217000.json','["兩峯峻上半天開，一水爭奔急雪來。", "眺遠直疑滄海近，洞靈曲坳湧泉迴。", "慨思南北江山異，更陟嵯峨宇宙恢。", "眇眇愁余歌石鼓，漫磨枯墨灑蒼苔。"]'),
('41ce5083-ee5a-4b9b-bee6-96abdb1035bb','句','彭克','宋','宋诗','song-poetry','','[]','一溪煙月無人共，吹落梨花曉夢初。',16,'全唐诗/poet.song.217000.json','["一溪煙月無人共，吹落梨花曉夢初。"]'),
('db7fd866-8b39-4115-a90b-2f5e5bb1cf49','元日登九山','潘牥','宋','宋诗','song-poetry','','[]','不到鰲峰久，重來感物華。',48,'全唐诗/poet.song.217000.json','["不到鰲峰久，重來感物華。", "松應添歲壽，梅尚隔年花。", "清磬聞朝斗，丹爐借瀹茶。", "滿城人記節，此日正喧嘩。"]'),
('a8ba9af0-9f05-4ff9-8362-c8773432667c','人日後一日立春','潘牥','宋','宋诗','song-poetry','','[]','人日才過春日至，薄醪生菜旅亭頭。',32,'全唐诗/poet.song.217000.json','["人日才過春日至，薄醪生菜旅亭頭。", "慈親鬢髮垂垂白，應看諸孫弄土牛。"]'),
('8e6447d8-0b21-4ba1-936d-4fa99f1e89e0','重九','潘牥','宋','宋诗','song-poetry','','[]','纔說登山病便蘇，老身健得似於菟。',64,'全唐诗/poet.song.217000.json','["纔說登山病便蘇，老身健得似於菟。", "一絲白處潮來往，數點青邊山有無。", "厭勝詩窮多插菊，驅魔酒惡細看萸。", "龍山落帽方真樂，孫盛汝非柏氏圖。"]'),
('33829d6c-568d-4434-8e85-74ecbfe7f058','除夜','潘牥','宋','宋诗','song-poetry','','[]','屈指頭顱三十一，年時又見煮酴酥。',64,'全唐诗/poet.song.217000.json','["屈指頭顱三十一，年時又見煮酴酥。", "平生自謂妄男子，未死誰甘賤丈夫。", "歡逐兒童燒竹爆，自拈禿筆寫桃符。", "梅花一笑須相領，莫道今吾非故吾。"]'),
('f160b878-2060-4012-8533-7545d1858605','晴','潘牥','宋','宋诗','song-poetry','','[]','西風一夜與晴期，紅日當天燒陸離。',32,'全唐诗/poet.song.217000.json','["西風一夜與晴期，紅日當天燒陸離。", "雲似敗棋無著處，山如宿酒頓醒時。"]'),
('05d74e71-c2cb-4cf8-9001-e75bad06c3ec','喜晴','潘牥','宋','宋诗','song-poetry','','[]','久雨淋漓天亦厭，一聲霹靂洗層陰。',64,'全唐诗/poet.song.217000.json','["久雨淋漓天亦厭，一聲霹靂洗層陰。", "青山愁似故人面，初日明如烈士心。", "掃石安排朝曬藥，約僧準備晚聽琴。", "清宵那更當三五，賸把金樽對月斟。"]'),
('33572174-e4ef-498e-960d-de38051ae4db','春花秋色','潘牥','宋','宋诗','song-poetry','','[]','似覺山桃野杏非，耻將濃綠眩群姿。',32,'全唐诗/poet.song.217000.json','["似覺山桃野杏非，耻將濃綠眩群姿。", "向天乞入秋風隊，蘭菊中間入片時。"]'),
('4758e97f-b2bb-4e7b-8bd4-dc5499f04a09','梅花  其一','潘牥','宋','宋诗','song-poetry','','[]','柴門盡日少蹄輪，坐對橫窗數點春。',64,'全唐诗/poet.song.217000.json','["柴門盡日少蹄輪，坐對橫窗數點春。", "心向雪中偏暴白，影來月下亦精神。", "十分洗盡鉛華相，百劫修來貞潔身。", "笑殺唐人風味短，不應喚作弄珠人。"]'),
('fc83ca21-9222-4766-8e77-0de77a08ee95','梅花  其二','潘牥','宋','宋诗','song-poetry','','[]','偷得湖齋半日閑，有梅此地即孤山。',64,'全唐诗/poet.song.217000.json','["偷得湖齋半日閑，有梅此地即孤山。", "瘦邊似我腰全沈，白處憐渠鬢亦潘。", "惟有竹君同所好，豈容蝶使戲其間。", "調羹莫作兒童語，老眼相看在歲寒。"]'),
('e5d354b2-51b9-475b-be60-883d15daf8a0','梅花  其三','潘牥','宋','宋诗','song-poetry','','[]','老梅手植幾何年，一見風標姑射仙。',64,'全唐诗/poet.song.217000.json','["老梅手植幾何年，一見風標姑射仙。", "特地留爲滕六伴，笑他大欠麴生緣。", "孤高直是難諧俗，開落從渠莫問天。", "座上諸公醒亦醉，對花起舞藉花眠。"]'),
('d9baa0f6-5539-40ae-904b-e779c4f02564','梅花  其四','潘牥','宋','宋诗','song-poetry','','[]','昨夜花神有底忙，先教踏白入南邦。',64,'全唐诗/poet.song.217000.json','["昨夜花神有底忙，先教踏白入南邦。", "冷將雙眼窺春破，肯把孤心受雪降。", "松弟得兄呼最長，竹君取友歎無雙。", "月宵試看尤清絕，一在梢頭一在窗。"]'),
('9adf64b0-7647-4c7d-9137-30b0dc393f63','九月梅','潘牥','宋','宋诗','song-poetry','','[]','洒掃東籬具菊杯，仙翁折送幾枝梅。',64,'全唐诗/poet.song.217000.json','["洒掃東籬具菊杯，仙翁折送幾枝梅。", "絕憐綠萼纔先去，能與黄花作伴開。", "造物定應無頃刻，未霜早自有春回。", "窮山似汝真何數，幸被詩人拈出來。"]'),
('60d55e63-7186-421e-aded-dd627897b603','用錢買綠萼梅','潘牥','宋','宋诗','song-poetry','','[]','爲愛栽梅廢食眠，杖藜行盡幾山巔。',64,'全唐诗/poet.song.217000.json','["爲愛栽梅廢食眠，杖藜行盡幾山巔。", "因貪雪後橫窗影，那用朝來糴米錢。", "窮鬼揶揄爭笑我，詩翁邂逅亦欣然。", "花時莫起淵明恨，糞火蹲鴟酌澗泉。"]'),
('8dea820c-f896-4c57-81dc-515a89701547','落梅','潘牥','宋','宋诗','song-poetry','','[]','一夜風吹恐不禁，曉來冷落已駸駸。',64,'全唐诗/poet.song.217000.json','["一夜風吹恐不禁，曉來冷落已駸駸。", "忍看病鶴和苔啄，空遣饑蜂繞竹尋。", "稚子躊躇看不掃，老夫索莫坐微吟。", "窗前最是關情處，拾片殷勤嗅掌心。"]'),
('e5ea48bb-d8e0-492e-a48a-2e00269d9c01','蘭花  其一','潘牥','宋','宋诗','song-poetry','','[]','長身大葉聳叢叢，生處雖殊臭味同。',64,'全唐诗/poet.song.217000.json','["長身大葉聳叢叢，生處雖殊臭味同。", "全带安期溪澗碧，微偷勾漏箭砂紅。", "聞名久向騷經內，識面翻從要服中。", "等是海山閑草木，東皇一顧便春風。"]'),
('e255e5e0-4ef5-49ef-b8bc-184e89fdc8b6','蘭花  其二','潘牥','宋','宋诗','song-poetry','','[]','聞說吾家又一種，移來遠自劍津灣。',64,'全唐诗/poet.song.217000.json','["聞說吾家又一種，移來遠自劍津灣。", "葉如壯士衝冠髮，花带癯仙辟穀顔。", "行輩合推梅以上，交游多在菊之間。", "平生我亦好修者，乞取幽蘭鎮小山。"]'),
('e2695a1c-b8fc-44a4-8dd7-2b76f131cb22','遣人取紫巖劍蘭','潘牥','宋','宋诗','song-poetry','','[]','萬里鯨波一葦航，坐移楚畹置吾傍。',64,'全唐诗/poet.song.217000.json','["萬里鯨波一葦航，坐移楚畹置吾傍。", "葉侵海氣三分瘦，花比家山一樣香。", "灌溉預先收露水，栽培偏愛近朝陽。", "莫教晚節儕蕭艾，我欲歸來結佩囊。"]'),
('6cbe466c-5a01-4149-b92d-738191c13a9f','緋桃','潘牥','宋','宋诗','song-poetry','','[]','一枝纔破便精神，直是猩猩血染成。',32,'全唐诗/poet.song.217000.json','["一枝纔破便精神，直是猩猩血染成。", "休逐東風貪結子，玉環早已妒傾城。"]'),
('8529a0e8-9452-45ad-b5c1-c330dcd6c1c8','瑞香  其一','潘牥','宋','宋诗','song-poetry','','[]','愛極愁風雨，移根入畫檐。',48,'全唐诗/poet.song.217000.json','["愛極愁風雨，移根入畫檐。", "色過袍樣紫，香带蜜脾甜。", "密葉團團護，幽枝歲歲添。", "芬芳無著處，一月在書簽。"]'),
('08a09bbe-4a1d-4a83-995d-9b4596b7fa3d','瑞香  其二','潘牥','宋','宋诗','song-poetry','','[]','瑞香蓓蕾破寒晴，稚子呼爲紫素馨。',32,'全唐诗/poet.song.217000.json','["瑞香蓓蕾破寒晴，稚子呼爲紫素馨。", "萬斛幽香量不盡，霜風吹送暮天青。"]'),
('5ce456e5-a192-41fa-a57d-94a67c041ed2','梨果','潘牥','宋','宋诗','song-poetry','','[]','紫輕半百遠分貽，正值文園病渴時。',64,'全唐诗/poet.song.217000.json','["紫輕半百遠分貽，正值文園病渴時。", "玉液果如孫楚賦，金柯未數上林奇。", "斷牙頗覺飛泉繞，老態慚非飣玉姿。", "無限世間蒸食者，令人那解識檀梨。"]'),
('c0407610-9316-4d45-9a85-607786515431','牡丹','潘牥','宋','宋诗','song-poetry','','[]','爲愛妖嬈惱病懷，翠屏錦幄護香荄。',64,'全唐诗/poet.song.217000.json','["爲愛妖嬈惱病懷，翠屏錦幄護香荄。", "真教花事從頭盡，却把東風滿室開。", "一縷暗藏金世界，千重高擁玉樓臺。", "螯湯池館依然在，游子年年來不來。"]'),
('e5545038-da70-4e99-9f40-193b02621cf8','三月晦日剪牡丹','潘牥','宋','宋诗','song-poetry','','[]','三月三十日，千花餘牡丹。',48,'全唐诗/poet.song.217000.json','["三月三十日，千花餘牡丹。", "莫辭連夜剪，猶得及春看。", "銀燭淺深間，金瓶高下安。", "洛中全盛日，見說大如盤。"]'),
('d2c095c8-8068-4622-a609-75be9babe81f','十月菊  其一','潘牥','宋','宋诗','song-poetry','','[]','香名不枉入騷壇，最愛霜枝傲歲寒。',64,'全唐诗/poet.song.217000.json','["香名不枉入騷壇，最愛霜枝傲歲寒。", "切莫逢人歎遲暮，何曾委地有彫殘。", "人如靖節方堪採，世欠靈均少得餐。", "甚矣吾衰閉門坐，籬邊自折一枝看。"]'),
('23437129-3033-4c4b-b72b-4930f901240e','十月菊  其二','潘牥','宋','宋诗','song-poetry','','[]','先生嗜菊菊中仙，不把東籬博秫田。',32,'全唐诗/poet.song.217000.json','["先生嗜菊菊中仙，不把東籬博秫田。", "九日於中誰不愛，勤餐何可得延年。"]'),
('7e697afa-01fa-4144-b1e3-32fd888b6bbb','十月菊  其三','潘牥','宋','宋诗','song-poetry','','[]','夕陽西去一憑欄，眼底黄花自歲寒。',32,'全唐诗/poet.song.217000.json','["夕陽西去一憑欄，眼底黄花自歲寒。", "姚魏終皆非正色，請君細把楚騷看。"]'),
('9e59fe5a-6ea7-44b8-bc78-36eb313bf28c','十月菊  其四','潘牥','宋','宋诗','song-poetry','','[]','不染東籬一樣黄，枝頭瑣細白而香。',32,'全唐诗/poet.song.217000.json','["不染東籬一樣黄，枝頭瑣細白而香。", "勞將茉莉相題品，未必蓮花似六郎。"]'),
('07124069-b9cc-4446-b759-910a43e51278','十月菊  其五','潘牥','宋','宋诗','song-poetry','','[]','一段風流玉琢成，開從霜後越精神。',32,'全唐诗/poet.song.217000.json','["一段風流玉琢成，開從霜後越精神。", "休嫌茉莉非吾配，曾見張良似婦人。"]'),
('42df258f-24f8-4626-9ed5-c9210d628b08','芙蓉','潘牥','宋','宋诗','song-poetry','','[]','爲惜艷陽妝，新枝不肯長。',48,'全唐诗/poet.song.217000.json','["爲惜艷陽妝，新枝不肯長。", "綠深秋後雨，紅坼夜來霜。", "偏間垂楊畔，多臨古岸傍。", "年年根蒂在，開謝未渠央。"]'),
('e1176c2a-ea88-4e31-8cc7-923d40911d26','松','潘牥','宋','宋诗','song-poetry','','[]','柯伐移來得得長，想渠歷晉復經唐。',64,'全唐诗/poet.song.217000.json','["柯伐移來得得長，想渠歷晉復經唐。", "慣於巖畔諳風雨，可與人間作棟梁。", "二室七仙同守護，千杉萬檜任低昂。", "向來諸葛祠前柏，此物□□□□□。"]'),
('5ad9c082-6e8f-4a7e-a0c8-6ccbd5e0a600','雷鳴不雨  其一','潘牥','宋','宋诗','song-poetry','','[]','海激天翻電雹真，蒼枝十丈擘爲薪。',32,'全唐诗/poet.song.217000.json','["海激天翻電雹真，蒼枝十丈擘爲薪。", "須臾龍卷他山去，誤殺田頭望雨人。"]'),
('b9630fdc-3f03-4bb3-9e6d-75fa4d350859','雷鳴不雨  其二','潘牥','宋','宋诗','song-poetry','','[]','樵子俄從問路回，因言溪谷響如雷。',32,'全唐诗/poet.song.217000.json','["樵子俄從問路回，因言溪谷響如雷。", "分明雨怕城中去，只隔前峯不過來。"]'),
('8c1d6acd-ad1d-49ea-b5c7-089d5f2b8f80','雪  其一','潘牥','宋','宋诗','song-poetry','','[]','薄暮風吹一片雲，可人滕六張吾軍。',64,'全唐诗/poet.song.217000.json','["薄暮風吹一片雲，可人滕六張吾軍。", "鋪勻世界能平等，補住梅花得十分。", "但使一天長玉色，何須雙手裂龜紋。", "時清果亦多廉叟，委地珠璣若不聞。"]'),
('1898ad0e-931f-4760-b6fe-506c5e7d50db','雪  其二','潘牥','宋','宋诗','song-poetry','','[]','薄暮簷牙雨跳珠，兒童指似雪先驅。',64,'全唐诗/poet.song.217000.json','["薄暮簷牙雨跳珠，兒童指似雪先驅。", "初聞竹上來能密，旋覺梅梢重欲扶。", "北地多應三丈許，南州近亦十年無。", "此間斷縛吳元濟，看踏銀沙入獻俘。"]'),
('658f5987-c5a7-4a40-9885-2097e7d5695e','登嶺  其一','潘牥','宋','宋诗','song-poetry','','[]','纔登西嶺路，詩思便能清。',48,'全唐诗/poet.song.217000.json','["纔登西嶺路，詩思便能清。", "棧道雲間沒，籃輿壁上行。", "遥山時見虎，深谷夏聞鶑。", "咫尺名山寺，猶分兩日程。"]'),
('0e650e33-7c83-42a2-aa71-d32b54567e74','登嶺  其二','潘牥','宋','宋诗','song-poetry','','[]','黄茅連遠近，不見一人行。',48,'全唐诗/poet.song.217000.json','["黄茅連遠近，不見一人行。", "信步未知險，回頭方可驚。", "路由高頂過，雲在半腰生。", "落日無棲止，飄飄自問程。"]'),
('e5b71208-30b2-4872-aea2-b6422cb05df5','郊行  其一','潘牥','宋','宋诗','song-poetry','','[]','山色今朝改，溪流昨夜添。',48,'全唐诗/poet.song.217000.json','["山色今朝改，溪流昨夜添。", "數荷紅貼水，一笋綠平簷。", "處處聞繅軸，時時見酒帘。", "買香諠岳廟，翁媼亦祈籤。"]'),
('1e828ae8-db78-4c4a-b00e-8cc80e60b526','郊行  其二','潘牥','宋','宋诗','song-poetry','','[]','衰病逢行健，歸途未寂寥。',48,'全唐诗/poet.song.217000.json','["衰病逢行健，歸途未寂寥。", "晚山青潑眼，早稻綠平腰。", "林舊藏僧寺，溪新架石橋。", "松陰田舍古，小立聽鳴蜩。"]'),
('7342a836-9116-4355-af6c-0e9172c50a1e','郊行  其三','潘牥','宋','宋诗','song-poetry','','[]','擬欲尋詩取次行，東風放出十分晴。',64,'全唐诗/poet.song.217000.json','["擬欲尋詩取次行，東風放出十分晴。", "花時酒旆家家有，蠶月繅車處處鳴。", "乍可腰鐮從父老，何能手板事公卿。", "他年若述逸民傳，萬一中問有姓名。"]'),
('5307dca0-2020-4fe2-8881-80251ad3a85c','郊行  其四','潘牥','宋','宋诗','song-poetry','','[]','野店柴門傍水開，憑欄漱罷一裴回。',32,'全唐诗/poet.song.217000.json','["野店柴門傍水開，憑欄漱罷一裴回。", "雲來嶺表商量雨，峯繞溪灣物色梅。"]'),
('e0171b9d-ad93-4590-8986-a4d152c02d06','郊行雨','潘牥','宋','宋诗','song-poetry','','[]','出郭忽數里，雨餘秋意偏。',48,'全唐诗/poet.song.217000.json','["出郭忽數里，雨餘秋意偏。", "遠山青入霧，野水白平田。", "鷺立斜陽去，牛依古樹眠。", "不辭泥濘極，即此是豐年。"]'),
('03751def-df37-448b-8beb-35d3d37a86ba','江行','潘牥','宋','宋诗','song-poetry','','[]','急櫓鳴鵝鸛，喧灘閙鼓鼙。',48,'全唐诗/poet.song.217000.json','["急櫓鳴鵝鸛，喧灘閙鼓鼙。", "風隨山曲折，船與浪高低。", "春淺霜連夜，天隨月半溪。", "嵯峨如許石，直欠一鎸題。"]'),
('192e224f-5b77-4332-8f43-7b5e921e7d7a','江舍','潘牥','宋','宋诗','song-poetry','','[]','近郭畏囂塵，移居在水濱。',48,'全唐诗/poet.song.217000.json','["近郭畏囂塵，移居在水濱。", "江山千古意，松竹四時春。", "賓客門無禁，詩書筆有神。", "何郎好心事，鷗鷺亦相親。"]'),
('ea78c4ba-80a1-415d-a77e-570ab5e85bfe','樓','潘牥','宋','宋诗','song-poetry','','["\u592a\u6e56"]','突兀樓居倚碧空，松江西畔太湖中。',32,'全唐诗/poet.song.217000.json','["突兀樓居倚碧空，松江西畔太湖中。", "天垂十二闌干角，月滿三千世界中。"]'),
('d60a0e19-74e3-4e65-9c6b-45794ac60b69','琴  其一','潘牥','宋','宋诗','song-poetry','','[]','只是尋常操，傳來便不同。',48,'全唐诗/poet.song.217000.json','["只是尋常操，傳來便不同。", "初疑聲已盡，旋覺曲方中。", "清碎如章草，和平似國風。", "自從今夕聽，吾耳一生聾。"]'),
('f57a2415-d3f3-4d2c-a5db-5712b8f89932','琴  其二','潘牥','宋','宋诗','song-poetry','','[]','操高不救西山死，瓢飲空稱陋巷賢。',32,'全唐诗/poet.song.217000.json','["操高不救西山死，瓢飲空稱陋巷賢。", "二調只堪彈我聽，不消舉此貴人前。"]'),
('6d2c7038-9cc6-49d7-a11d-722edb5d4625','琴  其三','潘牥','宋','宋诗','song-poetry','','[]','道人清夜理瑶琴，愛學啼烏囀羽音。',32,'全唐诗/poet.song.217000.json','["道人清夜理瑶琴，愛學啼烏囀羽音。", "莫把世人工拙論，世人彈耳不彈心。"]'),
('b80ef97a-120e-4d81-bce7-d5c383b4cc2f','劍','潘牥','宋','宋诗','song-poetry','','[]','并州昔用千金賈，流落人間歲月多。',32,'全唐诗/poet.song.217000.json','["并州昔用千金賈，流落人間歲月多。", "背有龍文空自寶，世無麟血倩誰磨。"]'),
('19210bc4-64a2-4cde-943e-21e0032da7b4','燈','潘牥','宋','宋诗','song-poetry','','[]','一點無多小似螢，虛堂夜靜滅還明。',32,'全唐诗/poet.song.217000.json','["一點無多小似螢，虛堂夜靜滅還明。", "若教安頓無風處，猶可從容到五更。"]'),
('14ae7c94-7b5e-4b42-8f3f-2819de893e50','百舌','潘牥','宋','宋诗','song-poetry','','[]','問渠得似山間日，猶自筠籠叫不停。',32,'全唐诗/poet.song.217000.json','["問渠得似山間日，猶自筠籠叫不停。", "我亦多言私自省，再三守口要如瓶。"]'),
('29e8c12d-f591-483c-8d20-9b5e409810f4','代百舌答','潘牥','宋','宋诗','song-poetry','','[]','禍福無門未可憑，天教有口可無聲。',32,'全唐诗/poet.song.217000.json','["禍福無門未可憑，天教有口可無聲。", "莫嫌口解爲身累，雁不能鳴反自烹。"]'),
('9498c312-8419-4080-88a7-17ab3355f08c','子規','潘牥','宋','宋诗','song-poetry','','[]','一聲啼破萬山雲，我正思歸自喜聞。',32,'全唐诗/poet.song.217000.json','["一聲啼破萬山雲，我正思歸自喜聞。", "莫向貴人庭樹下，王孫金彈不饒君。"]'),
('0c928fa9-0a7d-458e-9f64-cebeb5a58dc6','鵲 肥沙','潘牥','宋','宋诗','song-poetry','','[]','石坡泥淺無蟲蚓，小竹纔高一尺餘。',32,'全唐诗/poet.song.217000.json','["石坡泥淺無蟲蚓，小竹纔高一尺餘。", "獨自行行無可啄，低頭努觜欲何如。"]'),
('dee3beb8-a87c-46af-a9a5-b1f302ff059c','鵲 曬翅','潘牥','宋','宋诗','song-poetry','','[]','揀盡南枝與北枝，風吹霜竹葉還稀。',32,'全唐诗/poet.song.217000.json','["揀盡南枝與北枝，風吹霜竹葉還稀。", "旁人憂喜非吾事，且自梳翎向落暉。"]'),
('2bd118b4-0e66-4e22-8b4a-d6dbbb6cb36d','蜂','潘牥','宋','宋诗','song-poetry','','[]','今歲分成第幾房，刳松爲屋蜜爲糧。',64,'全唐诗/poet.song.217000.json','["今歲分成第幾房，刳松爲屋蜜爲糧。", "門臨花圃身長逸，架近松窗蠟漸香。", "長日去憑雙翅遠，有時淡染半腰黄。", "西園風雨無堪采，待得天晴出未忙。"]'),
('d291221c-82e8-4ddc-9735-94df3c0106c6','蟬','潘牥','宋','宋诗','song-poetry','','[]','秋事遽如許，空山夜已蟬。',48,'全唐诗/poet.song.217000.json','["秋事遽如許，空山夜已蟬。", "多吟清露底，偏傍竹籬邊。", "翼似霜餘葉，聲如雨後泉。", "兒曹讀書罷，貪聽不成眠。"]'),
('f89c0869-3437-42c0-a518-3b51b2050240','漁父  其一','潘牥','宋','宋诗','song-poetry','','[]','小舟真箇白鷗輕，一一鳴榔作陣行。',32,'全唐诗/poet.song.217000.json','["小舟真箇白鷗輕，一一鳴榔作陣行。", "打得鮮鱗歸去早，蓼花深處賣魚羹。"]'),
('55a853af-bcf3-4656-a14d-d2c01eccaec1','漁父  其二','潘牥','宋','宋诗','song-poetry','','[]','生來一舸鎮隨身，柳月蘆風處處春。',32,'全唐诗/poet.song.217000.json','["生來一舸鎮隨身，柳月蘆風處處春。", "翁自醉眠魚自樂，無心重理舊絲綸。"]'),
('369d4cc9-ab3e-442e-a0e6-cabbfc30ee29','讀道書  其一','潘牥','宋','宋诗','song-poetry','','[]','道人掃灑一間房，紙帳梅花滋味長。',32,'全唐诗/poet.song.217000.json','["道人掃灑一間房，紙帳梅花滋味長。", "清曉起來無箇事，爐香端簡面虛皇。"]'),
('2d3f5b5b-0ae7-4263-bc14-779ea92c9af7','讀道書  其二','潘牥','宋','宋诗','song-poetry','','[]','道人清曉炷爐薰，嵐重衣巾濕露痕。',32,'全唐诗/poet.song.217000.json','["道人清曉炷爐薰，嵐重衣巾濕露痕。", "課罷楞嚴經一卷，小窗徙倚候啼猿。"]'),
('4dd18ce4-9e2b-4732-a55f-3753cf1b14ea','道士造籙','潘牥','宋','宋诗','song-poetry','','[]','不見東山謝紫虛，時時獨自撚吟鬚。',64,'全唐诗/poet.song.217000.json','["不見東山謝紫虛，時時獨自撚吟鬚。", "常憑香案監抄籙，時點朱砂爲訂符。", "日裏慣曾參寶語，夜深夢必入清都。", "此心却恐多君事，廢了工夫火一銖。"]'),
('1d1ce13a-4ab9-4b3e-b993-544d0f163076','醫士','潘牥','宋','宋诗','song-poetry','','[]','聞君妙得醫王訣，我病勞君指下求。',32,'全唐诗/poet.song.217000.json','["聞君妙得醫王訣，我病勞君指下求。", "天與一般愚直性，不知何劑可能瘳。"]'),
('34fae41d-6982-482a-ab74-b71359bb727e','相士','潘牥','宋','宋诗','song-poetry','','[]','女媧摶土費工夫，箇箇生來箇箇麤。',64,'全唐诗/poet.song.217000.json','["女媧摶土費工夫，箇箇生來箇箇麤。", "有底終須還富貴，無時換不得頭顱。", "若還非我安知我，莫道今吾非故吾。", "也要終南分一半，麻衣還肯點頭無。"]'),
('6d6856a9-8ea3-4f52-9b3e-072a97cfef71','題嶽麓寺道鄉臺','潘牥','宋','宋诗','song-poetry','','[]','坡仙不謫黄，黄應無雪堂。',72,'全唐诗/poet.song.217000.json','["坡仙不謫黄，黄應無雪堂。", "道鄉不如新，此臺無道鄉。", "青山非其人，山靈能頡頏。", "一落名勝手，境與人俱香。", "悲吟倚空寂，臨眺生慨慷。", "道鄉不可作，承君不可忘。"]'),
('93e8e4bc-932e-41e9-8d58-6e03123cc83e','宗祀夕','潘牥','宋','宋诗','song-poetry','','[]','玉天無滓月光寒，霽色分明在露盤。',32,'全唐诗/poet.song.217000.json','["玉天無滓月光寒，霽色分明在露盤。", "一夜九重全不寐，時教中使捲簾看。"]'),
('c6bb9fa4-0dd4-48a6-bff5-af233b6d2a4f','恭謝駕自景靈宮回丞相以下皆簪花','潘牥','宋','宋诗','song-poetry','','[]','輦路安排看駕迴，千官花壓帽簷垂。',32,'全唐诗/poet.song.217000.json','["輦路安排看駕迴，千官花壓帽簷垂。", "君王不輟憂勤念，玉貌還如未插時。"]'),
('2dd95cd9-836c-42d9-995a-d29dd88a183a','題陳圖南鼾睡圖','潘牥','宋','宋诗','song-poetry','','[]','甲馬營中紫氣高，屬豬人已著黄袍。',32,'全唐诗/poet.song.217000.json','["甲馬營中紫氣高，屬豬人已著黄袍。", "此回天下都無事，可是山中睡得牢。"]'),
('137a7d3d-0abb-4efd-a3d5-4f5f9c2ca9db','涵空閣','潘牥','宋','宋诗','song-poetry','','[]','危欄貪倚眺，薄暮不能休。',48,'全唐诗/poet.song.217000.json','["危欄貪倚眺，薄暮不能休。", "直下疑無地，滿前都是秋。", "晚山平入畫，新月側當樓。", "莫說興亡事，吟人本白頭。"]'),
('83b7996e-e869-4ade-8e90-76fdd9087134','虎丘分韻得落字','潘牥','宋','宋诗','song-poetry','','[]','急雨成快晴，晚日射□薄。',48,'全唐诗/poet.song.217000.json','["急雨成快晴，晚日射□薄。", "院靜轆轤聲，崖古枇杷落。", "澄泓有潛鱗，寥廓無歸鶴。", "明年當掛冠，吾志在丘壑。"]'),
('5716f80a-9e1f-46a5-98ad-a26d3e817646','次陳仲文八月十二夜韻','潘牥','宋','宋诗','song-poetry','','[]','癡雲吹盡月行天，新琢冰輪欠半邊。',64,'全唐诗/poet.song.217000.json','["癡雲吹盡月行天，新琢冰輪欠半邊。", "須信缺中元不缺，便教圓處可長圓。", "寒生沙渚雁初下，冷浸紗窗人未眠。", "萬事虛盈皆此類，幾看如鏡復如弦。"]'),
('9535f419-8102-4fa7-9166-fa270b1393f5','雪中聽緜州鄧道士琴','潘牥','宋','宋诗','song-poetry','','[]','黄冠家萬里，忽此動瑶琴。',48,'全唐诗/poet.song.217000.json','["黄冠家萬里，忽此動瑶琴。", "歲暮多風雪，天涯少信音。", "淒涼當日事，寂寞此時心。", "我醉君休去，蒲團共夜深。"]'),
('bf77a84e-e2d7-4313-9a6e-34a18f225424','曹娥廟','潘牥','宋','宋诗','song-poetry','','[]','一川紅漲夕陽波，幼婦碑殘鎖綠蘿。',32,'全唐诗/poet.song.217000.json','["一川紅漲夕陽波，幼婦碑殘鎖綠蘿。", "不止但爭三十里，曹瞞元不識曹娥。"]'),
('ea9c5730-2d99-4712-93c9-74dca20d2c02','書趙知院墨梅後','潘牥','宋','宋诗','song-poetry','','[]','疏蘂暗藏春意足，橫枝老閲歲華深。',32,'全唐诗/poet.song.217000.json','["疏蘂暗藏春意足，橫枝老閲歲華深。", "廣平能賦君能畫，總是平生鐵石人。"]'),
('41fd4da6-d8ca-4533-ba7f-850db0dbf409','英烈夫人','潘牥','宋','宋诗','song-poetry','','[]','淮海艷姬毛惜惜，蛾眉有此萬人英。',64,'全唐诗/poet.song.217000.json','["淮海艷姬毛惜惜，蛾眉有此萬人英。", "恨無匕首學秦女，向使裹頭真杲卿。", "玉骨花顔城下土，冰魂雪魄史間名。", "古今無限要金者，歌舞筵中過一生。"]'),
('5495bb85-4ca8-4e5c-a835-91d7d9eaab4e','茶  其一','潘牥','宋','宋诗','song-poetry','','[]','透屋松風蠏眼湯，野人紗帽自煎嘗。',32,'全唐诗/poet.song.217000.json','["透屋松風蠏眼湯，野人紗帽自煎嘗。", "諫議不分三道印，趙州剩借一甌香。"]'),
('8836f930-2802-4ed3-8e77-ca47e41594ea','茶  其二','潘牥','宋','宋诗','song-poetry','','[]','瑞草如梅早占春，誰將龍鳳付仙人。',32,'全唐诗/poet.song.217000.json','["瑞草如梅早占春，誰將龍鳳付仙人。", "烹來盞內花猶白，澆出胸中不語塵。"]'),
('db0632fd-9d9b-470a-934d-998488ae400c','茶  其三','潘牥','宋','宋诗','song-poetry','','[]','豕腹中空暗浪驚，羊腸旋復繞車聲。',64,'全唐诗/poet.song.217000.json','["豕腹中空暗浪驚，羊腸旋復繞車聲。", "纔看雲脚如絲動，便覺詩脾作雪清。", "麴糵無功將退舍，蘼蕪何罪亦遭烹。", "傍人莫訝能句賦，窗下觀書眼倍明。"]'),
('ea0b2b79-a2d6-4c6d-9428-6db0b2b8eacb','茶  其四','潘牥','宋','宋诗','song-poetry','','[]','不因將軍打門驚，瓦釜何從得此聲。',64,'全唐诗/poet.song.217000.json','["不因將軍打門驚，瓦釜何從得此聲。", "誰道枯腸三椀怯，能令俗骨一生清。", "鴻漸絕怕膏新絕，党進那知雪水烹。", "從此客來真水厄，吾方正酒學泉明。"]'),
('3d195a1e-1b46-428c-bff2-a3ce293d4298','謝林簿遺廬阜茶芽  其一','潘牥','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','誰採匡廬紫玉芽，二千里路到吾家。',32,'全唐诗/poet.song.217000.json','["誰採匡廬紫玉芽，二千里路到吾家。", "磚爐石銚自烹喫，清落詩脾作雪花。"]'),
('9401c762-f4b7-4356-b108-6cda14c23d0f','謝林簿遺廬阜茶芽  其二','潘牥','宋','宋诗','song-poetry','','[]','向來皇祐最升平，民識犁鋤不識兵。',32,'全唐诗/poet.song.217000.json','["向來皇祐最升平，民識犁鋤不識兵。", "茶向此時還有錄，令人長羨蔡端明。"]'),
('e59ec569-290a-4a11-a41a-d2d0763652a7','菊花','潘牥','宋','宋诗','song-poetry','','[]','露葉霜枝矮作團，淡黄殘綠故瓓珊。',32,'全唐诗/poet.song.217000.json','["露葉霜枝矮作團，淡黄殘綠故瓓珊。", "柴門盡日無人到，獨自栽花獨自看。"]'),
('9d12e370-2e4e-4e86-b9d0-6c747288886d','山居苦','潘牥','宋','宋诗','song-poetry','','[]','門外車聲寂不譁，數椽凈掃小山家。',64,'全唐诗/poet.song.217000.json','["門外車聲寂不譁，數椽凈掃小山家。", "懶鉏茂叔窗前草，賸種淵明籬下花。", "不飲客來還貰酒，長閑飯罷必煎茶。", "紫巖堪隠吾偕子，雪後春深蕨已芽。"]'),
('09803f28-704e-4c39-a95f-a302a194035f','壽士人','潘牥','宋','宋诗','song-poetry','','[]','花朝清曉雨初收，瑞氣祥風滿玉樓。',64,'全唐诗/poet.song.217000.json','["花朝清曉雨初收，瑞氣祥風滿玉樓。", "蓬矢重逢三八日，椿齡再祝一千秋。", "飛黄去逐沖霄鳳，詔紫來從入谷騶。", "富貴光榮皆分事，早看名姓動金甌。"]'),
('7646a064-d805-4ade-a939-9d69fef6d4a9','壽翁漕','潘牥','宋','宋诗','song-poetry','','[]','攙先三日上元前，天産皇家間世才。',64,'全唐诗/poet.song.217000.json','["攙先三日上元前，天産皇家間世才。", "臺閣久傾紅藥賦，山川聊爲錦衣回。", "地分八群尊威節，天遣千花獻壽盃。", "只恐金甌名不掩，使星歸處是三台。"]'),
('a4956458-21bf-4f4b-b3f5-37a730667548','壽友人','潘牥','宋','宋诗','song-poetry','','[]','當年崧岳慶生賢，恰在新秋四日前。',64,'全唐诗/poet.song.217000.json','["當年崧岳慶生賢，恰在新秋四日前。", "萬縷水沈燃寶鴨，千鍾醽醁酌金船。", "冰桃雪藕將陪宴，雨柏霜松莫計年。", "金鼎若容負薪水，亦令雞犬得神仙。"]'),
('90355223-a42d-4904-b02b-fc8eaa762df2','句','潘牥','宋','宋诗','song-poetry','','[]','竹纔生便直，梅到死猶香。',12,'全唐诗/poet.song.217000.json','["竹纔生便直，梅到死猶香。"]'),
('6d5dd8c6-c93d-43e3-86ee-244ac0a9c318','存目','潘牥','宋','宋诗','song-poetry','','[]','詩題：灃陵旅店首句：一郭依稀隔渡頭。',18,'全唐诗/poet.song.217000.json','["詩題：灃陵旅店首句：一郭依稀隔渡頭。"]'),
('16f55dc8-28d4-4592-992d-246363f395e3','折齒歌','羅椅','宋','宋诗','song-poetry','','[]','春衫未成錦機語，棠棣半花鳳一羽。',160,'全唐诗/poet.song.217000.json','["春衫未成錦機語，棠棣半花鳳一羽。", "象牀雪綜小龍梭，細穴銀光吐冰縷。", "西鄰郎君東海歸，芙蓉露白杏雨肥。", "十二欄邊說幽怨，勸織南浦雙鴛飛。", "匿蘭含蕙無消息，春酲彤霞亂玉色。", "小龍噓出風雨聲，奔騰觸裂雙白石。", "白石國城三十六，女子軍來兩城覆。", "鸞歌猿嘯强低昂，北戶風來如箭鏃。", "章臺公子真豪縱，能以微詞相感動。", "郎君輒莫更癡腸，忍作肝心可人痛。"]'),
('f889f5be-237d-4c90-a18a-3aaed12d68e8','挑濠歌','羅椅','宋','宋诗','song-poetry','','[]','滿城挑濠五更起，城頭直挑到城尾。',128,'全唐诗/poet.song.217000.json','["滿城挑濠五更起，城頭直挑到城尾。", "一彎一轉春蛇長，圍人方圓三十里。", "去年十月霜淒淒，挑濠人立霜中嗁。", "今年一春春雨多，泥滑將奈挑濠何。", "只今清明霜不若，皇天何時收雨脚。", "幾人带雨濠上啼，半溼半饑春病瘧。", "雨之久，可以晴。", "濠之長，可以城。", "只愁挑得濠始竟，公家又有守濠令。"]'),
('1c6eefe7-206c-42bc-a27e-79334105a4a0','田蛙歌','羅椅','宋','宋诗','song-poetry','','[]','蝦蟆，蝦蟆，汝本吾田蛙。',106,'全唐诗/poet.song.217000.json','["蝦蟆，蝦蟆，汝本吾田蛙。", "渴飲吾稻根水，饑食吾禾穟花。", "池塘雨初霽，籬落月半斜。", "啁啁又向他人叫，使我惆悵悲無涯。", "蝦蟆對我說，使君休怨嗟。", "古田千年八百主，如今一年換一家。", "休怨嗟，休怨嗟。", "明年此日君見我，不知又是誰田蛙。"]'),
('fe7f36a8-b2f6-42c6-8503-3b90a749d368','題信豐縣城門六首 拱日','羅椅','宋','宋诗','song-poetry','','[]','桃紅抱城東，武山排闥入。',48,'全唐诗/poet.song.217000.json','["桃紅抱城東，武山排闥入。", "杲日出扶桑，橘紅蘸溪溼。", "公退倚朱欄，萬象俱收拾。", "無數喚舟人，沙頭雁行入。"]'),
('891871d9-d745-41de-a56d-15def73b252e','題信豐縣城門六首 安成','羅椅','宋','宋诗','song-poetry','','[]','門前楊柳樹，長繫波頭船。',48,'全唐诗/poet.song.217000.json','["門前楊柳樹，長繫波頭船。", "隔岸幾人家，青林吐炊烟。", "飛鳥逐林間，遊鱼躍深淵。", "物各適其性，於人胡不然。"]'),
('2a04835b-eefa-4eb6-8622-99f9a4d6f859','題信豐縣城門六首 禾豐','羅椅','宋','宋诗','song-poetry','','[]','城西路平夷，五更近水南。',48,'全唐诗/poet.song.217000.json','["城西路平夷，五更近水南。", "旭日明高岡，瑞烟鎖叢杉。", "時和歲豐稔，歸人多醉酣。", "仙臺玉簫聲，對景思鸞驂。"]'),
('fef6c857-110c-47bc-8b08-ccd00f8aecb9','題信豐縣城門六首 清平','羅椅','宋','宋诗','song-poetry','','[]','行行西復西，稍喜市聲靜。',48,'全唐诗/poet.song.217000.json','["行行西復西，稍喜市聲靜。", "征夫指前路，望望梅花嶺。", "淡烟雞犬村，落日牛羊徑。", "忽見荷鋤人，喚起歸田興。"]'),
('a8ff3d9f-4177-4a70-82a5-e91c217dc593','題信豐縣城門六首 民信','羅椅','宋','宋诗','song-poetry','','[]','南山天馬來，南城下盤踞。',48,'全唐诗/poet.song.217000.json','["南山天馬來，南城下盤踞。", "前撞古寺鐘，後彫譙樓鼓。", "我來俯崔巍，山靈相呼舞。", "年豐民物熙，細聽閭閻語。"]'),
('88ac81cd-8dae-41ec-bafc-5a35099d5feb','題信豐縣城門六首 朝天','羅椅','宋','宋诗','song-poetry','','[]','駕言出北門，長橋拱門外。',48,'全唐诗/poet.song.217000.json','["駕言出北門，長橋拱門外。", "雙溪東西來，到此而始匯。", "人言似章貢，玉虹夾其背。", "擬作合江亭，景物無小大。"]'),
('f999649e-39c6-4780-adb3-061e5cb10abe','次劉孟元見贄韻二首  其一','羅椅','宋','宋诗','song-poetry','','[]','不見碧瑶叟，年齡二十餘。',48,'全唐诗/poet.song.217000.json','["不見碧瑶叟，年齡二十餘。", "兒今亦耆舊，孫復抱詩書。", "後浪催人老，長牋不我疏。", "眼中誰有此，雅雅更魚魚。"]'),
('d2855afe-dd36-43f2-be8f-2a8924b9fa43','次劉孟元見贄韻二首  其二','羅椅','宋','宋诗','song-poetry','','[]','久坐不知夜，饑鼯窺瓦檠。',48,'全唐诗/poet.song.217000.json','["久坐不知夜，饑鼯窺瓦檠。", "詩徒我樂國，酒不打愁城。", "白雪夫君句，黄花老我情。", "商量能任不，勝欲飲公榮。"]'),
('d6b51c3f-9a3f-46da-991c-8c51567355c3','冷泉亭','羅椅','宋','宋诗','song-poetry','','[]','老木碧毿毿，幽亭著兩三。',48,'全唐诗/poet.song.217000.json','["老木碧毿毿，幽亭著兩三。", "山飛不到地，空處遂爲巖。", "古塔開蒼蘚，清泉滴暮嵐。", "遊人莫來此，渠正試春衫。"]'),
('33864780-d35c-4a7d-9322-8c4279616c18','溪南春曉','羅椅','宋','宋诗','song-poetry','','[]','行逢二三月，春映掌中杯。',48,'全唐诗/poet.song.217000.json','["行逢二三月，春映掌中杯。", "綠久山猶淺，花寒雨未開。", "誰能奈愁得，拌不上樓來。", "更莫看雲坐，瀟湘有雁回。"]'),
('742dc01a-c1c2-4350-bf57-a817835bf0dd','寄答楷姪','羅椅','宋','宋诗','song-poetry','','[]','時秋四壁冷，片紙百回看。',48,'全唐诗/poet.song.217000.json','["時秋四壁冷，片紙百回看。", "字古微侵隸，吟清不到寒。", "人生快意有，天下好時難。", "澗水光如月，吾琴爾去彈。"]'),
('6b5b268b-b477-4c72-9a05-f7463dcc44ba','秋日雜興二首  其一','羅椅','宋','宋诗','song-poetry','','[]','秋山何言哉，萬物興自闌。',48,'全唐诗/poet.song.217000.json','["秋山何言哉，萬物興自闌。", "昔翳春空雲，今作道上斑。", "况此江浦蕙，幾何不爲菅。", "幽泉大自在，映月瀉潺湲。"]'),
('d6a3355a-3e7f-4f7f-9bed-f99e4b80a754','秋日雜興二首  其二','羅椅','宋','宋诗','song-poetry','','[]','躍魚甚微細，解轉秋江漪。',48,'全唐诗/poet.song.217000.json','["躍魚甚微細，解轉秋江漪。", "一靜未滿刻，一動輒移時。", "豈由魚樂乎，或是水性之。", "商量未渠穩，風急蘆花低。"]'),
('0e20e190-faab-4c6f-8505-df2be8d7e18e','題方武城詩卷','羅椅','宋','宋诗','song-poetry','','[]','斯人懷妙質，事事合唐賢。',48,'全唐诗/poet.song.217000.json','["斯人懷妙質，事事合唐賢。", "命短於長吉，吟情似閬仙。", "寒鴉政鳴噪，獨鶴已蹁躚。", "落日山亭下，沈思一愴然。"]'),
('55f76173-5bb3-4c30-925b-ef3b361a468d','謁趙東野','羅椅','宋','宋诗','song-poetry','','[]','水樹摇窗榻見天，空花換盡我依然。',64,'全唐诗/poet.song.217000.json','["水樹摇窗榻見天，空花換盡我依然。", "吟情豁處因聞道，隠趣深來頗入禪。", "不以耳聽何用洗，且無琴在底須絃。", "未知遇得開關否，破費滄江月一船。"]'),
('d9e0822f-5d4f-486f-bfa4-0bc2290669b9','次歐振仲見贄韻','羅椅','宋','宋诗','song-poetry','','[]','紫蘭賸有無離騷，梅花不見見水曹。',64,'全唐诗/poet.song.217000.json','["紫蘭賸有無離騷，梅花不見見水曹。", "眇焉何許是人物，枉子秣馬行林皋。", "古人相逢未易得，紫燕西飛東伯勞。", "吟餘切莫談時事，正攪春思分二毛。"]'),
('df8b94f7-20df-4e83-9e62-45907f36dbd4','寄危驪塘贈以古鑑二首  其一','羅椅','宋','宋诗','song-poetry','','[]','百尺樓頭山雨長，夢提白髮濯滄浪。',64,'全唐诗/poet.song.217000.json','["百尺樓頭山雨長，夢提白髮濯滄浪。", "從渠金带花成簇，何處魚羹飯不香。", "語妙囊中了今古，騷成肘後繫瀟湘。", "山寒歲晚蘭苗盛，欲當包茅獻草堂。"]'),
('e4615bfc-7840-4cb8-ae66-522c075a9092','寄危驪塘贈以古鑑二首  其二','羅椅','宋','宋诗','song-poetry','','[]','澗底春冰偶不融，風前凝作水晶宮。',64,'全唐诗/poet.song.217000.json','["澗底春冰偶不融，風前凝作水晶宮。", "古人心事如此鑑，今代眼明惟有公。", "落月還應照太白，秋江只合瞰涪翁。", "送君去貌驪塘影，影見疏梅颭晚風。"]'),
('82251dac-4133-4f57-bed2-fca90a30e47e','謝南劍黄使君贈松紋劍','羅椅','宋','宋诗','song-poetry','','[]','使君袖裏玉淵虬，曾截蠻江江上流。',64,'全唐诗/poet.song.217000.json','["使君袖裏玉淵虬，曾截蠻江江上流。", "海立山摇三尺外，風盲雨怪一時休。", "民元不許佩牛犢，客政何妨彈蒯緱。", "遮莫塵清便回使，青山猶赦郅支頭。"]'),
('608a43de-b4ea-41dd-9dfe-32e6ef45fcfb','白蓮花','羅椅','宋','宋诗','song-poetry','','[]','白鸞仙人按羽衣，曲中弄影江南漪。',67,'全唐诗/poet.song.217000.json','["白鸞仙人按羽衣，曲中弄影江南漪。", "江妃閉置未許歸，一把青寒縈玉絲。", "玉絲蟬連不禁折，折著透根仍透葉。", "風流極處絕成愁，君不見秋扇團圓似明月。"]'),
('27462801-cb2b-4cb4-a84d-39f22f14b857','江石','羅椅','宋','宋诗','song-poetry','','[]','勢橫截江虎踞足，白龜却行馮夷哭。',64,'全唐诗/poet.song.217000.json','["勢橫截江虎踞足，白龜却行馮夷哭。", "大川當時波沄沄，石也如此受命獨。", "水石擊撞無了時，因危見節乃見奇。", "世間大有胡廣輩，欠讀澗民江石詩。"]'),
('9c3fcfbb-8aee-4baf-808b-045d0359a94d','題圓覺寺小軒','羅椅','宋','宋诗','song-poetry','','["\u897f\u6e56"]','禪子安排定不癡，數拳石映半泓池。',64,'全唐诗/poet.song.217000.json','["禪子安排定不癡，數拳石映半泓池。", "巖如大厦元生就，水似人心未動時。", "二月春深梅不覺，五更風起檜先知。", "青林野寺西湖路，直得先生一首詩。"]'),
('b0334507-92e0-4415-afa5-bd531aee5563','遠遊','羅椅','宋','宋诗','song-poetry','','[]','因夢吳雲賦遠遊，江花扶柁水悠悠。',64,'全唐诗/poet.song.217000.json','["因夢吳雲賦遠遊，江花扶柁水悠悠。", "半輪月散千山影，一葉舟勝萬斛愁。", "天氣漸於寒食近，春風祗到牡丹休。", "水程孤冷難爲夜，起吸滄江當拍浮。"]'),
('151444ef-eff5-4256-9402-e467c52dd1a7','題信豐縣覽秀亭','羅椅','宋','宋诗','song-poetry','','[]','燕賀初成百尺臺，一新粉堞更周迴。',64,'全唐诗/poet.song.217000.json','["燕賀初成百尺臺，一新粉堞更周迴。", "水流東北交虹去，山自西南擁翠來。", "瓦縫參差千戶密，市城翕聚六門開。", "賓儔眺望從今始，佳氣隨風入酒杯。"]'),
('52121dac-89f7-4550-9545-9aa0e88dc6d8','元旦試筆','羅椅','宋','宋诗','song-poetry','','[]','聞道黄河徹底清，千年氣數此分明。',32,'全唐诗/poet.song.217000.json','["聞道黄河徹底清，千年氣數此分明。", "堯民商耉渾蹉過，輸與殘生見太平。"]'),
('ca3b7794-1d43-4274-90e5-209d3eb5ba92','題向伯僑吳松雪霽圖三首  其一','羅椅','宋','宋诗','song-poetry','','[]','暖來日曬冰滑，恨極天寒竹修。',28,'全唐诗/poet.song.217000.json','["暖來日曬冰滑，恨極天寒竹修。", "雲開梵鐸相訴，水活漁船自流。"]'),
('1e229510-9710-4ccf-aeb4-aba68fd92774','題向伯僑吳松雪霽圖三首  其二','羅椅','宋','宋诗','song-poetry','','[]','天上清流雲片，人間名勝吳松。',28,'全唐诗/poet.song.217000.json','["天上清流雲片，人間名勝吳松。", "兩賢相厄已甚，頼有斜陽半峯。"]'),
('15ee47b6-c715-4578-ac42-7c5df7d217b4','題向伯僑吳松雪霽圖三首  其三','羅椅','宋','宋诗','song-poetry','','[]','天隨漫解理艇，不慣霜後霜前。',28,'全唐诗/poet.song.217000.json','["天隨漫解理艇，不慣霜後霜前。", "幸自竹篙閒著，拋來借與鄰船。"]'),
('7ad2c38b-d735-4c90-a5eb-985a17663d9a','孫氏女哀詞三章  其一','羅椅','宋','宋诗','song-poetry','','[]','秋風蕭颯兮白露零，汝墳何在兮何草爲青。',51,'全唐诗/poet.song.217000.json','["秋風蕭颯兮白露零，汝墳何在兮何草爲青。", "昨秋此日兮猶冀汝生，灑墨我別兮人間父子之情。", "我枯如腊兮涕更縱橫。"]'),
('31520287-cbee-4702-88ae-b86a694dd560','孫氏女哀詞三章  其二','羅椅','宋','宋诗','song-poetry','','[]','秋風蕭颯兮白露晞，五十年閨闥兮甯識馬嘶。',50,'全唐诗/poet.song.217000.json','["秋風蕭颯兮白露晞，五十年閨闥兮甯識馬嘶。", "銜轡迫人兮魂爲之飛，歸來一空兮不死何爲。", "誰爲此禍兮使汝當之。"]'),
('17c7efa6-5ac5-4bf1-b443-f14bcd0432de','孫氏女哀詞三章  其三','羅椅','宋','宋诗','song-poetry','','[]','秋風蕭颯兮白露下，豈不日月兮照我下土。',50,'全唐诗/poet.song.217000.json','["秋風蕭颯兮白露下，豈不日月兮照我下土。", "持此白頭兮言歸何所，默已不堪兮哭微更苦。", "兒孫爲吾一慟兮萬萬古。"]'),
('c5a36c82-1619-46d2-bdd0-a0c35310fa76','瞌睡詩','羅椅','宋','宋诗','song-poetry','','[]','瞌睡從何來，譬若風雨至。',168,'全唐诗/poet.song.217000.json','["瞌睡從何來，譬若風雨至。", "曲几不待憑，虛櫺那暇寄。", "應人眉强撐，伸手扇已墜。", "徑遊華胥國，欲見混沌帝。", "齁齁自成腔，兀兀更有味。", "息疎疑暫醒，氣窒還扶醉。", "兒童欲惱翁，摇膝問某字。", "吻間僅一答，言下已復寐。", "雜然拍手笑，欲嗔嗔不遂。", "何曾參佛祖，先會點頭意。", "何曾逢麴車，流涎已沾袂。", "不省較短長，誰能問興替。", "陰天百怪舞，開口輒差異。", "三百六十日，何似長瞌睡。"]'),
('bbbf9b98-deaf-407f-9247-1d948c6dd922','讀曾景建四詩','羅椅','宋','宋诗','song-poetry','','[]','騷客詩翁死有靈，君行亦足慰飄零。',64,'全唐诗/poet.song.217000.json','["騷客詩翁死有靈，君行亦足慰飄零。", "甫云來共長沙醉，原謂何如澤畔醒。", "一瓣誰堪續香供，四詩今擬當埋名。", "黄花紅葉秋天晚，想見瀟湘野鶩汀。"]'),
('23c14f54-fa06-404a-9440-1537e5d982be','絕句二首  其一','羅椅','宋','宋诗','song-poetry','','[]','巖青樹綠坱兮軋，澗落雲寒折以清。',32,'全唐诗/poet.song.217000.json','["巖青樹綠坱兮軋，澗落雲寒折以清。", "二月山礬九月桂，江南處處得閑行。"]'),
('e9198730-035d-4551-8c9a-6144439a8501','絕句二首  其二','羅椅','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','楚山葉脫洞庭波，紉落毛兮製薜蘿。',32,'全唐诗/poet.song.217000.json','["楚山葉脫洞庭波，紉落毛兮製薜蘿。", "欲識千秋萬古意，前人此句後人哦。"]'),
('b1757444-bab5-4f1f-8e1e-d6e3b012dadb','見陳制帥子華二首  其一','羅椅','宋','宋诗','song-poetry','','[]','北山老子勉齋翁，總把經綸付我公。',64,'全唐诗/poet.song.217000.json','["北山老子勉齋翁，總把經綸付我公。", "胸次詩書行杲日，兵前草木轉春風。", "五谿衣服桑麻盡，萬里東南煙火空。", "直待此行料理著，却鎸歌頌對閩中。"]'),
('9a7b97c2-1388-471c-a589-b13a0c7c8795','見陳制帥子華二首  其二','羅椅','宋','宋诗','song-poetry','','[]','奇功畢竟屬吾曹，狄武襄無諸葛豪。',64,'全唐诗/poet.song.217000.json','["奇功畢竟屬吾曹，狄武襄無諸葛豪。", "翠羽葆行禽孟獲，金龍衣在失儂高。", "春生洲渚千麾出，麥熟崆峒萬矢櫜。", "從此南人不反矣，犂邊犢是带邊刀。"]'),
('67f00f66-6998-4716-8eb3-31b63c908fd2','寄雲巢','羅椅','宋','宋诗','song-poetry','','[]','芰製荷衣不御寒，古人持以傲羅紈。',64,'全唐诗/poet.song.217000.json','["芰製荷衣不御寒，古人持以傲羅紈。", "隠雖有味非中道，出本無心始耐看。", "釣瀨不妨侵帝坐，跨鯨何似對金鑾。", "先生出手前賢上，莫戀松風十二盤。"]'),
('9b6e993f-9cc6-4cee-89be-cdfb61c6960b','寄杜南安子野','羅椅','宋','宋诗','song-poetry','','[]','松竹林中琴一枝，妖嵐散作半江漪。',64,'全唐诗/poet.song.217000.json','["松竹林中琴一枝，妖嵐散作半江漪。", "縣於庾嶺梅差近，政看圜扉草便知。", "熟事無多迎客早，清吟未了放衙遲。", "朔雲野雪滄江遠，不得相從且寄詩。"]'),
('271f4bd0-2d65-4a65-a569-8fe3c6d4937a','酬楊休文','羅椅','宋','宋诗','song-poetry','','[]','未交君臂得君詩，一掬清寒已可知。',64,'全唐诗/poet.song.217000.json','["未交君臂得君詩，一掬清寒已可知。", "寫就榴皮書壁字，吟成松上步虛詞。", "卧看山月涼生夢，饑嚼梅花香透脾。", "襆被携琴不可晚，江郊今政雪來時。"]'),
('33969c13-b8d0-4999-90cc-d030971fa99f','江水','羅椅','宋','宋诗','song-poetry','','[]','江雲粘水濕西風，冷落汀洲起夜鴻。',32,'全唐诗/poet.song.217000.json','["江雲粘水濕西風，冷落汀洲起夜鴻。", "甚欲吟秋少才思，不如岸北岸南楓。"]'),
('ade0a329-821d-431f-b609-3f891cc504bc','句','羅椅','宋','宋诗','song-poetry','','[]','華裾客子袖文過。',8,'全唐诗/poet.song.217000.json','["華裾客子袖文過。"]'),
('8d25aa5e-51a6-4df1-864c-9d96151945df','贊崇禧丈室二仙圖','張榘','宋','宋诗','song-poetry','','[]','鹿皮槲葉，容顔枯槁。',40,'全唐诗/poet.song.217000.json','["鹿皮槲葉，容顔枯槁。", "青巾白袍，飄然氣貌。", "不同者形，所同者道。", "金丹一丸，天地同老。"]'),
('9c178bb9-9cf0-4cde-84c7-1354bca89246','敬餞劉興伯提幹之官','張榘','宋','宋诗','song-poetry','','[]','平生子劉子，勁氣橫秋霜。',132,'全唐诗/poet.song.217000.json','["平生子劉子，勁氣橫秋霜。", "不肯作短簿，海漘駕飛航。", "稜嶒高頰顴，碧眼鬚眉蒼。", "鶑花風月夜，錦繡傾肝腸。", "諸公盍推轂，置之白玉堂。", "筦庫着此士，四海空茫茫。", "僕也客於浙，雲阡凄故鄉。", "退鷁豈坦率，瞽無預文章。", "乘除君晚泰，尚欲思激昂。", "年饑僅半菽，羞澀無酒漿。", "贐別祗此詩，君無誚凄凉。"]'),
('7ec1b07b-2331-46c9-804c-6cf3ba5538aa','登鍾山','張榘','宋','宋诗','song-poetry','','[]','登高得勝遊，暫喜塵鞅脫。',48,'全唐诗/poet.song.217000.json','["登高得勝遊，暫喜塵鞅脫。", "林深鳥聲微，石兀馬足滑。", "一笑立高寒，雙明渺遐闊。", "酒酣百慮消，世事等毫末。"]'),
('835b2e65-70a1-4e3f-bb07-31939b43faa0','送姚提幹行','張榘','宋','宋诗','song-poetry','','[]','虛齋鎮東鄞，從之南容君。',180,'全唐诗/poet.song.217000.json','["虛齋鎮東鄞，從之南容君。", "我初未之識，邕翰傾殷勤。", "修潔以博習，秀美而有文。", "玉犀映秋水，英辭湧春雲。", "雞距角魯蜀，昂然鶴非羣。", "晤言到聖處，商也樂所聞。", "最喜直而義，壯音駴鼓鼖。", "告子少於孟，先策養氣勛。", "牛山木信美，謹勿容斧斤。", "助苗固得槁，可使稗不耘。", "觀于所植立，真能張吾軍。", "仁義可效治，淵源在河汾。", "詩書自師友，芝蘭足膏薰。", "剛風接勁翮，去去翔霄旻。", "清時有聞者，必也吾子云。"]'),
('e169e8d4-fbf7-4c36-9ad9-de75341f4ad1','賦山水雪景','張榘','宋','宋诗','song-poetry','','[]','寒雲凝不飛，回風舞霏雪。',72,'全唐诗/poet.song.217000.json','["寒雲凝不飛，回風舞霏雪。", "移多山凹平，漸釋澗聲咽。", "饑烏噤無語，老樹僵欲折。", "薄暮漁舟歸，行人稍稀絕。", "詩翁酒力微，清興渺天末。", "夜深有奇事，玉樓耿寒月。"]'),
('3d9e813b-0034-4d7f-bcc5-869fddc020fb','約臺府同官王元敬以次七人登巾山以前峰月照半江水分韻得半字','張榘','宋','宋诗','song-poetry','','[]','一江貫萬山，雙塔抵層漢。',48,'全唐诗/poet.song.217000.json','["一江貫萬山，雙塔抵層漢。", "我來躡勝遊，寒日已過半。", "夕陽滿孤村，潮勢吞兩岸。", "俯視塵世微，雲邊數聲雁。"]'),
('e4cc680b-5934-41c2-b7ed-8b8d2d0805bf','題三茅峰','張榘','宋','宋诗','song-poetry','','[]','巨靈握奇石，飛落人間世。',180,'全唐诗/poet.song.217000.json','["巨靈握奇石，飛落人間世。", "怒拳一擊破，高下成鼎峙。", "三光發其精，吾岳借之氣。", "精氣久以靈，稍稍見奇異。", "香之爲草木，清之爲泉水。", "天則爲洞天，地則爲福地。", "㠌嶔白雲根，怪巧分瑣細。", "龍潛而虎藏，猿啼而鶴唳。", "始焉三仙居，終也衆真萃。", "至今丹砂光，上下數萬里。", "清遊動高吟，今古幾騷士。", "搜奇探幽深，或僅見一二。", "輸君呼筆神，盡發萬古秘。", "我于塵埃中，讀之如親履。", "呼兒謹縢藏，再拜歸棐几。"]'),
('fc9f422a-bc59-4f99-9c4b-b83137672aca','次韻孟師翰鳳兒花滴滴金  其一','張榘','宋','宋诗','song-poetry','','[]','彩鳳與幽花，動植自形色。',48,'全唐诗/poet.song.217000.json','["彩鳳與幽花，動植自形色。", "命名取肖似，造化何容力。", "丹穴呈九苞，夜夢或吐白。", "未若秋中芳，榮悴了無迹。"]'),
('c6fa083a-a932-45e2-bcf0-8579f7f1edbf','次韻孟師翰鳳兒花滴滴金  其二','張榘','宋','宋诗','song-poetry','','[]','物理紛以移，血或化爲碧。',48,'全唐诗/poet.song.217000.json','["物理紛以移，血或化爲碧。", "安知秋草英，不作金點滴。", "非由冶者鑄，芳葩自光澤。", "誤彼市中攫，一過一目逆。"]'),
('e1816161-5b3a-4c8b-becd-6d87fef927a8','有懷尤贊府季耑','張榘','宋','宋诗','song-poetry','','[]','西風約暮雨，虛亭得新爽。',48,'全唐诗/poet.song.217000.json','["西風約暮雨，虛亭得新爽。", "忽焉見崚嶒，彷佛呈萬象。", "誰其伴孤吟，寒蛩軋幽響。", "碧雲渺佳人，抱膝注遐想。"]'),
('4de1befa-aa7f-47e8-a03b-f993190a2084','題劉直孺拙逸軒','張榘','宋','宋诗','song-poetry','','[]','營營天壤間，孰不爲智使。',196,'全唐诗/poet.song.217000.json','["營營天壤間，孰不爲智使。", "有美山中君，獨與世俗異。", "一真不鑿若大愚，四體安然如止水。", "人皆喜君得佳扁，我於其間有餘議。", "一陰一陽分動靜，江河山嶽判流峙。", "造化而欲辭其勞，造化之功亦息矣。", "伊周孔孟心乎民，老氏莊蒙忘此世。", "使四君子俱恝然，萬古滔滔孰經濟。", "以拙而望巧，巧未及成拙。", "先至晦巧而爲拙，終焉多與巧相值。", "逸者自逸勞者勞，天之降材爾殊爾。", "君才足以應萬殊，袖手山林恐非計。", "願君畢力運天巧，却換軒名與張子。"]'),
('971b4196-931d-4618-9bd0-1ab0880b57e6','爲茅峰崇禧主人景架巖贊王肖巖所寫喜容','張榘','宋','宋诗','song-poetry','','[]','虬髯如雲眼如月，胸次毫端一泓雪。',64,'全唐诗/poet.song.217000.json','["虬髯如雲眼如月，胸次毫端一泓雪。", "政恐儒冠或誤身，尚友虛無老莊列。", "松陰泉影綠悠悠，此時此意如何說。", "三真跨鶴夜相從，長嘯一聲山谷裂。"]'),
('bb3c47ab-a50f-42b6-aaed-c79e4756b662','贈雲竹一老琴師歌','張榘','宋','宋诗','song-poetry','','[]','昌黎不作穎師已，千古風流隨逝水。',170,'全唐诗/poet.song.217000.json','["昌黎不作穎師已，千古風流隨逝水。", "大音祗在天壤間，雲竹翁能發其秘。", "明之爲侯王，幽之爲神鬼。", "悟翁一轉指頭禪，萬事泯然心耳廢。", "澗泉淅瀝走宮商，仙佩丁當分角徵。", "數聲急羽來秋空，夜半西風掠蛩砌。", "諸公不但知此音，真欲鈎深得其藝。", "大篇小什分珠璣，往往不惜兼金餽。", "吾聞南風之歌下舜廊，四海熙熙樂平治。", "願翁持此天上頭，一鼓解民慍，再鼓阜民財，勿作區區自豐計。"]'),
('c7580f4c-27ac-416a-b467-2fe04ad283cd','題錢則父凜對軒軒有老檜奇甚','張榘','宋','宋诗','song-poetry','','[]','老紅落盡蒼苔院，萬物隨時自流轉。',64,'全唐诗/poet.song.217000.json','["老紅落盡蒼苔院，萬物隨時自流轉。", "蒼然古檜夜窗前，獨抱寒姿聳孤榦。", "幽人丈室空無埃，風聲月影共徘徊。", "樹兮人兮兩清絕，不然君肯居此哉。"]'),
('29d87ca3-06fe-4162-9b07-854ced80f4ae','題金淵綠凈亭','張榘','宋','宋诗','song-poetry','','[]','憑高四望天沉沉，平蕪遠樹橫夕陰。',64,'全唐诗/poet.song.217000.json','["憑高四望天沉沉，平蕪遠樹橫夕陰。", "碧雲吐吞獻奇象，迺知造物得我心。", "漁舟兩兩疊烟棹，白鳥出沒滄波深。", "悠然呼酒納幽致，須臾寒月照古琴。"]'),
('bf9d6bfa-49ba-4b0a-8657-7c69199490f6','第一峰詩  其一','張榘','宋','宋诗','song-poetry','','[]','穿雲踏月登茅嶺，一陣西風吹客衣。',70,'全唐诗/poet.song.217000.json','["穿雲踏月登茅嶺，一陣西風吹客衣。", "松儼立兮如伏，山週迴兮若幃。", "竹泉清可鑒，苔石坐忘歸。", "鶴唳空靄，猿啼翠微。", "白露下，碧烟飛。", "適意，忘機。", "歔，欷。"]'),
('604f6c89-c53a-4c8d-9222-93d3a6473b9e','第一峰詩  其二','張榘','宋','宋诗','song-poetry','','[]','凄，清。',70,'全唐诗/poet.song.217000.json','["凄，清。", "露重，月明。", "紗帽濕，裌衣輕。", "路險僕倦，石危馬驚。", "近市火數點，出林鍾一聲。", "客子征鞍暫解，仙家雲關未扃。", "濁酒三杯投倦榻，夢回畫被寫吟情。"]'),
('346de499-a2fd-41b6-beb5-24ca19f02d1d','雪後呈邵堯章權尉','張榘','宋','宋诗','song-poetry','','[]','刮地風成陣，漫空雪作團。',48,'全唐诗/poet.song.217000.json','["刮地風成陣，漫空雪作團。", "侵陵詩骨瘦，開拓酒腸寬。", "入竹寒聲細，緘梅冷艷乾。", "長官何太喜，農事正相干。"]'),
('e1980d86-0c6a-46f0-abf3-df6da31dd0b7','半年','張榘','宋','宋诗','song-poetry','','[]','半年留鶴邑，歲晚倦重游。',48,'全唐诗/poet.song.217000.json','["半年留鶴邑，歲晚倦重游。", "雪柳带春意，煙蕪生暮愁。", "怕看新鳳歷，忍拂舊貂裘。", "莫道知心少，相親有白鷗。"]'),
('2802b3b2-0371-4a4d-bcfa-457cfbf68c77','華亭道間','張榘','宋','宋诗','song-poetry','','[]','移船過九曲，滿袖貯西風。',48,'全唐诗/poet.song.217000.json','["移船過九曲，滿袖貯西風。", "木落山容老，荷枯水面空。", "客懷詩句裏，時事酒杯中。", "莫聽雲間鶴，寧呼天外鴻。"]'),
('a1bfc453-e63a-4f91-afdd-d538d25bf2c8','題雲間皎上人扃綠軒','張榘','宋','宋诗','song-poetry','','[]','叢竹傍幽亭，蕭然一畫屏。',48,'全唐诗/poet.song.217000.json','["叢竹傍幽亭，蕭然一畫屏。", "色欺春酒碧，光映夜燈青。", "雨葉供香潤，風枝摇夢醒。", "却嫌千畝闊，浩渺綠難扃。"]'),
('317c9e30-be31-4b0c-9ac5-852e94256759','題黄巖黄山樓','張榘','宋','宋诗','song-poetry','','[]','樓俯澄江碧，山宜四面觀。',48,'全唐诗/poet.song.217000.json','["樓俯澄江碧，山宜四面觀。", "壓波橋影闊，带雨櫓聲寒。", "客夢因詩醒，歸心得酒寬。", "虛懷納幽致，濕翠撲欄干。"]'),
('23c05c68-04ad-4fae-8004-81ebe559b7fc','相公新創雲山觀於州治之東詩以頌之','張榘','宋','宋诗','song-poetry','','[]','華榱勝概實相兼，却笑滕王詫棟簾。',64,'全唐诗/poet.song.217000.json','["華榱勝概實相兼，却笑滕王詫棟簾。", "海內一雲高出岫，江南列嶂杳平簷。", "作霖錫命宜爰立，維石興歌正具瞻。", "寰宇固應同德宇，共期羹鼎試梅鹽。"]'),
('8a2da495-1bea-4aef-b2f6-628a57094303','帝城  其一','張榘','宋','宋诗','song-poetry','','[]','帝城那得見秋容，秋在三吳澤國中。',64,'全唐诗/poet.song.217000.json','["帝城那得見秋容，秋在三吳澤國中。", "蘆未著霜花已白，蓼宜近水影偏紅。", "一行落雁低南浦，萬點棲鴉起北風。", "安得畫師模此景，釣魚磯上著詩翁。"]'),
('0b62484d-8fc5-412d-8f07-cbdcbce8eebc','帝城  其二','張榘','宋','宋诗','song-poetry','','[]','半年再作華亭客，每喜輕帆得順風。',64,'全唐诗/poet.song.217000.json','["半年再作華亭客，每喜輕帆得順風。", "白水涵秋千頃浄，清霜粲曉萬山空。", "蹔時放浪如塵外，憶昨經過似夢中。", "濁酒三盃眠未熟，不能平處枕邊鴻。"]'),
('7df32f78-39a5-48ac-af19-5ab1c4a171b2','次韻金陵趙民曹水閣即事','張榘','宋','宋诗','song-poetry','','[]','尚想溪亭跨鴨頭，市囂到曉不曾休。',64,'全唐诗/poet.song.217000.json','["尚想溪亭跨鴨頭，市囂到曉不曾休。", "角聲吹斷老梅月，橋影壓翻寒葦秋。", "三語固知非昔比，十年不到使人愁。", "老來著脚茆峯下，相望何殊風馬牛。"]'),
('f10426df-d641-461b-98c1-1c5b657a4b85','再用韻呈相公','張榘','宋','宋诗','song-poetry','','[]','等囿乾坤造化中，此花珍重殿春紅。',64,'全唐诗/poet.song.217000.json','["等囿乾坤造化中，此花珍重殿春紅。", "矜持不受荼䕷月，披拂正須楊柳風。", "三詠品題真入妙，獨慚屬和未能工。", "廳前舊本今應在，何必移根江以東。"]'),
('562d3f98-51d3-4a28-9f75-ba32d2161365','和澄齋劉制幹過蕪湖渭陽宅有感韻','張榘','宋','宋诗','song-poetry','','[]','興言陟屺駐征艎，丘水依然亦故鄉。',64,'全唐诗/poet.song.217000.json','["興言陟屺駐征艎，丘水依然亦故鄉。", "萱草夢寒詩思遠，梅花月冷角聲長。", "暫辭小隠從三聘，况值清時已一陽。", "朝籍漸通恩數洽，會看梧檟發幽光。"]'),
('5351af8f-ab7c-419b-93a8-6e06e56dfa0b','留別耘業林逢吉飯牛翁鄭簡子','張榘','宋','宋诗','song-poetry','','[]','天台山下兩詩仙，剪霧裁冰五十年。',64,'全唐诗/poet.song.217000.json','["天台山下兩詩仙，剪霧裁冰五十年。", "耘業三間千古意，飯牛數集幾人傳。", "半江明月曾同賦，一段清風豈偶然。", "匹馬衝寒西驛路，碧雲苒苒思綿綿。"]'),
('29a12b28-10b0-4551-be2b-c8f8dd8c77d8','奉和魏提幹','張榘','宋','宋诗','song-poetry','','[]','騎鶴樓前奏宓琴，朅來又作海山吟。',64,'全唐诗/poet.song.217000.json','["騎鶴樓前奏宓琴，朅來又作海山吟。", "碧雲不隔鄉關夢，白髮能灰客子心。", "愧我抗塵徒走俗，羨君博古更通今。", "新詩清響傳空谷，擊節長歌到夜深。"]'),
('cce0150e-d5c8-47fc-9852-d0e9efbecda3','登蘇臺用袁憲韻贈兩趙提幹','張榘','宋','宋诗','song-poetry','','[]','勝賞多從暇日違，眼中朋友欲星稀。',64,'全唐诗/poet.song.217000.json','["勝賞多從暇日違，眼中朋友欲星稀。", "退休不復思三顧，能賦猶堪廣七依。", "遊鹿臺前空逝水，栖烏曲裏只斜暉。", "書生懷古真癡絕，看盡閑雲入棟飛。"]'),
('69ffb50a-1be0-4583-87c2-6c1036af0f29','窗上','張榘','宋','宋诗','song-poetry','','[]','窗上月朦朧，香芸鼻觀通。',24,'全唐诗/poet.song.217000.json','["窗上月朦朧，香芸鼻觀通。", "了無梅竹影，猛省在舟中。"]'),
('f8db72bb-a7f7-4a7d-adea-a76a957d5b75','題啄蜂雀井團雀二圖  其一','張榘','宋','宋诗','song-poetry','','[]','游蜂從何來，饑雀巧相遇。',24,'全唐诗/poet.song.217000.json','["游蜂從何來，饑雀巧相遇。", "誰其釋紛拏，放汝採花去。"]'),
('0c6d5cb1-3f86-4eb3-9d0c-2677247c5e73','題啄蜂雀井團雀二圖  其二','張榘','宋','宋诗','song-poetry','','[]','日暮投荒榛，吻利腹良餒。',24,'全唐诗/poet.song.217000.json','["日暮投荒榛，吻利腹良餒。", "爾竟何所爭，固結不可解。"]'),
('e6e50cff-52d0-4cf2-97ed-f460319caeb9','雁聲','張榘','宋','宋诗','song-poetry','','[]','雁聲恰值到江東，霜影空濛落晚篷。',32,'全唐诗/poet.song.217000.json','["雁聲恰值到江東，霜影空濛落晚篷。", "寒著蘆花禁不得，一層晴雪亂西風。"]'),
('5a983b88-39a6-498a-b065-2c11d9ddb264','春吟四絕  其一','張榘','宋','宋诗','song-poetry','','[]','岸草不知緣底綠，山花試問爲誰紅。',32,'全唐诗/poet.song.217000.json','["岸草不知緣底綠，山花試問爲誰紅。", "元造本來惟寂寞，年年多事是春風。"]'),
('a400005f-1cbc-44e3-b54a-90c770916730','春吟四絕  其二','張榘','宋','宋诗','song-poetry','','[]','沙渚清泠蒲葉水，野亭和暖杏花風。',32,'全唐诗/poet.song.217000.json','["沙渚清泠蒲葉水，野亭和暖杏花風。", "此中佳趣無人會，牛背斜陽卧牧童。"]'),
('a733517a-888b-4d03-890f-b68b26df3222','春吟四絕  其三','張榘','宋','宋诗','song-poetry','','[]','花露半乾紅入戶，竹風微動綠侵床。',32,'全唐诗/poet.song.217000.json','["花露半乾紅入戶，竹風微動綠侵床。", "翠屏殘夢不知處，幽鳥數聲春日長。"]'),
('67b5316c-b3e0-485c-b84a-46eb50c8852f','春吟四絕  其四','張榘','宋','宋诗','song-poetry','','[]','香鼎灰寒午夢回，閒情誰與夢徘徊。',32,'全唐诗/poet.song.217000.json','["香鼎灰寒午夢回，閒情誰與夢徘徊。", "杖藜信步穿幽徑，一陣野芳何處來。"]'),
('e591d344-9c0c-4ec9-81b8-3b458d5e1189','送賓書記自揚歸吳門','張榘','宋','宋诗','song-poetry','','[]','一葉黄蘆渡渺茫，誤隨野鶴上維揚。',32,'全唐诗/poet.song.217000.json','["一葉黄蘆渡渺茫，誤隨野鶴上維揚。", "角聲吹斷梅花夢，依舊楓灣半葉霜。"]'),
('6f69c0ff-7a41-4b9c-90e1-7c97b967c285','聞杜鵑','張榘','宋','宋诗','song-poetry','','[]','流落江南帝魄癡，年年啼到綠陰肥。',32,'全唐诗/poet.song.217000.json','["流落江南帝魄癡，年年啼到綠陰肥。", "蜀山邈在青天外，只勸人歸不自歸。"]'),
('b85eb649-c23f-423b-bd4a-98181fe8dc64','勸農二絕  其一','張榘','宋','宋诗','song-poetry','','[]','善端天賦本無殊，力穡之餘好讀書。',32,'全唐诗/poet.song.217000.json','["善端天賦本無殊，力穡之餘好讀書。", "莫訝勸農因勸學，須知公相起犂鋤。"]'),
('460021e3-cda2-42a3-b6ef-171d1fe70a4b','勸農二絕  其二','張榘','宋','宋诗','song-poetry','','[]','長官誨汝亦諄諄，須信民生總在勤。',32,'全唐诗/poet.song.217000.json','["長官誨汝亦諄諄，須信民生總在勤。", "試誦殷盤豳七月，詩書即是勸農文。"]'),
('42dd5c5b-2a52-48d2-916a-31c98f4e6c75','題包虎  其一','張榘','宋','宋诗','song-poetry','','[]','正眎眈眈怒作威，西風摇毒上牙鬚。',32,'全唐诗/poet.song.217000.json','["正眎眈眈怒作威，西風摇毒上牙鬚。", "山翁祗作丹青看，馮婦從教自下車。"]'),
('a7d6cfcb-8a7a-4bc3-a880-6a58d44d771a','題包虎  其二','張榘','宋','宋诗','song-poetry','','[]','日日紅林飽血腴，尚將餘力咬枯株。',32,'全唐诗/poet.song.217000.json','["日日紅林飽血腴，尚將餘力咬枯株。", "高亭素壁黄昏後，疑有悲風落坐隅。"]'),
('e7268f95-e8de-47e6-8465-cbcb116008ca','咏十月桃','張榘','宋','宋诗','song-poetry','','[]','十月桃開三四枝，凄凉時候見芳菲。',32,'全唐诗/poet.song.217000.json','["十月桃開三四枝，凄凉時候見芳菲。", "小紅不著黄花蝶，一樹春風怨落暉。"]'),
('b841e30b-2cf3-4ff6-9ea5-1b037f51adc9','騎鶴仙','張榘','宋','宋诗','song-poetry','','[]','擁麾猶願富腰錢，千古相傳跨鶴仙。',32,'全唐诗/poet.song.217000.json','["擁麾猶願富腰錢，千古相傳跨鶴仙。", "莫笑昔人空覬望，後來人欲更熏天。"]'),
('cbffed51-0cc2-431d-8f08-722515f09b8c','題稅軒新築送青亭四首  其一','張榘','宋','宋诗','song-poetry','','[]','花木中間著小亭，簷虛不礙兩峯青。',32,'全唐诗/poet.song.217000.json','["花木中間著小亭，簷虛不礙兩峯青。", "數聲啼鳥閙中過，不似家山子細聽。"]'),
('6c76b4d4-1cc0-4a93-a200-889344298445','題稅軒新築送青亭四首  其二','張榘','宋','宋诗','song-poetry','','[]','日抱吟情到此亭，捲簾孤坐看雲生。',32,'全唐诗/poet.song.217000.json','["日抱吟情到此亭，捲簾孤坐看雲生。", "詩懷恰與雲相似，一點悠然度太清。"]'),
('66305d59-3d45-4b32-bea4-fccfec1e92ee','題稅軒新築送青亭四首  其三','張榘','宋','宋诗','song-poetry','','[]','白雲盡處青山小，紅雨飛時綠樹新。',32,'全唐诗/poet.song.217000.json','["白雲盡處青山小，紅雨飛時綠樹新。", "佳致仗誰同管領，野禽啁哳話深春。"]'),
('bb9eedea-a267-4d12-a81c-37f1b0e8c316','題稅軒新築送青亭四首  其四','張榘','宋','宋诗','song-poetry','','[]','日移花影上疎簾，香鼎燒殘逐旋添。',32,'全唐诗/poet.song.217000.json','["日移花影上疎簾，香鼎燒殘逐旋添。", "春事已隨詩入夢，一庭芳草綠纖纖。"]'),
('0041fc2d-7063-45a5-aff1-da435d6e64d4','題趙子固水仙圖','張榘','宋','宋诗','song-poetry','','[]','紫府川妃夜宴還，玉盤金椀落人間。',32,'全唐诗/poet.song.217000.json','["紫府川妃夜宴還，玉盤金椀落人間。", "香肌不受緇塵污，依約風前響珮環。"]'),
('c8346294-ec2c-44b1-be4f-aa984af4d895','秦淮','張榘','宋','宋诗','song-poetry','','[]','往在秦淮問六朝，江樓只有女吹簫。',32,'全唐诗/poet.song.217000.json','["往在秦淮問六朝，江樓只有女吹簫。", "昭陽太極無行路，歲歲鵝黄上柳條。"]'),
('cfa3e062-61df-4a6c-bf21-cd1a8e8896f4','至後二日登狼峰','張榘','宋','宋诗','song-poetry','','[]','江流不盡天連地，山意無窮春復秋。',32,'全唐诗/poet.song.217000.json','["江流不盡天連地，山意無窮春復秋。", "多少詩人無分到，我來三月得重遊。"]'),
('e1c8cf15-ab7c-4ade-b40a-af112f4ad031','聞春禽','張榘','宋','宋诗','song-poetry','','[]','萬疊雲山擁翠屏，筍輿終日面山行。',32,'全唐诗/poet.song.217000.json','["萬疊雲山擁翠屏，筍輿終日面山行。", "幽禽上下好音語，到底不知誰命名。"]'),
('bbe45028-7215-49be-b3a7-ffdc6215084a','雨花臺','張榘','宋','宋诗','song-poetry','','[]','莫說南朝勝概繁，祗今近郭已江村。',64,'全唐诗/poet.song.217000.json','["莫說南朝勝概繁，祗今近郭已江村。", "臺荒浪紀曼花墜，事往空餘古意存。", "甌缺正緣輕納景，鼎分誰謂不如孫。", "滔滔千載興亡恨，盡付凭欄對月樽。"]'),
('84090110-bdb9-4914-91ff-15c724b09ef8','送戴式之自越遊江西','張榘','宋','宋诗','song-poetry','','[]','石屏峰下孤吟客，吟到頭童更苦吟。',64,'全唐诗/poet.song.217000.json','["石屏峰下孤吟客，吟到頭童更苦吟。", "四海江山多識面，百年人物半知心。", "詩于唐米偶先後，較以杜韋無古今。", "容易相逢容易別，不堪回首白雲深。"]'),
('281becdd-ef7a-463c-a1b5-b9549832732b','樓中即事','張榘','宋','宋诗','song-poetry','','[]','園亭已覺晴簷暖，樓上東風尚峭寒。',64,'全唐诗/poet.song.217000.json','["園亭已覺晴簷暖，樓上東風尚峭寒。", "燕壘泥乾芹菜老，蜜房香滿杏花殘。", "詩懷正似曉山好，酒量不如春水寬。", "陌上兒童應笑我，黄昏猶自倚蘭干。"]'),
('9db05e8c-8169-4759-901f-873bbe6ff29d','春盡出郊','張榘','宋','宋诗','song-poetry','','[]','薔薇花落筍斑斑，醖釀清和數日間。',32,'全唐诗/poet.song.217000.json','["薔薇花落筍斑斑，醖釀清和數日間。", "杜宇不知春去了，又啼斜日過前山。"]'),
('151234fd-7494-46e7-8f22-47c5dc3a90ca','句','韓履常','宋','宋诗','song-poetry','','[]','李門弟子饒門友，渭水年齡泗水心。',16,'全唐诗/poet.song.217000.json','["李門弟子饒門友，渭水年齡泗水心。"]'),
('2405d3fa-74a7-4bb2-8301-fa16d90a2d96','曹將軍','安如山','宋','宋诗','song-poetry','','[]','將軍精悍姿，齒齒碎鐵石。',288,'全唐诗/poet.song.217000.json','["將軍精悍姿，齒齒碎鐵石。", "在昔童稚中，但聞飽經術。", "縱橫騁柔翰，丹雘間金碧。", "有司塞明詔，敝邑屈詞伯。", "芹香春水生，冠玉侍重席。", "脫略章句陋，搜抉窮理窟。", "未及文化成，其如王土窄。", "丈夫報主願，豈必蒙清秩。", "蒼然請去位，滿面秋栗烈。", "糾合熊虎羣，旌旆揚廣陌。", "正當摩厲閒，一鼓拔勍敵。", "屯兵沔水源，千里斧截截。", "浩蕩排煙旻，西極安屼嵲。", "奈何國無人，腐儒秉旄鉞。", "賞予入私門，金湯授盜賊。", "公時奮臂爭，反遭獻玉刖。", "三軍視馬首，痛哭下天壁。", "功成坐齟齬，憤怒鬚插戟。", "中宵拔劍起，肅肅整勁翮。", "吐氣風雲生，搴旗陷堅列。", "貫穿死生地，蹀血天地黑。", "勢雖衆寡懸，形未雌雄决。", "路窮斷首尾，衆盡乃手格。", "豈知龍虎逝，黯淡山川色。"]'),
('7276836a-18d8-4810-91b1-a430dd36bab1','下瞿塘','安如山','宋','宋诗','song-poetry','','[]','去去如奔馬，來來無盡船。',24,'全唐诗/poet.song.217000.json','["去去如奔馬，來來無盡船。", "人心似江水，日夜向吳天。"]'),
('6c1b166e-05d2-446e-a470-de43e559640d','贄見洪師','黄鑄','宋','宋诗','song-poetry','','[]','風煙入暝少人行，獨鶴來依帝子城。',32,'全唐诗/poet.song.217000.json','["風煙入暝少人行，獨鶴來依帝子城。", "華表柱頭霜月冷，清宵有夢到鐘聲。"]'),
('efc62a5f-54c5-4f2d-bc74-78468b3cbd10','題沖佑觀','謝塈','宋','宋诗','song-poetry','','[]','一線天回得順流，幾家脩竹滿巖幽。',64,'全唐诗/poet.song.217000.json','["一線天回得順流，幾家脩竹滿巖幽。", "轉頭已失來時路，過眼猶憐水上舟。", "仙事渺茫姑勿論，客情蕭散故遲留。", "試尋懷玉山人傳，更有承平好識不。"]'),
('83a6dc35-9356-4d7f-9e9b-2931f095c0a4','餞周東巖之石門訪汾陽氏并呈友人','程炎子','宋','宋诗','song-poetry','','[]','漫浪江湖脚，周遊到石門。',48,'全唐诗/poet.song.217000.json','["漫浪江湖脚，周遊到石門。", "能迎徐孺子，知有令公孫。", "話雨燈輝座，酬春酒灩樽。", "况逢朋友在，一見必溫存。"]'),
('d86a4293-c3c2-4f51-a00e-90a1390a57b5','四安舟中','程炎子','宋','宋诗','song-poetry','','[]','多行三兩日，猶在四安舟。',48,'全唐诗/poet.song.217000.json','["多行三兩日，猶在四安舟。", "天正當寒夜，人偏作遠遊。", "風高雲葉動，江闊浪花浮。", "會得幽閒趣，唯應是白鷗。"]'),
('34c94358-b8f8-4389-bcf6-94a0ba83f5c7','山中雜詩  其一','程炎子','宋','宋诗','song-poetry','','[]','側耳橋邊聽，聲聲在翠微。',48,'全唐诗/poet.song.217000.json','["側耳橋邊聽，聲聲在翠微。", "自甘留此坐，何苦勸人歸。", "院悄驚春晝，山空戀夕暉。", "得如鷗與鷺，對我欲忘機。"]'),
('93e77027-5e44-4097-9394-70346ce85cb0','山中雜詩  其二','程炎子','宋','宋诗','song-poetry','','[]','崑崙初鑿破，大巧奪天真。',48,'全唐诗/poet.song.217000.json','["崑崙初鑿破，大巧奪天真。", "竹鎖三更月，桃酣幾度春。", "山空聞鶴唳，溪遠卜鷗鄰。", "爲拂留題石，松摇露滴身。"]'),
('db3f6386-0e08-4473-a4a0-2925eeb99359','登高感興','程炎子','宋','宋诗','song-poetry','','[]','破帽西風裏，龍山憶孟嘉。',48,'全唐诗/poet.song.217000.json','["破帽西風裏，龍山憶孟嘉。", "白衣誰送酒，黄菊自開花。", "塞遠書傳鴈，天昏墨點鴉。", "憑高窮北望，何處是中華。"]'),
('d4fd9788-6fa6-42b6-aa44-09c1b0f4806c','次郡太守劉朔齋秋晚謁謝脁亭小飲三首  其一','程炎子','宋','宋诗','song-poetry','','[]','鞭摇五馬踏沙隄，秋晚除書下紫泥。',64,'全唐诗/poet.song.217000.json','["鞭摇五馬踏沙隄，秋晚除書下紫泥。", "蘚壁篆碑猿捧硯，松關吟句鶴分題。", "裴休故宅今爲寺，謝脁閑官昔仕齊。", "太守宴歸賓客從，數聲山鳥日平西。"]'),
('9efe43b3-ebf6-42a4-9afc-edc44bf813f3','次郡太守劉朔齋秋晚謁謝脁亭小飲三首  其二','程炎子','宋','宋诗','song-poetry','','[]','一禱心香雨便晴，萬家和氣釀成醺。',64,'全唐诗/poet.song.217000.json','["一禱心香雨便晴，萬家和氣釀成醺。", "時方入到昭亭路，風已吹開疊嶂雲。", "話向禪中參冷淡，心於靜處息紛紜。", "麥畦邂逅長沮語。", "想徹黄堂亦喜聞。"]'),
('147f2bd5-e834-4a3e-9f94-5a843f830380','次郡太守劉朔齋秋晚謁謝脁亭小飲三首  其三','程炎子','宋','宋诗','song-poetry','','[]','掀髯一笑倚危闌，面面青山不厭看。',64,'全唐诗/poet.song.217000.json','["掀髯一笑倚危闌，面面青山不厭看。", "霜染丹楓秋色絢，日烘紫菊露痕乾。", "鵲爐火慢熏龍腦，蟹眼湯新瀹鳳團。", "回簇絳紗城郭晚，老梅吹角鴈拖寒。"]'),
('41ce0056-b3f9-4858-8efb-a8fe9d5bb96e','題如庵','程炎子','宋','宋诗','song-poetry','','[]','脫略機關一散人，清於蘭畹抱幽馨。',64,'全唐诗/poet.song.217000.json','["脫略機關一散人，清於蘭畹抱幽馨。", "撫松細嚼淵明句，瀹茗閑箋陸羽經。", "春對風光秋對月，曉觀雲氣夜觀星。", "世間局面多翻覆，著數雖高亦懶聽。"]'),
('c8a120d0-ef8d-4024-b8cf-7a67c3e20615','暮春','程炎子','宋','宋诗','song-poetry','','[]','花飛簷語恰經旬，强半韶華斷送頻。',64,'全唐诗/poet.song.217000.json','["花飛簷語恰經旬，强半韶華斷送頻。", "三月便晴三十日，一年只有一分春。", "酒甘不飲心如醉，詩苦耽吟味越真。", "欹枕北窗清夢覺，落紅啼鳥伴幽人。"]'),
('f4461b73-114e-4307-a471-f50bd94a76ff','古梅','程炎子','宋','宋诗','song-poetry','','[]','水邊山脚友漁樵，梅欲窺人故故招。',64,'全唐诗/poet.song.217000.json','["水邊山脚友漁樵，梅欲窺人故故招。", "樹剝龍鱗黏碧蘚，枝翹鶴膝糝紅椒。", "詩如老杜吟東閣，夢約逋仙過斷橋。", "好待月窗清影瘦，傳他神子上生綃。"]'),
('40415956-9314-447c-b5cc-5065693941c0','蠟梅','程炎子','宋','宋诗','song-poetry','','[]','畫樓人醉燭高燒，滴在寒枝蠟未消。',64,'全唐诗/poet.song.217000.json','["畫樓人醉燭高燒，滴在寒枝蠟未消。", "蘂撇打鶑金彈滑，花懸驅雀綵鈴摇。", "歌兒戲拍供檀板，妝女輕裁貼翠翹。", "酒揭黄封詩嚼淡，時勻乳蜜過山腰。"]'),
('b9e4a74d-2a72-40f5-b834-7de150cf792b','水樂洞','程炎子','宋','宋诗','song-poetry','','[]','南山水樂洞，窈窈白雲深。',24,'全唐诗/poet.song.217000.json','["南山水樂洞，窈窈白雲深。", "滿耳笙歌者，誰能一洗心。"]'),
('9b10b984-65e3-4add-af21-b5b306cfd535','歸日','程炎子','宋','宋诗','song-poetry','','[]','去時雪學楊花舞，歸日花如雪樣飛。',32,'全唐诗/poet.song.217000.json','["去時雪學楊花舞，歸日花如雪樣飛。", "何事楊花并雪絮，送人西邁送人歸。"]'),
('a45770d1-394b-4a26-9b1f-b21f14ec0f24','登新安五嶺','程炎子','宋','宋诗','song-poetry','','[]','五嶺崎嶇一步難，白雲兼霧羃中間。',32,'全唐诗/poet.song.217000.json','["五嶺崎嶇一步難，白雲兼霧羃中間。", "行人莫道山多險，更有人心險似山。"]'),
('aa889ad0-3386-44fe-8b90-349a1a94517c','天台陳山夫寄別用韻','程炎子','宋','宋诗','song-poetry','','[]','斷烟荒草共幽幽，斜雨拋絲織晚愁。',32,'全唐诗/poet.song.217000.json','["斷烟荒草共幽幽，斜雨拋絲織晚愁。", "鷗鳥似知人乍別，飛來飛去渡船頭。"]'),
('8fd6b6c2-d370-4d42-91cb-08d032803e15','和趙守獨遊水西寺','程炎子','宋','宋诗','song-poetry','','[]','吟月歌風酒力微，獨尋幽壑叩禪扉。',64,'全唐诗/poet.song.217000.json','["吟月歌風酒力微，獨尋幽壑叩禪扉。", "泊隄小艇迎人渡，入水閑雲伴鶴飛。", "梅落半含冰雪思，石寒長覆薜蘿衣。", "水西景物還如舊，恨不相從倒載歸。"]'),
('d8a2570e-d13c-4ad0-b864-f781ec1af4d3','謝張芸窗','劉啟之','宋','宋诗','song-poetry','','[]','夜深檛鼓醉紅裙，半世侯門熟稔聞。',64,'全唐诗/poet.song.217000.json','["夜深檛鼓醉紅裙，半世侯門熟稔聞。", "自是東籬窺宋玉，非關司馬挑文君。", "蒼頭誤送香羅帕，簧舌翻成貝錦文。", "幸頼老成持定力，一帆安穩過溪雲。"]'),
('3723b386-13ab-4c01-a51c-bf69ea3a0d3a','淳祐丙午講禮記畢錫宴祕書省賜侍讀少師鄭清之以下','宋理宗','宋','宋诗','song-poetry','','[]','鰲極開先已降衷，上天下澤禮居中。',64,'全唐诗/poet.song.217000.json','["鰲極開先已降衷，上天下澤禮居中。", "三才義理維持力，萬世綱常建立功。", "孔聖法言多纂輯，漢儒師學共修崇。", "經帷講徹資羣彥，克己工夫在廣充。"]'),
('0f4689ad-8fe4-4263-a09f-43a6c0341f6b','賜答鄭宷','宋理宗','宋','宋诗','song-poetry','','[]','秋思太華峯頭雪，晴憶巫山一片雲。',32,'全唐诗/poet.song.217000.json','["秋思太華峯頭雪，晴憶巫山一片雲。", "去國歸來猶未得，詩篇遥贈北山君。"]'),
('19fdd5f6-9e19-402b-9ba0-51e9f304bcc1','賜狀元文天祥以下','宋理宗','宋','宋诗','song-poetry','','[]','道久於心化未成，樂聞爾士對延英。',64,'全唐诗/poet.song.217000.json','["道久於心化未成，樂聞爾士對延英。", "誠惟不息斯文著，治豈多端在力行。", "華國以文由造理，事君務實勿沽名。", "得賢功用真無敵，能爲皇家立太平。"]'),
('d12b523e-9352-464b-9d1e-be0ebe0003b8','題趙葵墨梅','宋理宗','宋','宋诗','song-poetry','','[]','溪藤疏影勢千尋，筆補春工著意深。',32,'全唐诗/poet.song.217000.json','["溪藤疏影勢千尋，筆補春工著意深。", "止渴調羹歸妙手，誰知一片歲寒心。"]'),
('0075e46b-dbbb-4036-ba9c-07b3f5152e9c','重修復古殿紀事','宋理宗','宋','宋诗','song-poetry','','[]','烈祖謀詒燕，沖人命紹龜。',240,'全唐诗/poet.song.217000.json','["烈祖謀詒燕，沖人命紹龜。", "禁嚴瞻復古，締創想當時。", "鳳紀因多歷，翬飛欲寖隳。", "端居常念此，涼德恐羞之。", "勉輯炎興業，新還舜禹規。", "棟驤非玉瑱，樸斲僅塗茨。", "咫尺羹牆見，延洪典則貽。", "緬懷光宅舊，儼若煥章垂。", "聖志惟先定，鴻名寓有爲。", "風烟沈廟算，天日俯疇咨。", "屏翰環方召，言謨富禹夔。", "權綱歸總攬，制度永維持。", "養士翔鴛鷺，蒐兵振虎貔。", "宣王修政日，光武中興時。", "文治綏函夏，英威鬯遠夷。", "萬年丕顯績，三紀太平基。", "繼述慚非稱，規恢動慨思。", "肯堂心翼翼，景行日孜孜。", "載繹車攻雅，宜賡考室詩。", "告成書梗概，拜手緝蕪辭。"]'),
('66414c4b-aaf4-4ae5-92fb-b421f6f7c11b','昌化縣進嘉禾嘉粟賜賈丞相','宋理宗','宋','宋诗','song-poetry','','[]','一德交孚叶兩儀，嘉禾嘉粟獻珍奇。',64,'全唐诗/poet.song.217000.json','["一德交孚叶兩儀，嘉禾嘉粟獻珍奇。", "祥呈屬邑信非偶，瑞應明禋若有期。", "周紀唐封生秀穎，漢歌郊廟産靈芝。", "何如近在王畿內，慶典珍符萃一時。"]'),
('eb6b166f-d7a8-4eb8-b72e-c7f20e044ed5','批養性存心二說','宋理宗','宋','宋诗','song-poetry','','[]','方寸中涵一太虛，操存須用養工夫。',32,'全唐诗/poet.song.217000.json','["方寸中涵一太虛，操存須用養工夫。", "瑩然鏡浄無纖翳，一性融明萬理俱。"]'),
('49c9b505-63eb-4e9f-9884-7739e01b8636','筆占示林君奇','宋理宗','宋','宋诗','song-poetry','','[]','許負往昔矣，天綱今何之。',24,'全唐诗/poet.song.217000.json','["許負往昔矣，天綱今何之。", "誰知千載後，復遇林君奇。"]'),
('245354e0-91ec-4de4-9822-37fba2a9a4f7','瑞不爲祥','宋理宗','宋','宋诗','song-poetry','','[]','初是烈祖開炎圖，華夷一統同車書。',192,'全唐诗/poet.song.217000.json','["初是烈祖開炎圖，華夷一統同車書。", "人心愛戴無遠邇，親傳聖像繪成都。", "成都赤子尊君父，大廷重光奉祠宇。", "殿旁一木久已枯，俄發三芽當夏五。", "萬物榮枯知有時，枯楊況更能生稊。", "天胡此野大此瑞，祖宗垂佑從可知。", "吁嗟全蜀今非昔，玉壘金城久荆棘。", "幸今天道已好還，欲洗腥羶歸古益。", "矧茲廊廟古棟梁，肅雍顯相登明堂。", "岷峨萬里來獻瑞，願符景運答休祥。", "書言顛木有由蘗，天其永命復大業。", "中興肇開同一機，萬載重芳光史牒。"]'),
('40db0bfb-d548-43ca-8082-5df89a72d4e4','李璮歸國','宋理宗','宋','宋诗','song-poetry','','[]','力扶漢鼎頼元勳，泰道宏開萬象新。',64,'全唐诗/poet.song.217000.json','["力扶漢鼎頼元勳，泰道宏開萬象新。", "聲暨南郊方慕義，恩漸東海悉來臣。", "凱書已奏三邊捷，廟算全消萬里塵。", "坐致太平今日事，中興寶運喜環循。"]'),
('9cfe095e-155f-4763-b9c0-aa595f1f9d03','賜賈相','宋理宗','宋','宋诗','song-poetry','','[]','清明朝野遇清明，萬國歡心樂太平。',32,'全唐诗/poet.song.217000.json','["清明朝野遇清明，萬國歡心樂太平。", "樽俎優賢咨啟沃，載賡既醉詠盈成。"]'),
('a1cad617-1f29-42d6-9632-12c75655f07e','賜馬廷鸞四首  其一','宋理宗','宋','宋诗','song-poetry','','[]','天高地下禮由分，聖哲於焉秩糾紛。',64,'全唐诗/poet.song.217000.json','["天高地下禮由分，聖哲於焉秩糾紛。", "心法操存毋不敬，治功顯設在斯文。", "會通自可躋明聖，品節應知本儉勤。", "旃厦講磨資衆彥，精微盡處是尊聞。"]'),
('c9fe984d-9c27-425e-ac97-9d876ff5b0b3','賜馬廷鸞四首  其二','宋理宗','宋','宋诗','song-poetry','','[]','春秋萬古一權衡，筆削昭然揭日星。',64,'全唐诗/poet.song.217000.json','["春秋萬古一權衡，筆削昭然揭日星。", "道貫百王垂大法，義先五始定常經。", "是非褒貶寓深意，理亂安危燭未形。", "內夏外夷歸一統，燁然治象炳丹青。"]'),
('063d306a-b902-4026-b878-f5c2a5bbc836','賜馬廷鸞四首  其三','宋理宗','宋','宋诗','song-poetry','','[]','古掖摛文步武高，綾衾寓直焰蘭膏。',64,'全唐诗/poet.song.217000.json','["古掖摛文步武高，綾衾寓直焰蘭膏。", "當年宮錦飛雙鵠，今夕僊圖看巨鼇。", "詩賜玉堂蘇易簡，光摇蓮炬令狐綯。", "明時盛事今重見，爰製篇章示衮褒。"]'),
('8daec133-eeff-4665-bfe5-87da810bd604','賜馬廷鸞四首  其四','宋理宗','宋','宋诗','song-poetry','','[]','聖烈神謨肇我邦，鉅編詔後總宏綱。',64,'全唐诗/poet.song.217000.json','["聖烈神謨肇我邦，鉅編詔後總宏綱。", "立心廣大侔天地，行事明通邁帝王。", "訓與六經相表裏，法垂萬世愈巍煌。", "講帷可但資敷繹，夙夜惟知率舊章。"]'),
('755a3da4-83c8-496b-9305-eabed89e7f6f','賜鄭丞相','宋理宗','宋','宋诗','song-poetry','','[]','菲德承休帝命新，青陽闓動御昌辰。',64,'全唐诗/poet.song.217000.json','["菲德承休帝命新，青陽闓動御昌辰。", "慶貽虹渚嘉祥衍，春滿鼇山景色新。", "鎬燕頌思勤□□，靈韶協奏喜橫陳。", "在朝從此薰和氣，要使驩心萬姓均。"]'),
('26b5bc09-86fb-4d0c-9daa-69d9928c351c','聞喜宴詩賜狀元方逢辰','宋理宗','宋','宋诗','song-poetry','','[]','肆予臨御九賓興，藹藹盈庭俊乂升。',64,'全唐诗/poet.song.217000.json','["肆予臨御九賓興，藹藹盈庭俊乂升。", "喜頼讜言調八事，欲垂景運進三登。", "攄忠社稷惟名節，濟用邦家必器能。", "豐芑涵濡盛今日，勉思德意共欽承。"]'),
('3a9c0ef3-41dc-4bd1-8941-2aabeb810663','寧宗皇帝挽詞  其一','宋理宗','宋','宋诗','song-poetry','','[]','沖澹凝金汞，憂勤失寶丹。',48,'全唐诗/poet.song.217000.json','["沖澹凝金汞，憂勤失寶丹。", "講餘曦正午，班促漏方殘。", "濟野雲生暗，蒼梧日轉寒。", "列朝從藝祖，天闕會金鑾。"]'),
('57a4c47b-550d-4810-bb16-4dc516824c34','寧宗皇帝挽詞  其二','宋理宗','宋','宋诗','song-poetry','','[]','仙御賓空日，龍飛杳杳間。',48,'全唐诗/poet.song.217000.json','["仙御賓空日，龍飛杳杳間。", "五雲呈瑞綵，九虎敞重關。", "寶輦扶蒼鶴，雲韶擁玉班。", "千年棲佛地，今日覩天顔。"]'),
('8574334b-0321-469d-9a5f-78354112d1f4','題夏珪夜潮風景圖','宋理宗','宋','宋诗','song-poetry','','[]','定知玉兔十分圓，已作霜風九月寒。',32,'全唐诗/poet.song.217000.json','["定知玉兔十分圓，已作霜風九月寒。", "寄語重門休上鑰，夜潮留向月中看。"]'),
('e3813b3b-776f-4159-b893-23a392f2fa1a','孝梅里','宋理宗','宋','宋诗','song-poetry','','[]','南風六月吐梅花，奇絕西昌孝子家。',32,'全唐诗/poet.song.217000.json','["南風六月吐梅花，奇絕西昌孝子家。", "一點落英千古月，夜來啼殺後棲鴉。"]'),
('9503e992-f5fe-4e33-8715-fb41dbf3070a','偈頌','宋理宗','宋','宋诗','song-poetry','','[]','大暑流金石，寒風結凍雲。',24,'全唐诗/poet.song.217000.json','["大暑流金石，寒風結凍雲。", "梅花香度遠，自有一枝春。"]'),
('0daa660f-5999-4615-bd90-0570a3b9b46b','和靈隠長老頌','宋理宗','宋','宋诗','song-poetry','','[]','欲言心佛難分別，俱是精微無礙通。',32,'全唐诗/poet.song.217000.json','["欲言心佛難分別，俱是精微無礙通。", "跳出千重縛不住，天涯海角任西風。"]'),
('b6c38ced-9213-4429-991e-2dd518da9414','項龍歸省','宋理宗','宋','宋诗','song-poetry','','[]','清河正願得忠臣，豈覺辭官歸思匆。',64,'全唐诗/poet.song.217000.json','["清河正願得忠臣，豈覺辭官歸思匆。", "爲道思親心甚切，難留執手意奚窮。", "親斟御酒資行色，更敕雲臺寫範容。", "回到家鄉人問及，始知朕不負勳功。"]'),
('59f8b655-636d-4375-a3c9-0676a1a835c9','句  其一','宋理宗','宋','宋诗','song-poetry','','[]','天高地下禮居中。',8,'全唐诗/poet.song.217000.json','["天高地下禮居中。"]'),
('e923b6f4-90cc-4455-bf0a-69b913efc1fe','句  其二','宋理宗','宋','宋诗','song-poetry','','[]','芳意饒呈瑞，寒光助照人。',12,'全唐诗/poet.song.217000.json','["芳意饒呈瑞，寒光助照人。"]'),
('2d4c5f43-4ab5-4446-a7c8-d32a4b6ac9cb','妾薄命','左瀛','宋','宋诗','song-poetry','','[]','妾貌微微改，君恩漸漸疏。',48,'全唐诗/poet.song.217000.json','["妾貌微微改，君恩漸漸疏。", "本期爲匹鳥，深恐作前魚。", "却月無心畫，香雲信手梳。", "佳人多薄命，不必重欷歔。"]'),
('6ece6b76-55a4-45b5-a72d-2744e83a4712','絕句','趙希𩇕','宋','宋诗','song-poetry','','[]','手執黄庭上石臺，竹陰掃月徧蒼苔。',32,'全唐诗/poet.song.217000.json','["手執黄庭上石臺，竹陰掃月徧蒼苔。", "欲從此處即仙去，玉立清風待鶴來。"]'),
('26bb9c56-7fdd-40cb-8480-cfdbc2ae4059','絕命偈','趙希𩇕','宋','宋诗','song-poetry','','[]','六十二年皮袋，放下了無罣礙。',28,'全唐诗/poet.song.217000.json','["六十二年皮袋，放下了無罣礙。", "青天明月一輪，萬古逍遥自在。"]'),
('01007ad4-f444-46e1-bd36-755334e2e332','遊瑞象寺和杜夢麟韻','趙希𩇕','宋','宋诗','song-poetry','','[]','招提深僻好山重，濕翠陰森一徑松。',64,'全唐诗/poet.song.217000.json','["招提深僻好山重，濕翠陰森一徑松。", "夜靜鶴歸清夢繞，日高僧起碧雲封。", "晴分貝葉翻餘照，雨送鐘聲度遠峰。", "竹舍因逢三昧語，鳥啼花滿萬緣空。"]'),
('536065ad-0c5c-41dd-aa8d-0b88acab9a69','池州和同官詠梅花  其一','張道洽','宋','宋诗','song-poetry','','[]','朔風吹石裂，寒谷自春生。',48,'全唐诗/poet.song.217000.json','["朔風吹石裂，寒谷自春生。", "根老香全古，花疏格轉清。", "園林千樹禿，籬落一枝橫。", "佩芷兼懷玉，悠然見此兄。"]'),
('bba8638f-ca61-4b9f-85d5-74c649c8645e','池州和同官詠梅花  其二','張道洽','宋','宋诗','song-poetry','','[]','苔封鶴膝枝，流水繞疏籬。',48,'全唐诗/poet.song.217000.json','["苔封鶴膝枝，流水繞疏籬。", "一白雪相似，獨清春不知。", "風流無俗韻，恬澹出天姿。", "霜月娟娟夜，吾今見所思。"]'),
('f67a12a5-77d8-4c5d-9e27-572d6f777987','池州和同官詠梅花  其三','張道洽','宋','宋诗','song-poetry','','[]','半枯頑鐵石，特地數花生。',48,'全唐诗/poet.song.217000.json','["半枯頑鐵石，特地數花生。", "迥立風塵表，長含水月清。", "屋頭寒嶺瘦，門外小溪橫。", "萬里今爲客，相看如弟兄。"]'),
('1f217f56-b990-48bd-bdd0-d73d071e5663','池州和同官詠梅花  其四','張道洽','宋','宋诗','song-poetry','','[]','疎疎竹外枝，短短水邊籬。',48,'全唐诗/poet.song.217000.json','["疎疎竹外枝，短短水邊籬。", "南雪若相避，東風殊不知。", "蘭荃皆弱植，桃杏總凡姿。", "坐歎逋仙遠，清宵費夢思。"]'),
('1408349e-f90e-4106-a5d9-c4035569c394','池州和同官詠梅花  其五','張道洽','宋','宋诗','song-poetry','','[]','不带吟詩癖，緣何太瘦生。',48,'全唐诗/poet.song.217000.json','["不带吟詩癖，緣何太瘦生。", "肌膚姑射白，風骨伯夷清。", "格外宮粧別，天然畫軸橫。", "涪翁太多可，喚作水仙兄。"]'),
('95ee8657-d1f9-49f0-92ba-203b15bf44b9','池州和同官詠梅花  其六','張道洽','宋','宋诗','song-poetry','','[]','蒼虬百歲枝，殘雪數家籬。',48,'全唐诗/poet.song.217000.json','["蒼虬百歲枝，殘雪數家籬。", "點俗那能染，孤芳只自知。", "肯回桃李面，要是雪霜姿。", "不見紫芝久，悠悠使我思。"]'),
('f9a5e66a-469b-4c60-9e6e-22848d2f9026','池州和同官詠梅花  其七','張道洽','宋','宋诗','song-poetry','','[]','不與百花競，春風驀地生。',48,'全唐诗/poet.song.217000.json','["不與百花競，春風驀地生。", "故將天下白，獨向雪中清。", "我輩詩仍要，誰家笛自橫。", "歲寒堪共老，髯叟十年兄。"]'),
('f0cfa02e-3681-4ee2-9bf3-c32929bd693d','池州和同官詠梅花  其八','張道洽','宋','宋诗','song-poetry','','[]','何處出斜枝，茅簷自竹籬。',48,'全唐诗/poet.song.217000.json','["何處出斜枝，茅簷自竹籬。", "首回春一盼，最與月相知。", "嚴冷冰霜面，清癯山澤姿。", "幾番將鶴去，倚樹說相思。"]'),
('6766bb80-9515-4982-9f7d-7d3991842eb5','池州和同官詠梅花  其九','張道洽','宋','宋诗','song-poetry','','[]','有月色逾淡，無風香自生。',48,'全唐诗/poet.song.217000.json','["有月色逾淡，無風香自生。", "霜崖和樹瘦，冰壑養花清。", "政爾疎還冷，忽然斜又橫。", "千林成獨韻，難弟又難兄。"]'),
('2344e2f3-4876-4eb8-916b-73359a81948c','池州和同官詠梅花  其一○','張道洽','宋','宋诗','song-poetry','','[]','雪後半橫枝，溪邊一带籬。',48,'全唐诗/poet.song.217000.json','["雪後半橫枝，溪邊一带籬。", "春從窮臘透，香報老夫知。", "淡月弄疎影，嫩寒含令姿。", "天涯值西子，牢落慰吾思。"]'),
('46f07540-9937-4706-b118-8de8e042512f','池州和同官詠梅花  其一一','張道洽','宋','宋诗','song-poetry','','[]','殷勤天女供，那復一塵生。',48,'全唐诗/poet.song.217000.json','["殷勤天女供，那復一塵生。", "質淡全身白，香寒到骨清。", "常留雪中看，遮莫鬢邊橫。", "萬古月宮桂，猶吾異姓兄。"]'),
('0fa10882-c20b-423a-bdac-beb84f8e9f1d','池州和同官詠梅花  其一二','張道洽','宋','宋诗','song-poetry','','[]','古蘚護疎枝，幽花發短籬。',48,'全唐诗/poet.song.217000.json','["古蘚護疎枝，幽花發短籬。", "唯宜霜月照，莫遣雪風知。", "數點玲瓏玉，三生灑落姿。", "自從窗外見，風味至今思。"]'),
('96803c4e-ad3d-4991-ba91-8b715980e688','池州和同官詠梅花  其一三','張道洽','宋','宋诗','song-poetry','','[]','玉肌元不粟，未怕夜寒生。',48,'全唐诗/poet.song.217000.json','["玉肌元不粟，未怕夜寒生。", "雪裏孤花發，山中一段清。", "幾回和月看，獨立到參橫。", "不傍人籬落，誰呼石作兄。"]'),
('bf730041-ec5b-4ff5-8c7a-2547bad3afe5','池州和同官詠梅花  其一四','張道洽','宋','宋诗','song-poetry','','[]','春脚到寒枝，詩情滿雪籬。',48,'全唐诗/poet.song.217000.json','["春脚到寒枝，詩情滿雪籬。", "每留孤鶴伴，不遣一蜂知。", "風漏臘前信，月描塵外姿。", "憶從歸閬苑，終歲祇君思。"]'),
('0a34595e-16e0-4a88-93a8-0e5cee559488','池州和同官詠梅花  其一五','張道洽','宋','宋诗','song-poetry','','[]','萬壑寒皆沍，孤根暖自生。',48,'全唐诗/poet.song.217000.json','["萬壑寒皆沍，孤根暖自生。", "不隨千卉豔，獨負一身清。", "水際寒香迥，窗間夜影橫。", "輿臺桃李輩，誰弟又誰兄。"]'),
('81b6e2f0-04c2-48a8-8a51-c3b0999fe24a','池州和同官詠梅花  其一六','張道洽','宋','宋诗','song-poetry','','[]','突出一清枝，孤村雪擁籬。',48,'全唐诗/poet.song.217000.json','["突出一清枝，孤村雪擁籬。", "韻無凡眼識，香有自心知。", "不是神仙骨，何緣冰玉姿。", "看看金鼎實，此味幾人思。"]'),
('74d3d8a6-474e-4a92-b17d-0b1d5a20d43d','池州和同官詠梅花  其一七','張道洽','宋','宋诗','song-poetry','','[]','參透香嚴境，都無滅與生。',48,'全唐诗/poet.song.217000.json','["參透香嚴境，都無滅與生。", "平分天女白，全借月娥清。", "雪屋人家好，霜橋野岸橫。", "天寒倚修竹，齊弟伯夷兄。"]'),
('2d3be672-d043-4cd2-bdfe-438d36b3eef5','池州和同官詠梅花  其一八','張道洽','宋','宋诗','song-poetry','','[]','子真同一性，和靖是三生。',48,'全唐诗/poet.song.217000.json','["子真同一性，和靖是三生。", "山意冷愈澹，月香幽更清。", "只應霜鴈識，未怯玉龍橫。", "密友惟清士，佳名稱素兄。"]'),
('164eed03-bbc6-402e-8a55-768c2ef556b3','池州和同官詠梅花  其一九','張道洽','宋','宋诗','song-poetry','','[]','爲愛歲寒枝，呼童旋插籬。',48,'全唐诗/poet.song.217000.json','["爲愛歲寒枝，呼童旋插籬。", "花清吟思覺，香冷夢魂知。", "雪月成仙韻，風煙带野姿。", "江天暮雲合，千里故人思。"]'),
('cc6d38bf-f80a-4539-b064-be27ee02c539','池州和同官詠梅花  其二○','張道洽','宋','宋诗','song-poetry','','[]','村墅苔爲徑，茅檐竹作籬。',48,'全唐诗/poet.song.217000.json','["村墅苔爲徑，茅檐竹作籬。", "神清和月寫，香遠隔煙知。", "老樹有餘韻，別花無此姿。", "詩人風味似，夢寐也應思。"]'),
('c939b1d5-77e4-4691-a6d2-7fca301c633d','梅花二十首  其一','張道洽','宋','宋诗','song-poetry','','[]','和靖風流百世長，吟魂依舊化幽芳。',64,'全唐诗/poet.song.217000.json','["和靖風流百世長，吟魂依舊化幽芳。", "已枯半樹風煙古，纔放一花天地香。", "不肯面隨春冷暖，只將影共月行藏。", "懸知骨法清如許，傳得仙人服玉方。"]'),
('d1dbcec8-1871-4b5f-87c5-227af81879a1','梅花二十首  其二','張道洽','宋','宋诗','song-poetry','','[]','數花疏疏靜處芳，便成佳景不荒凉。',64,'全唐诗/poet.song.217000.json','["數花疏疏靜處芳，便成佳景不荒凉。", "暖回窮谷春常早，影落寒溪水也香。", "自倚風流高格調，唯消質素淡衣裳。", "滿天霜月花邊宿，無復莊周蝶夢狂。"]'),
('adb3303b-fa42-463a-af72-87a46d65bca9','梅花二十首  其三','張道洽','宋','宋诗','song-poetry','','[]','泠泠澗水石橋傍，春正濃時風味長。',64,'全唐诗/poet.song.217000.json','["泠泠澗水石橋傍，春正濃時風味長。", "清介終持孤竹操，繁華不夢百花場。", "描來月地前生瘦，吹落風簷到死香。", "結習已空無染著，每來花下輒成狂。"]'),
('1aa06a79-968f-4ec4-863c-6f582de1750c','梅花二十首  其四','張道洽','宋','宋诗','song-poetry','','[]','凍花無多樹更孤，一溪霜月照清癯。',64,'全唐诗/poet.song.217000.json','["凍花無多樹更孤，一溪霜月照清癯。", "終身只友竹君子，雅志絕羞松大夫。", "白玉都拚雕作蕊，黄金不惜撚爲鬚。", "亦知世有春風伴，問萬花中著得無。"]'),
('59046680-1ee6-4a29-b5d9-0a2fc6a4119e','梅花二十首  其五','張道洽','宋','宋诗','song-poetry','','[]','孤芳嫌殺渾羣芳，雪滿山坳月滿塘。',64,'全唐诗/poet.song.217000.json','["孤芳嫌殺渾羣芳，雪滿山坳月滿塘。", "韻士不隨今世態，仙姝猶作古時粧。", "雪羞潔白常回避，春忌清高不主張。", "地僻何妨絕供給，饑來只用嚥寒香。"]'),
('da7b8f16-6476-4ce0-9d80-990130128467','梅花二十首  其六','張道洽','宋','宋诗','song-poetry','','[]','政爾寒陰慘淡時，忽逢孤豔映疏籬。',64,'全唐诗/poet.song.217000.json','["政爾寒陰慘淡時，忽逢孤豔映疏籬。", "金紫氣味無人識，玉雪襟懷只自知。", "竹屋紙窗清不俗，茶甌禪榻兩相宜。", "花邊不敢高聲語，羌管淒涼更忍吹。"]'),
('5a0a911a-9457-4960-8c0b-1d73d3bbc392','梅花二十首  其七','張道洽','宋','宋诗','song-poetry','','[]','千林凍損積陰凝，一點春從底處生。',64,'全唐诗/poet.song.217000.json','["千林凍損積陰凝，一點春從底處生。", "玉色獨鍾天地正，鐵心不受雪霜驚。", "孤芳若與東君背，數樹能令南紀明。", "醉後惟愁踏花影，青鞋不敢近花行。"]'),
('3cb68c74-7a16-4ecd-82ed-371b53a30346','梅花二十首  其八','張道洽','宋','宋诗','song-poetry','','[]','數株如玉照寒塘，無日無風自在香。',64,'全唐诗/poet.song.217000.json','["數株如玉照寒塘，無日無風自在香。", "谷冷難教春管領，山深自共雪商量。", "已成到骨詩家瘦，不賣入時宮樣粧。", "亂插繁花花下醉，只應我似放翁狂。"]'),
('2a1327cd-4f12-4c89-bc26-a3545e712918','梅花二十首  其九','張道洽','宋','宋诗','song-poetry','','[]','行盡荒林一徑苔，竹稍深處數枝開。',64,'全唐诗/poet.song.217000.json','["行盡荒林一徑苔，竹稍深處數枝開。", "絕知南雪羞相並，欲嫁東風耻自媒。", "無主野橋隨月管，有根寒谷也春回。", "醉餘不睡庭前地，只恐忽吹花落來。"]'),
('de6da430-054e-4432-a24c-ae1841c3babb','梅花二十首  其一○','張道洽','宋','宋诗','song-poetry','','[]','天然標格閬風鄉，薄薄鉛華淡淡粧。',64,'全唐诗/poet.song.217000.json','["天然標格閬風鄉，薄薄鉛華淡淡粧。", "月地向誰孤弄影，雪天驀地忽聞香。", "征鞍處處頻回首，羌管聲聲欲斷腸。", "天上玉妃新謫墮，游蜂不敢近花傍。"]'),
('8f62a783-b349-435d-86f5-8959e952ed18','梅花二十首  其一一','張道洽','宋','宋诗','song-poetry','','[]','纔有梅花便自奇，清香分付入新詩。',64,'全唐诗/poet.song.217000.json','["纔有梅花便自奇，清香分付入新詩。", "閒持盃酒臨風處，獨倚欄干待月時。", "試向園林千萬樹，何如籬落兩三枝。", "霜天角裏空哀怨，丘壑風流總不知。"]'),
('48f814e6-8a2a-45a9-9ea0-2dd993e7f9c6','梅花二十首  其一二','張道洽','宋','宋诗','song-poetry','','[]','纔有梅花便自清，孤山兩句一條冰。',64,'全唐诗/poet.song.217000.json','["纔有梅花便自清，孤山兩句一條冰。", "問渠紫陌花間客，得似清溪樹下僧。", "雅淡久無蘭作伴，孤高惟有竹爲朋。", "雪天枝上三更月，人在瑶臺第幾層。"]'),
('c4880236-2e45-4141-a275-f3f6aaf214b2','梅花二十首  其一三','張道洽','宋','宋诗','song-poetry','','[]','天寒花信未能靈，佇立通宵戶不扃。',64,'全唐诗/poet.song.217000.json','["天寒花信未能靈，佇立通宵戶不扃。", "小萼欲爭天下白，數條獨向雪中青。", "肯教旅雁尋常見，未許游蜂取次經。", "一片唯愁汚塵土，寒苕和月掃中庭。"]'),
('e413476e-1818-41ca-a6c9-566cfcdee780','梅花二十首  其一四','張道洽','宋','宋诗','song-poetry','','[]','纔有梅花便不塵，和霜和月爲精神。',64,'全唐诗/poet.song.217000.json','["纔有梅花便不塵，和霜和月爲精神。", "風流晉宋之間客，清曠羲皇以上人。", "年後臘前無盡意，水邊林下自然春。", "萬花錦繡東風閙，難浼翛翛玉雪身。"]'),
('ab5e377b-6b1d-440a-9e65-aa562c534f24','梅花二十首  其一五','張道洽','宋','宋诗','song-poetry','','[]','纔有梅花便不村，其人如玉立黄昏。',64,'全唐诗/poet.song.217000.json','["纔有梅花便不村，其人如玉立黄昏。", "些些蕊裏藏風韻，箇箇枝頭带月魂。", "常挹清香來燕坐，可教落片點空樽。", "到腰深雪庭前白，心事寒松擬共論。"]'),
('c74108d1-995a-4aca-944a-bd87b1c05ad5','梅花二十首  其一六','張道洽','宋','宋诗','song-poetry','','[]','纔有梅花便不同，一年清致雪霜中。',64,'全唐诗/poet.song.217000.json','["纔有梅花便不同，一年清致雪霜中。", "疏疏籬落娟娟月，寂寂軒窗淡淡風。", "生長元從瓊玉圃，安排合在水晶宮。", "何須更探春消息，自有幽香夢裏通。"]'),
('cebc2562-dc1c-42da-907a-abe57c5c5203','梅花二十首  其一七','張道洽','宋','宋诗','song-poetry','','[]','天下無花白到梅，風前和我不塵埃。',64,'全唐诗/poet.song.217000.json','["天下無花白到梅，風前和我不塵埃。", "崚嶒鶴骨霜中立，偃蹇龍身雪裏來。", "未許瓊花爲行輩，定教玉蕊作輿臺。", "夜深立盡扶疏影，一路清溪踏月回。"]'),
('63d988cf-32f6-4944-b0d7-6a9aecdc8528','梅花二十首  其一八','張道洽','宋','宋诗','song-poetry','','[]','幾年冷樹雪封骨，一夜東風春透懷。',64,'全唐诗/poet.song.217000.json','["幾年冷樹雪封骨，一夜東風春透懷。", "花裏清含仙韻度，人中癯似我形骸。", "三點兩點淡尤好，十枝五枝疏更佳。", "野意終多官意少，玉堂茅舍任安排。"]'),
('aeee64db-df9d-4569-be79-cd3562df4f8f','梅花二十首  其一九','張道洽','宋','宋诗','song-poetry','','[]','愛疏愛淡愛枯枝，已愛梅花更愛奇。',64,'全唐诗/poet.song.217000.json','["愛疏愛淡愛枯枝，已愛梅花更愛奇。", "江路一年春好處，石橋半夜月明時。", "蹇馿積雪深須去，破帽嚴霜打不知。", "世上非無好顔色，詩人所賞是風姿。"]'),
('256ca9f5-19e0-41af-aeae-44c71c7f217d','梅花二十首  其二○','張道洽','宋','宋诗','song-poetry','','[]','癖愛梅花不可醫，開教探早落教遲。',64,'全唐诗/poet.song.217000.json','["癖愛梅花不可醫，開教探早落教遲。", "欲知無限春風意，盡在相將暮雪時。", "竹嶼烟深尋得巧，茅簷月淡立成癡。", "夢驂鸞鶴相尋去，題徧江南寺寺詩。"]'),
('da45c825-e4d2-4b33-aac2-0148b6852610','梅花七律  其一','張道洽','宋','宋诗','song-poetry','','[]','夜月輕描玉樣身，枉拚心力喚真真。',64,'全唐诗/poet.song.217000.json','["夜月輕描玉樣身，枉拚心力喚真真。", "藤牀幾度勞清夢，竹屋相看是故人。", "玉雪襟期惟我共，金蘭氣味更誰親。", "一清頼有天知己，多少春花逐後塵。"]'),
('e1e5ac2b-2595-4d94-80e5-b3607ca6f5bc','梅花七律  其二','張道洽','宋','宋诗','song-poetry','','[]','南堂深處向陽身，第一東風信息真。',64,'全唐诗/poet.song.217000.json','["南堂深處向陽身，第一東風信息真。", "樹冷花清無俗韻，天寒日暮有佳人。", "林逋眼目纔能識，何遜心情獨見親。", "養就枝頭金鼎實，千花陌上已成塵。"]'),
('d7886dc2-782f-4cff-b07e-27afb823a57a','梅花七律  其三','張道洽','宋','宋诗','song-poetry','','[]','灑落胸襟不受塵，水沈爲骨玉爲神。',64,'全唐诗/poet.song.217000.json','["灑落胸襟不受塵，水沈爲骨玉爲神。", "直疑天上渾無雪，不許人閒別有春。", "驅遣山蜂離境界，招呼野鶴作比鄰。", "分明清入仙臞格，人似孤山始得真。"]'),
('7af8ee93-5d3f-45b7-b4ef-14f48a8c25a4','梅花七律  其四','張道洽','宋','宋诗','song-poetry','','[]','清白家風不染塵，冰霜氣骨玉精神。',64,'全唐诗/poet.song.217000.json','["清白家風不染塵，冰霜氣骨玉精神。", "臘前恰見無多蕊，天下還他第一春。", "香在雪天孤有韻，影於月地四無鄰。", "逃禪未到天然處，筆底如何寫得真。"]'),
('003fc108-f03d-4b3a-ab0a-2121cff92a7e','梅花七律  其五','張道洽','宋','宋诗','song-poetry','','[]','雪白都無半點塵，多應滕六即花神。',64,'全唐诗/poet.song.217000.json','["雪白都無半點塵，多應滕六即花神。", "孤根欲老冰霜國，一朵盡收天下春。", "流水斷橋誰是主，寒松疎竹合爲鄰。", "寥寥不見古顔色，澹月微雲到本真。"]'),
('2a8dd1a7-4e41-4eb2-9e46-51c573f78c36','梅花七律  其六','張道洽','宋','宋诗','song-poetry','','[]','萬雪千霜百歲枯，月中不數桂婆娑。',64,'全唐诗/poet.song.217000.json','["萬雪千霜百歲枯，月中不數桂婆娑。", "香來野墅深深徑，影落寒池淺淺波。", "衆木凋零愁凍折，一枝的皪得春多。", "題詩未有驚人句，輸與風流人姓何。"]'),
('9405c624-d875-47ee-a016-a4c58b28fa4b','梅花七律  其七','張道洽','宋','宋诗','song-poetry','','[]','白玉花頭碧玉柯，半枯安得樹婆娑。',64,'全唐诗/poet.song.217000.json','["白玉花頭碧玉柯，半枯安得樹婆娑。", "雲垂江路天將雪，霜滑溪橋水不波。", "林杪冬窮羣木落，嶺頭春蚤一枝多。", "夜深立盡窗前月，其奈此兄風味何。"]'),
('823d5ebf-8919-403b-9097-7834d916bd62','梅花七律  其八','張道洽','宋','宋诗','song-poetry','','["\u897f\u6e56"]','雪虐風饕鐵石柯，終然疎瘦欠婆娑。',64,'全唐诗/poet.song.217000.json','["雪虐風饕鐵石柯，終然疎瘦欠婆娑。", "清姿雅澹嫌霜粉，疎影橫斜浸月波。", "幽樹百年渾未老，好春數點不須多。", "西湖處士風流遠，善識花人更幾何。"]'),
('4faf5225-1405-4d41-8e04-64a8a21372b9','梅花七律  其九','張道洽','宋','宋诗','song-poetry','','[]','蘚護苔封白玉柯，沍寒驀地轉陽和。',64,'全唐诗/poet.song.217000.json','["蘚護苔封白玉柯，沍寒驀地轉陽和。", "任枯半樹韻尤古，纔放一花春已多。", "神倩滿庭明月寫，香隨隔水晚風過。", "古今真愛梅人少，願祀詩家始祖何。"]'),
('5525d5a6-f38b-444f-8ddc-317ad483bffa','梅花七律  其一○','張道洽','宋','宋诗','song-poetry','','[]','高標勝韻點人寒，殘雪疎籬是水南。',64,'全唐诗/poet.song.217000.json','["高標勝韻點人寒，殘雪疎籬是水南。", "天上玉妃居第一，人閒石友結成三。", "廣平心事今猶在，和靖家風晚最諳。", "莫訝清晨將鶴出，孤筇行過竹西庵。"]'),
('c97b1f35-845b-4486-9d61-7aae44908ae2','梅花七律  其一一','張道洽','宋','宋诗','song-poetry','','[]','蓓蕾梢頭破晚寒，風流無限澗之南。',64,'全唐诗/poet.song.217000.json','["蓓蕾梢頭破晚寒，風流無限澗之南。", "俯看春艷相千萬，微挂月痕初二三。", "巖桂清應居此下，山桃素不與吾諳。", "一枝昨夜垂垂白，知在前村水竹庵。"]'),
('31fd9890-e6c4-4bce-b29a-26b9b366d963','梅花七律  其一二','張道洽','宋','宋诗','song-poetry','','[]','瑩徹無瑕照眼寒，無邊春意滿溪南。',64,'全唐诗/poet.song.217000.json','["瑩徹無瑕照眼寒，無邊春意滿溪南。", "絕疑飛雪吹花六，獨自臨風遶樹三。", "夜月襟懷誰與共，歲寒情味久相諳。", "軟紅塵土應無此，竹外清湍竹裏庵。"]'),
('b50466ba-550c-4233-8778-0a39d5ec0153','梅花七律  其一三','張道洽','宋','宋诗','song-poetry','','[]','纔有梅花便不凡，半依月澗半霜巖。',64,'全唐诗/poet.song.217000.json','["纔有梅花便不凡，半依月澗半霜巖。", "斜欹獨樹疑龍卧，細啄殘英笑鶴饞。", "雪裏仙姿誰解寫，臘前春信可容緘。", "孤山遺下十四字，千載一條冰樣銜。"]'),
('b6d95e8d-5d68-4702-97ef-58f067d4351d','梅花七律  其一四','張道洽','宋','宋诗','song-poetry','','[]','窮臘無花可入詩，何人翦玉著南枝。',64,'全唐诗/poet.song.217000.json','["窮臘無花可入詩，何人翦玉著南枝。", "香浮風細月明夜，春在天寒日暮時。", "玉面亭亭成獨立，冰心皎皎竟誰知。", "眼明數點窗前白，夢見魯山元紫芝。"]'),
('48f0a733-4d75-4399-9854-e5f6abad8e16','梅花七律  其一五','張道洽','宋','宋诗','song-poetry','','[]','兀坐蒲團眼輒驚，數花點得一窗明。',64,'全唐诗/poet.song.217000.json','["兀坐蒲團眼輒驚，數花點得一窗明。", "月邊再見古顔色，雪裏獨含春性情。", "骨格三生傳島瘦，風標萬世說夷清。", "夜霜竹屋寒無奈，一笑持杯壽此兄。"]'),
('0d2c48bc-d2dc-4a6f-82c1-397e2e664e26','梅花七律  其一六','張道洽','宋','宋诗','song-poetry','','[]','皎然玉色耿無鄰，回首千花總後塵。',64,'全唐诗/poet.song.217000.json','["皎然玉色耿無鄰，回首千花總後塵。", "數樹羅浮山下月，一枝大庾嶺頭春。", "與時無競抱幽質，於我有情真故人。", "衆志獨清天不管，自臨野水照精神。"]'),
('205f5de9-da8f-42b7-8fe7-ea20cf91675e','梅花七律  其一七','張道洽','宋','宋诗','song-poetry','','[]','冰氏根苗出涸陰，一團玉雪縞千林。',64,'全唐诗/poet.song.217000.json','["冰氏根苗出涸陰，一團玉雪縞千林。", "百年幽樹古香澹，數箇疎花春意深。", "俗眼共憐西子態，世人誰識廣平心。", "孤芳不入騷經裏，物色分留待我吟。"]'),
('bcc02d53-e86b-41f8-b449-2233744ac31f','梅花七律  其一八','張道洽','宋','宋诗','song-poetry','','[]','落盡精英宇宙荒，天將清白付幽芳。',64,'全唐诗/poet.song.217000.json','["落盡精英宇宙荒，天將清白付幽芳。", "萬花場裏春無色，獨樹橋邊月有香。", "怪怪奇奇依水石，瀟瀟灑灑带冰霜。", "瓊膚耐得寒如許，薄薄輕綃翦作裳。"]'),
('b5db8704-2d20-49f0-b282-c52a71bf8e6f','梅花七律  其一九','張道洽','宋','宋诗','song-poetry','','[]','越疎越澹越幽奇，最是精神與月宜。',64,'全唐诗/poet.song.217000.json','["越疎越澹越幽奇，最是精神與月宜。", "殘雪軒窗看到曉，冷煙籬落立移時。", "寄將水驛傳千里，折得寒檐第幾枝。", "只爲花清詩自別，此花之外更無詩。"]'),
('fc36b03d-4d8d-4fbe-84f2-b69770ad5352','梅花七律  其二○','張道洽','宋','宋诗','song-poetry','','[]','花中氣節老逾剛，萬木摧殘獨自芳。',64,'全唐诗/poet.song.217000.json','["花中氣節老逾剛，萬木摧殘獨自芳。", "天女不生凡意想，月娥偏尚澹梳妝。", "精神冰玉前生瘦，骨髓栴檀抵死香。", "說到調和天下口，輕輕桃杏敢承當。"]'),
('e33c5c50-ec03-4cee-948c-d610387366b5','梅花七律  其二一','張道洽','宋','宋诗','song-poetry','','[]','子真世裔神仙種，和靖家風冰玉身。',64,'全唐诗/poet.song.217000.json','["子真世裔神仙種，和靖家風冰玉身。", "只此玲瓏三數蕊，不知收拾幾多春。", "香浮靜夜天知己，影浸寒池月寫真。", "留待楚騷千載恨，花中誰識獨醒人。"]'),
('2c72ccdb-b55c-431f-94fc-5770ce7af7bf','梅花七律  其二二','張道洽','宋','宋诗','song-poetry','','[]','天姿雅澹似高人，萬樹千紅總後塵。',64,'全唐诗/poet.song.217000.json','["天姿雅澹似高人，萬樹千紅總後塵。", "花蚤花遲兩年景，枝南枝北一家春。", "輕輕欲折還休去，得得相看不厭頻。", "坐到參橫渾未曉，夜窗無月更傳神。"]'),
('d3b4736c-f172-47af-8f20-17ac35476e6b','梅花七律  其二三','張道洽','宋','宋诗','song-poetry','','[]','乾坤收拾幾精華，全付茅茨小小家。',64,'全唐诗/poet.song.217000.json','["乾坤收拾幾精華，全付茅茨小小家。", "壓盡園林千萬蕊，只消籬落兩三花。", "雪消數尺暗埋嶺，月浸一痕微印沙。", "玉面亭亭太幽獨，天寒空谷正堪嗟。"]'),
('a8aa09e8-f389-4374-8492-6b61e1db01a3','梅花七律  其二四','張道洽','宋','宋诗','song-poetry','','[]','百餘年樹半蒼苔，纔有一枝花便佳。',64,'全唐诗/poet.song.217000.json','["百餘年樹半蒼苔，纔有一枝花便佳。", "臘近已含春意思，香寒足慰晚情懷。", "澹煙孤寺藏山崦，殘雪疎籬傍水涯。", "剛被幽香相觸撥，消磨石路幾青鞵。"]'),
('02757e20-ae75-4568-8e30-c82680edbcb4','嶺梅','張道洽','宋','宋诗','song-poetry','','["\u6885\u82b1"]','到處皆詩境，隨時有物華。',24,'全唐诗/poet.song.217000.json','["到處皆詩境，隨時有物華。", "應酬都不暇，一嶺是梅花。"]'),
('4db0c215-1eb6-472d-8cba-f1fb32073d90','千葉梅','張道洽','宋','宋诗','song-poetry','','[]','應怯春寒悄，重重疊疊衣。',24,'全唐诗/poet.song.217000.json','["應怯春寒悄，重重疊疊衣。", "本來飛燕瘦，翻作玉環肥。"]'),
('2a0eee3c-c84c-46c8-a21b-1a8a9e9fc234','照水梅','張道洽','宋','宋诗','song-poetry','','[]','照影寒溪水，溪中水也香。',24,'全唐诗/poet.song.217000.json','["照影寒溪水，溪中水也香。", "佳人臨寶鑑，自作壽陽妝。"]'),
('81153517-c357-4cdc-b570-cba50901be6b','瓶梅','張道洽','宋','宋诗','song-poetry','','[]','春在膽瓶閒，朝看復暮看。',24,'全唐诗/poet.song.217000.json','["春在膽瓶閒，朝看復暮看。", "小屏遮護著，不怕玉肌寒。"]'),
('91ca3e6b-0bb8-457e-a8c4-eb09705da97b','尋梅','張道洽','宋','宋诗','song-poetry','','[]','澹澹一痕月，疎疎數箇花。',24,'全唐诗/poet.song.217000.json','["澹澹一痕月，疎疎數箇花。", "春風也公道，先到野人家。"]'),
('eb133300-cd6c-482e-b14d-71054bac8ec8','折梅','張道洽','宋','宋诗','song-poetry','','[]','日暮天寒小驛亭，竹邊流水淺泠泠。',32,'全唐诗/poet.song.217000.json','["日暮天寒小驛亭，竹邊流水淺泠泠。", "一枝蚤落詩人手，無恨春風入膽瓶。"]'),
('1796268c-3d47-468c-aa29-45469dbd9a36','嗅梅','張道洽','宋','宋诗','song-poetry','','[]','一夜吹香過別村，瘴江洗盡水雲昏。',32,'全唐诗/poet.song.217000.json','["一夜吹香過別村，瘴江洗盡水雲昏。", "真堪持作維摩供，鼻觀微參透頂門。"]'),
('b131b78e-40d7-40b7-adf9-028dd784e321','訪梅','張道洽','宋','宋诗','song-poetry','','[]','梅花欲放遶溪行，隔水香來分外清。',32,'全唐诗/poet.song.217000.json','["梅花欲放遶溪行，隔水香來分外清。", "拄杖過橋尋欲遍，竹林疎處數花明。"]'),
('13931110-200b-4271-ae0f-f5a4240e023e','憶梅','張道洽','宋','宋诗','song-poetry','','[]','到得芳天閙衆葩，相思一夜鬢成華。',32,'全唐诗/poet.song.217000.json','["到得芳天閙衆葩，相思一夜鬢成華。", "閬風歸去無消息，夢寐猶應見此花。"]'),
('7fff609b-17e9-4a50-b0e2-1827e6aab889','墨梅','張道洽','宋','宋诗','song-poetry','','[]','一枝的的照人寒，絕勝溪橋立馬看。',32,'全唐诗/poet.song.217000.json','["一枝的的照人寒，絕勝溪橋立馬看。", "祇恐東風解相怨，漏他消息入毫端。"]'),
('42e03fe9-1ac4-406c-b4c3-8d990f430a61','瓶梅','張道洽','宋','宋诗','song-poetry','','[]','寒水一瓶春數枝，清香不減小溪時。',32,'全唐诗/poet.song.217000.json','["寒水一瓶春數枝，清香不減小溪時。", "橫斜燭底無人見，莫與微雲澹月知。"]'),
('7d697247-acfa-4d75-bf50-72fa2cf9ef03','見梅','張道洽','宋','宋诗','song-poetry','','[]','寒梅衝雪領春回，桃李紛紛趁脚來。',32,'全唐诗/poet.song.217000.json','["寒梅衝雪領春回，桃李紛紛趁脚來。", "一點陽和無盡處，從頭分與百花開。"]'),
('b768486e-59b5-478d-9150-da2d42f5b14b','尋梅','張道洽','宋','宋诗','song-poetry','','[]','平生春興十分深，長恐梅花負賞心。',32,'全唐诗/poet.song.217000.json','["平生春興十分深，長恐梅花負賞心。", "偶有一枝斜照水，前村踏雪也須尋。"]'),
('905fe406-299b-48ab-859c-cf47c95bf09a','對梅  其一','張道洽','宋','宋诗','song-poetry','','[]','老年不著梅花眼，得見梅花子細看。',32,'全唐诗/poet.song.217000.json','["老年不著梅花眼，得見梅花子細看。", "我不似梅梅似我，風流心事一般般。"]'),
('4b78d189-8122-4030-b5c5-bd16856c2d26','對梅  其二','張道洽','宋','宋诗','song-poetry','','[]','一點春風天正冬，不妨花下倒金鍾。',32,'全唐诗/poet.song.217000.json','["一點春風天正冬，不妨花下倒金鍾。", "扳條揀蕊輕輕折，只嗅清香醉殺儂。"]'),
('fa9d80f1-773c-4e1d-9752-3eb1b25c4570','對梅  其三','張道洽','宋','宋诗','song-poetry','','[]','數點枝頭黏白玉，一年春意動黄鍾。',32,'全唐诗/poet.song.217000.json','["數點枝頭黏白玉，一年春意動黄鍾。", "爲渠拚受風流罪，只恐風流不到儂。"]'),
('34a35891-618f-4722-bd89-3436c3f8e34d','對梅  其四','張道洽','宋','宋诗','song-poetry','','[]','秋水娟娟隔美人，江東日暮幾重雲。',32,'全唐诗/poet.song.217000.json','["秋水娟娟隔美人，江東日暮幾重雲。", "孤燈竹屋霜清夜，夢到梅花即見君。"]'),
('59059f24-42f0-45af-b01a-f90508967ebc','詠梅雜詩  其一','張道洽','宋','宋诗','song-poetry','','[]','百餘年樹未爲古，三四點花何限春。',32,'全唐诗/poet.song.217000.json','["百餘年樹未爲古，三四點花何限春。", "欲折一枝無處贈，世間少有識花人。"]'),
('27f978f3-6621-41fe-9f5b-f70e7033bf0d','詠梅雜詩  其二','張道洽','宋','宋诗','song-poetry','','[]','此兄自是風塵表，半在山巔半水涯。',32,'全唐诗/poet.song.217000.json','["此兄自是風塵表，半在山巔半水涯。", "老子怕寒渾不出，夜窗明月看橫斜。"]'),
('a5ac32ea-2763-4592-8ff1-e776f63fd361','詠梅雜詩  其三','張道洽','宋','宋诗','song-poetry','','[]','疎花清曉嫩寒時，粉蝶霜禽總不知。',32,'全唐诗/poet.song.217000.json','["疎花清曉嫩寒時，粉蝶霜禽總不知。", "未有風流如此老，爲渠費盡雪橋詩。"]'),
('532fa93b-eb19-4d34-b448-3adfffbfb1a4','詠梅雜詩  其四','張道洽','宋','宋诗','song-poetry','','[]','風流百世林和靖，灑落三生楊補之。',32,'全唐诗/poet.song.217000.json','["風流百世林和靖，灑落三生楊補之。", "一自閬風歸去後，幾回展畫又觀詩。"]'),
('11cf7e0a-dc99-43c3-a4fa-8efdc1e7f72c','詠梅雜詩  其五','張道洽','宋','宋诗','song-poetry','','[]','夜深月透小窗紗，夢到瑶池阿母家。',32,'全唐诗/poet.song.217000.json','["夜深月透小窗紗，夢到瑶池阿母家。", "急遣山僮開戶看，不知是雪是梅花。"]'),
('9fd1ff01-c540-4d08-911b-f5191b6859b5','詠梅雜詩  其六','張道洽','宋','宋诗','song-poetry','','[]','孤山風味梅花句，先落人閒萬古香。',32,'全唐诗/poet.song.217000.json','["孤山風味梅花句，先落人閒萬古香。", "應笑老夫無一語，千回寂寞遶花傍。"]'),
('36bf84ff-7f91-49a3-a318-1586c5f8456e','詠梅雜詩  其七','張道洽','宋','宋诗','song-poetry','','[]','三生種植得梅緣，每見梅花輒欲顛。',32,'全唐诗/poet.song.217000.json','["三生種植得梅緣，每見梅花輒欲顛。", "清夢化爲蝴蝶去，也應只在此花邊。"]'),
('fff9c955-827e-4305-87b1-874a69b4bbaa','詠梅雜詩  其八','張道洽','宋','宋诗','song-poetry','','[]','昔年詩擔過羅浮，曾見梅花一夕留。',32,'全唐诗/poet.song.217000.json','["昔年詩擔過羅浮，曾見梅花一夕留。", "翠鳳幾回清夜夢，月明還挂舊枝頭。"]'),
('bed46f2f-5848-49bd-9d7c-f2dbdaa0cd39','詠梅雜詩  其九','張道洽','宋','宋诗','song-poetry','','[]','茶竈熏爐與筆牀，黄昏待月在東廂。',32,'全唐诗/poet.song.217000.json','["茶竈熏爐與筆牀，黄昏待月在東廂。", "無人知得花清處，影落寒池水亦香。"]'),
('79b7f152-754c-4ac4-9680-bac2e956f9fb','詠梅雜詩  其一○','張道洽','宋','宋诗','song-poetry','','[]','不是梅花契分深，與誰共話歲寒心。',32,'全唐诗/poet.song.217000.json','["不是梅花契分深，與誰共話歲寒心。", "隔溪竹外無人見，自有香來不用尋。"]'),
('2d2da2d4-66d3-40fa-a995-59b1fbad9b89','詠梅雜詩  其一一','張道洽','宋','宋诗','song-poetry','','[]','萬里閒關庾嶺回，嶺頭曾見此花來。',32,'全唐诗/poet.song.217000.json','["萬里閒關庾嶺回，嶺頭曾見此花來。", "遠遊何似在家好，屋角玲瓏一樹開。"]'),
('100a0e0e-8f38-4c58-9d79-73035ec7e711','詠梅雜詩  其一二','張道洽','宋','宋诗','song-poetry','','[]','數點疎花不滿枝，倚欄惟恨月明遲。',32,'全唐诗/poet.song.217000.json','["數點疎花不滿枝，倚欄惟恨月明遲。", "風流一段無人共，正是霜飛屋角時。"]'),
('88e5e836-e890-4ba0-bf22-41dc7aa6642d','詠梅雜詩  其一三','張道洽','宋','宋诗','song-poetry','','[]','小小茅茨野老家，不隨桃李競春華。',32,'全唐诗/poet.song.217000.json','["小小茅茨野老家，不隨桃李競春華。", "欲知格韻真孤絕，禿盡千林始一花。"]'),
('09fb6a8b-52c5-4952-a456-2cf85335ea6f','詠梅雜詩  其一四','張道洽','宋','宋诗','song-poetry','','[]','正是天荒地老時，芙蓉憔悴菊離披。',32,'全唐诗/poet.song.217000.json','["正是天荒地老時，芙蓉憔悴菊離披。", "呼童試探溪南路，春到寒梅第幾枝。"]'),
('e39883a0-9779-42c4-a5ef-3173b23d251c','詠梅雜詩  其一五','張道洽','宋','宋诗','song-poetry','','[]','南枝太蚤北枝遲，非蚤非遲恰好時。',32,'全唐诗/poet.song.217000.json','["南枝太蚤北枝遲，非蚤非遲恰好時。", "竹屋一痕微月照，老夫樹下正吟詩。"]'),
('4c35dbd6-6337-4437-be74-4ab1378e7dd6','和方虛谷豫章徐子蒼沿制檄抵秋浦','張道洽','宋','宋诗','song-poetry','','[]','詞林日凋疎，生意不復新。',48,'全唐诗/poet.song.217000.json','["詞林日凋疎，生意不復新。", "慎勿大崛奇，崛奇驚世人。", "玉堂老仙坡，過海走一巡。", "非天寔罰之，語言累其身。"]'),
('65a4bd4e-b251-4925-b3d8-c50d7d9879d1','包山書院','張道洽','宋','宋诗','song-poetry','','[]','銜命龍荒萬里餘，歸尋水竹與同居。',64,'全唐诗/poet.song.217000.json','["銜命龍荒萬里餘，歸尋水竹與同居。", "早從洙泗傳心學，晚闢包山教子書。", "細草幽花香筆硯，清風明月滿庭除。", "一生宇宙皆春意，此樂顔魯亦自如。"]'),
('e130bf63-ecb7-4aa5-b119-bda3eb49fb11','句  其一','張道洽','宋','宋诗','song-poetry','','[]','前生薝葡林中夢，到死旃檀國裏香。',16,'全唐诗/poet.song.217000.json','["前生薝葡林中夢，到死旃檀國裏香。"]'),
('945ff5f2-916c-44d1-b38d-b5a61b9888fb','句  其二','張道洽','宋','宋诗','song-poetry','','[]','早緣服玉肌能白，不爲薰衣骨亦香。',16,'全唐诗/poet.song.217000.json','["早緣服玉肌能白，不爲薰衣骨亦香。"]'),
('d6eaf3a5-39ce-4022-b3fa-51ae4f1e5876','遊九鎖  其一','楊伯巖','宋','宋诗','song-poetry','','[]','曉山雲樹碧生秋，乘興間爲洞府游。',32,'全唐诗/poet.song.217000.json','["曉山雲樹碧生秋，乘興間爲洞府游。", "片石却將仙路隔，負人平昔慕浮丘。"]'),
('fd313ff8-f272-46d4-b9dc-0608ed55cb9c','遊九鎖  其二','楊伯巖','宋','宋诗','song-poetry','','[]','亭前絕壁下飛瀑，天風夜半吹韶咸。',32,'全唐诗/poet.song.217000.json','["亭前絕壁下飛瀑，天風夜半吹韶咸。", "疑是銀河天上水，壯士挽落千丈巖。"]'),
('fd645b89-f0dc-4950-b569-40c53861374c','徐偃王廟','楊伯巖','宋','宋诗','song-poetry','','[]','當年大德瑞朱弓，仁在斯民千古同。',64,'全唐诗/poet.song.217000.json','["當年大德瑞朱弓，仁在斯民千古同。", "故國已無徐子土，靈祠今有梵王宮。", "水流簷影晴江上，山接鐘聲暮靄中。", "攬轡此行因致敬，蒲團分坐聽談空。"]'),
('20398b94-222e-4d51-9151-6d57cdafa2e8','句','楊伯巖','宋','宋诗','song-poetry','','[]','東臺仙子許參元，滿月光明現大千。',16,'全唐诗/poet.song.217000.json','["東臺仙子許參元，滿月光明現大千。"]'),
('b8284344-6bba-4a2d-9fb7-79a19542e583','端平乙未王正十月有二日以官事宿祥雲得五十六言','朱乙午','宋','宋诗','song-poetry','','[]','東風吹夢到遥岑，四日苔痕兩度尋。',64,'全唐诗/poet.song.217000.json','["東風吹夢到遥岑，四日苔痕兩度尋。", "鄰望紫衣騰佛氣，岩披古像印人心。", "新椽插斗營層址，老衲乘雲閴足音。", "我爲登山參世法，只將空洞瞰崎崟。"]'),
('6b442bb9-3116-45f1-9d4f-0b006275e277','題鼓山','鄭江','宋','宋诗','song-poetry','','[]','携檄來遊石鼓山，島洲疑望有無間。',64,'全唐诗/poet.song.217000.json','["携檄來遊石鼓山，島洲疑望有無間。", "大江潮落海門出，洞口雲深月戶關。", "名揭君謨椽筆健，詩留子直翠珉斑。", "古靈更有碑三字，屴崱須登莫倦還。"]'),
('d02fb15a-e32b-4552-81dc-2bc0b414b643','高塘橋','高衡孫','宋','宋诗','song-poetry','','[]','碧荷色猶懶，紫花香漸多。',48,'全唐诗/poet.song.217000.json','["碧荷色猶懶，紫花香漸多。", "過橋通故里，分界入新河。", "土潤何勞治，沙平不用磨。", "衣冠今已矣，從此想鳴珂。"]'),
('dde84cec-ee0e-48a9-9f2a-a1be1d324d8d','秋日憶友','張同甫','宋','宋诗','song-poetry','','[]','閶闔風高白露秋，蘆花如雪動邊愁。',32,'全唐诗/poet.song.217000.json','["閶闔風高白露秋，蘆花如雪動邊愁。", "故人迢遞天南北，明月娟娟獨倚樓。"]'),
('2999287e-ac8d-4599-b7c5-f10f3758cc3b','湯公洞','張同甫','宋','宋诗','song-poetry','','[]','萬點波光映古丘，林深雲鎖洞門秋。',32,'全唐诗/poet.song.217000.json','["萬點波光映古丘，林深雲鎖洞門秋。", "是誰訂我重來約，携手相將到白頭。"]'),
('de192517-f067-4c2d-be5f-4cdf61b7acce','天遊齋','李伯玉','宋','宋诗','song-poetry','','[]','丈人未始出吾宗，草靡波流盡太沖。',64,'全唐诗/poet.song.217000.json','["丈人未始出吾宗，草靡波流盡太沖。", "七竅鑿開無混沌，六根消落盡圓通。", "法身兔角聲聞外，塵事牛毛夢幻中。", "誰會天遊更端的，瘦梅疎竹一窗風。"]'),
('71c2fa03-e2bf-4c7a-93c2-ca30113925ec','碇齋','李伯玉','宋','宋诗','song-poetry','','[]','先生平地起風波，畢竟中流定得麽。',32,'全唐诗/poet.song.217000.json','["先生平地起風波，畢竟中流定得麽。", "放取斷頭船子去，醉眠烟雨一漁蓑。"]'),
('3e562fe8-5b64-4e4c-af27-adb9fb268a3f','吏隠堂','李伯玉','宋','宋诗','song-poetry','','[]','吏隠先尋一著高，盡輸酒聖與詩豪。',64,'全唐诗/poet.song.217000.json','["吏隠先尋一著高，盡輸酒聖與詩豪。", "君方無事同犀首，我縱有官如馬曹。", "把似啜茶看孟子，何如痛飲讀離騷。", "胸中磊落澆三椀，倩得麻姑癢處搔。"]'),
('a210e399-9edb-4034-9b30-15dcbe82a08c','送蕭晉卿西行','李伯玉','宋','宋诗','song-poetry','','[]','上馬能擊賊，下馬能草檄。',190,'全唐诗/poet.song.217000.json','["上馬能擊賊，下馬能草檄。", "蕭郎負此文武之全才，當卧元龍樓百尺。", "屏山閲盡眼中人，磊落深沉只識君。", "冷官不受人料理，拄笏時看西山雲。", "與君嘗談秘書閣，百二秦城錦相錯。", "第恐羌兒或弄兵，今日始知先一著。", "自有龍圖十萬兵，請乘一障終權輕。", "初聞召至青油幕，袖中已草從軍行。", "相國謀深古來少，想見智囊談未了。", "賀蘭鼠子不足平，底用西征出師表。", "凉州久苦寒烟埋，今年定見玉關開。", "凱旋只在春風後，趁取閑閑登吹臺。"]'),
('bfa8a2ab-611d-4c43-a257-147d78829c29','淳祐七年丁未十一月朔蔡久軒自江東提刑歸抵家時三館諸公以風霜隨氣節河漢下文章分韻賦詩送別得下字','李伯玉','宋','宋诗','song-poetry','','[]','清時屏臣姦，琴瑟大更化。',288,'全唐诗/poet.song.217000.json','["清時屏臣姦，琴瑟大更化。", "四佞斥昕朝，一札頒丙夜。", "明庭集孔鸞，清廟薦瓊斚。", "堂堂西山孫，藉藉少室價。", "給札承明廬，紬書群玉舍。", "功名渠自來，迫逐不容赦。", "君心政事本，治化朝廷下。", "紀綱始宮闈，國本關宗社。", "累章瀝忠赤，萬口齊膾炙。", "邇來忠佞雜，異論淆王霸。", "昊天且不容，膴仕駢姻婭。", "回遹何日沮，好官從唾駡。", "人方酣勢利，君獨辯姦詐。", "同僚俱愧赧，竈婢亦驚訝。", "官職一涕唾，名聲窮泰華。", "列之紹符間，允矣陳鄒亞。", "江東天一方，使者星言駕。", "我亦滕氓廛，何幸寇君借。", "國步正艱危，人心實凭藉。", "良民困盜賊，螟蟊損禾稼。", "豪姓侵細民，荆榛害桑柘。", "汙官混廉吏，鮑穢薰蘭麝。", "少煩六轡濡，行見四輩迓。", "君誠梁棟材，好與支大厦。"]'),
('17478dc4-8474-4404-9e76-a3864d8a62da','雪後','李伯玉','宋','宋诗','song-poetry','','[]','玉環暈月蟠長虹，飛沙捲土號陰風。',212,'全唐诗/poet.song.217000.json','["玉環暈月蟠長虹，飛沙捲土號陰風。", "黄雲羃羃翳晴空，屋頭唧唧鳴寒蟲。", "天符夜下扶桑宮，玄冥震怒鞭魚龍。", "魚龍飛出滄海底，咄嗟如律愁神公。", "急𣂏北斗捲雲漢，凌凘捲入天瓢中。", "椎璋碎六華，剪出寒瓏璁。", "翩翩作穗大如手，千奇萬巧難形容。", "恍如墮我銀沙界，清光皜夜寒朣朧。", "肝腸作祟耿無寐，試把往事閒追窮。", "男兒生須銜枚捲甲臂琱弓，徑投虎穴策奇功。", "不然羊羔酒帳玻瓈鍾，侍兒醉臉潮春紅。", "誰能蹇馿駝著灞陵東，骨相酸寒愁煞儂。", "屏山正吐黄虀氣，笑倒坐閒亡是公。"]'),
('e1e1b196-91f0-4e67-8e8c-35a91e67e832','懷湯尚書伯紀','李伯玉','宋','宋诗','song-poetry','','[]','一曲清歌一弄琴，十千美酒十分斟。',64,'全唐诗/poet.song.217000.json','["一曲清歌一弄琴，十千美酒十分斟。", "江流不動潮初上，斗柄將垂夜向深。", "沙觜露漙孤鶴警，潭心月冷老龍吟。", "此時最是懷鄉國，雲裏征鴻閒遠砧。"]'),
('3186cb25-2732-4bb2-b155-8cb6a5dd072b','挽徐衡','李伯玉','宋','宋诗','song-poetry','','[]','胸次恢恢百萬兵，文才武略冠群英。',64,'全唐诗/poet.song.217000.json','["胸次恢恢百萬兵，文才武略冠群英。", "挽弓破筈狀元銳，擒寇功封使者榮。", "兩尚皇姬升帝眷，一頒皂纛出神京。", "追思八字君恩重，鑾駕雖無如朕行。"]'),
('6d9ef22b-70ca-40f1-9526-a54c3c276288','金鰲橋','莊師熊','宋','宋诗','song-poetry','','[]','白鶴峰前放衙晚，金鰲背上駕樓成。',64,'全唐诗/poet.song.217000.json','["白鶴峰前放衙晚，金鰲背上駕樓成。", "舟移遠浦隨潮落，帷捲輕風看月生。", "他日懷人如在峴，今朝飲客且登瀛。", "幸陪讌笑欄干曲，醉後不知杯幾行。"]'),
('dea40ae6-7722-43fb-be2d-87c91a37bec4','御書閣','雍沿','宋','宋诗','song-poetry','','[]','三重神毫曼古稀，龍盤鳳戲欲騰飛。',32,'全唐诗/poet.song.217000.json','["三重神毫曼古稀，龍盤鳳戲欲騰飛。", "珍藏今作古山寶，一歲中添一褐衣。"]'),
('2eed21e5-7411-4004-b26d-0322a8be4404','仙馬洞','雍沿','宋','宋诗','song-poetry','','[]','龍駒昔日此昇仙，洞掩碑殘不計年。',32,'全唐诗/poet.song.217000.json','["龍駒昔日此昇仙，洞掩碑殘不計年。", "勝蹟依然無處問，一僧重鎖薜蘿煙。"]'),
('da369b05-f0e8-4309-9a71-51b56ffc6776','爾朱真人藥竈','雍沿','宋','宋诗','song-poetry','','[]','當日先生藥已成，便將金井等閑輕。',32,'全唐诗/poet.song.217000.json','["當日先生藥已成，便將金井等閑輕。", "迨今遺蹟峰巒上，時有青烟竈下生。"]'),
('5154e373-0d6c-4c10-a22e-2a92dd165c9c','太蓬景福寺','雍沿','宋','宋诗','song-poetry','','[]','樓閣參差聳茂林，危梯{土臼}徑幾重深。',67,'全唐诗/poet.song.217000.json','["樓閣參差聳茂林，危梯{土臼}徑幾重深。", "周行巖麓四十里，下視井塵千萬尋。", "僧住不生雲水興，客遊偷息利名心。", "若教工部曾經此，應徧靈蹤處處吟。"]'),
('4b55a8e0-016f-41c2-96b6-49c78853f0df','九江聞雁','陳均','宋','宋诗','song-poetry','','[]','烟波渺渺夢悠悠，家在江南海盡頭。',32,'全唐诗/poet.song.217000.json','["烟波渺渺夢悠悠，家在江南海盡頭。", "音信稀疏兄弟隔，一聲新雁九江秋。"]'),
('e129991e-3491-409f-b53b-4d1b3d74012a','鶴林寺  其一','陳均','宋','宋诗','song-poetry','','[]','知有楓林坐竹間，每尋紆路試登山。',32,'全唐诗/poet.song.217000.json','["知有楓林坐竹間，每尋紆路試登山。", "虛簷忽見籠中鶴，似我愛閒身未閒。"]'),
('f99f467e-0f46-4b16-a906-f491cfaf335e','鶴林寺  其二','陳均','宋','宋诗','song-poetry','','[]','竹遶高僧逢話處，花留仙者舊開枝。',32,'全唐诗/poet.song.217000.json','["竹遶高僧逢話處，花留仙者舊開枝。", "道身虛淡元無著，付與東風爛漫吹。"]'),
('42cedd42-162e-4c07-927e-295b8aaf9246','七溪','陳均','宋','宋诗','song-poetry','','[]','爲愛潺湲引步遲，不知行盡白雲西。',32,'全唐诗/poet.song.217000.json','["爲愛潺湲引步遲，不知行盡白雲西。", "雲深忘却來時路，吟斷空山片月低。"]'),
('d3eee39a-4bdf-45c1-9270-90372db8be63','孟享仰瞻聖駕','鄧克中','宋','宋诗','song-poetry','','[]','輦路春風錦繡張，裁紅剪綠鬭芬芳。',32,'全唐诗/poet.song.217000.json','["輦路春風錦繡張，裁紅剪綠鬭芬芳。", "黄羅傘底瞻天表，萬疊明霞捧太陽。"]'),
('0f32ada3-9742-4a02-8006-0820fa78ddf8','勉繩武王生','趙汝諤','宋','宋诗','song-poetry','','[]','家世才名著論衡，君今正好繼前程。',64,'全唐诗/poet.song.217000.json','["家世才名著論衡，君今正好繼前程。", "開門且悟扶風業，閲市須耽洛邑經。", "道在虞翻應有述，學高韓愈豈無稱。", "聖賢都屬吾儒事，莫墮疎慵忝此生。"]'),
('58d3dab5-cfe1-4149-8c69-cd1a87037b4c','悼梁公','趙汝諤','宋','宋诗','song-poetry','','["\u8861\u5c71"]','鶴髮童顔兩鬢星，一經庭訓已成名。',64,'全唐诗/poet.song.217000.json','["鶴髮童顔兩鬢星，一經庭訓已成名。", "倏驚南嶽長庚墮，怪底西巖暮日傾。", "爵錫九重恩正洽，骨埋三尺土猶馨。", "賢郎連步從階上，次弟褒封到墓塋。"]'),
('2aa7ec74-eda6-43f5-a691-143a8ecfcdf8','題秀巖','胡純','宋','宋诗','song-poetry','','[]','陽山鳥道峯前過，一谷呀然隔世埃。',64,'全唐诗/poet.song.217000.json','["陽山鳥道峯前過，一谷呀然隔世埃。", "泉落陰渠蒼海近，□穿嶔室濕雲開。", "回中百客麟堪供，仙者千年鶴自來。", "往矣張韓闕鎸賞，豎扶寒筆意生哀。"]'),
('a2332963-d985-4439-a339-b451226fbaa3','題東老庵','史功舉','宋','宋诗','song-poetry','','[]','弁山凝翠碧橫天，霅水開鑑流清泉。',180,'全唐诗/poet.song.217000.json','["弁山凝翠碧橫天，霅水開鑑流清泉。", "隠君東老志高潔，一庵結在青山邊。", "平生倒屣愛佳客，買書不惜傾囊錢。", "秋風八月酒初熟，邂逅有客來翩躚。", "豐姿灑落眼秋碧，太白邀飲清風前。", "欣然二翁話相得，醉來促席相留連。", "不覺達旦欲辭去，笑語拍手洪崖肩。", "逡巡灑翰落珠玉，藹藹態度含雲烟。", "更將禍福論天命，衣冠後世終榮傳。", "嗟乎東老今已矣，長有聲名伴山水。", "祇應驂鸞跨鶴蓬萊去，猶使鄉人指點庵前路。"]'),
('788fbfad-2ec8-4ecc-833a-275b951279b3','贈醫士','嚴嘉謀','宋','宋诗','song-poetry','','[]','脈差死活懸三指，灸誤風攣廢四肢。',32,'全唐诗/poet.song.217000.json','["脈差死活懸三指，灸誤風攣廢四肢。", "寧餌生金餐野葛，有身不可試庸醫。"]'),
('231894a3-59ea-429b-a001-80e26db02821','贈醫者川郭','嚴嘉謀','宋','宋诗','song-poetry','','[]','川郭顛强甚，平生挾術遊。',48,'全唐诗/poet.song.217000.json','["川郭顛强甚，平生挾術遊。", "老猶携侍女，貧不諂公俟。", "用藥多投病，酬錢或掉頭。", "金陵官酒貴，應典舊貂裘。"]'),
('70e2aecd-37bd-4f6d-a3bd-7cb190c45429','題浯溪中興頌二首  其一','陳容','宋','宋诗','song-poetry','','[]','銀旗金甲渡巴西，靈武城樓已萬幾。',64,'全唐诗/poet.song.217000.json','["銀旗金甲渡巴西，靈武城樓已萬幾。", "一札祗聞元帥命，五牋合待使臣歸。", "未聞請表更追表，且看黄衣換紫衣。", "天性非由人僞滅，何緣尚父結張妃。"]'),
('8498f455-6750-4e66-be7a-5b01fa99396c','題浯溪中興頌二首  其二','陳容','宋','宋诗','song-poetry','','[]','六等勝如誅獨柳，二張縱活亦何顔。',64,'全唐诗/poet.song.217000.json','["六等勝如誅獨柳，二張縱活亦何顔。", "太師死後猶書法，水部刑章托頌間。", "最憶海青投樂器，絕憐甄濟隠青山。", "中興碑下姦臣懼，天道何嘗不好還。"]'),
('be396fe2-7b0c-429a-a903-c541ed4e6ec7','題靈豐廟壁','陳容','宋','宋诗','song-poetry','','[]','紫馬仙人跨白犀，繙經臺映釣魚磯。',32,'全唐诗/poet.song.217000.json','["紫馬仙人跨白犀，繙經臺映釣魚磯。", "千年老樹風雷坼，獨有紅泉洗斷碑。"]'),
('9b03b171-9810-490f-8450-bc44f0c8751f','爲人賦橫舟二首  其一','陳容','宋','宋诗','song-poetry','','[]','古悲歌，淚如血，渡河無船氣欲絕。',144,'全唐诗/poet.song.217000.json','["古悲歌，淚如血，渡河無船氣欲絕。", "古非歌，淚如泉，河激湯湯聲徹天。", "峨舸大艑載琛貝，錦纜迷樓催管弦。", "人生苦樂不相等，風波血刃蛟流涎。", "神虺九首能三足，巨鼇觸怒群帝遷。", "縱有扁舟竟何往，乘桴意在滄洲上。", "祇緣轍朽無人知，入海居夷每惆悵。", "三間破屋名橫舟，三呼不答江水流。", "一帆徑渡溯天去，不繫斜陽古渡頭。"]'),
('0cba05d1-3bbc-4c1d-98c5-2bac192b7c50','爲人賦橫舟二首  其二','陳容','宋','宋诗','song-poetry','','[]','黄頭子，捩柁聽吾語。',188,'全唐诗/poet.song.217000.json','["黄頭子，捩柁聽吾語。", "三老駕三翼，疊鼓峭帆看風色。", "一千水，歸黄河，世無客星泛靈槎。", "恒河水，波斯匿王母將去，六十年間成壞故。", "性無生滅河水似，黄面瞿曇以筏諭。", "長淮水，一箭許，邊城白骨多於土。", "年年調舟已成泥，壽蔡孤城付朝暮。", "岷江漢源天上來，一夕不保如風埃。", "重慶今爲天下首，漢中不復言規恢。", "朽木爲舟土爲楫，白波如山水皆立。", "當時商家畚築子，夢裏撐船濟川去。", "只今無夢豈無舟，水淺都非泊舟處。"]'),
('e6997601-a5ae-4f18-b897-cf48326f4cca','題雲龍圖','陳容','宋','宋诗','song-poetry','','[]','騎元氣，游太空。',24,'全唐诗/poet.song.217000.json','["騎元氣，游太空。", "普厥施，收成功。", "抉河漢，觸華嵩。"]'),
('8d135bea-0470-4f64-aa38-0f5a5ab89890','它山堰','陳坰','宋','宋诗','song-poetry','','[]','堰雷推動阿香車，惠澤均霑十萬家。',32,'全唐诗/poet.song.217000.json','["堰雷推動阿香車，惠澤均霑十萬家。", "誰任長官身後責，迴潮今又見迴沙。"]'),
('884979e1-bb74-415d-8308-8c5b56393402','挽故知容州朝請陶公五首  其一','羅一龍','宋','宋诗','song-poetry','','[]','古貌如公更古心，宦情終淺道情深。',32,'全唐诗/poet.song.217000.json','["古貌如公更古心，宦情終淺道情深。", "區區飽煖何曾計，一字廉稱值萬金。"]'),
('2de9e852-aaca-4fdc-ac0b-a5eeb77fd42c','挽故知容州朝請陶公五首  其二','羅一龍','宋','宋诗','song-poetry','','[]','幕府當年譽四馳，諸公每恨識之遲。',32,'全唐诗/poet.song.217000.json','["幕府當年譽四馳，諸公每恨識之遲。", "長材若肯爲時用，世上何官不可爲。"]'),
('362de83d-c744-4e82-a8eb-a0af07cb29fc','挽故知容州朝請陶公五首  其三','羅一龍','宋','宋诗','song-poetry','','[]','盡說休官靖節賢，幾人真箇隠林泉。',32,'全唐诗/poet.song.217000.json','["盡說休官靖節賢，幾人真箇隠林泉。", "如今却有雲仍在，牢在平塘十五年。"]'),
('cabdafee-3051-4375-a961-df74b7cfd7c4','挽故知容州朝請陶公五首  其四','羅一龍','宋','宋诗','song-poetry','','[]','剖竹公符墨未乾，先生雅意只青山。',32,'全唐诗/poet.song.217000.json','["剖竹公符墨未乾，先生雅意只青山。", "瀟然紙帳梅花夢，不到清香畫戟間。"]'),
('ba576fee-213f-4ab4-b786-7eccae53cb07','挽故知容州朝請陶公五首  其五','羅一龍','宋','宋诗','song-poetry','','[]','平生心事辱相知，矻矻逢人說項斯。',32,'全唐诗/poet.song.217000.json','["平生心事辱相知，矻矻逢人說項斯。", "可恨襄陽失龐老，朔風吹淚送靈轜。"]'),
('100760b7-7b7b-4ad5-bb0c-78105ffc3c41','卧羊山','鄭士懿','宋','宋诗','song-poetry','','[]','見羊疑是已叱石，見石翻疑未叱羊。',32,'全唐诗/poet.song.217000.json','["見羊疑是已叱石，見石翻疑未叱羊。", "非石非羊何所見，這些意思難商量。"]'),
('b1e585b5-064a-4298-ae92-46b3de29d860','和徐夢發題超覽亭','鄭士懿','宋','宋诗','song-poetry','','[]','幾年江海客，復此預筵賓。',48,'全唐诗/poet.song.217000.json','["幾年江海客，復此預筵賓。", "地勝山川別，天晴草樹新。", "高歌千佛駭，一笑萬家春。", "珍重梁間扁，時時爲掃塵。"]'),
('7e636146-d5cd-4a5c-9b8a-267d8344d259','題壁二首  其一','胡叔陽子','宋','宋诗','song-poetry','','[]','知君色慾未能除，好把精神契太初。',32,'全唐诗/poet.song.217000.json','["知君色慾未能除，好把精神契太初。", "從今發誓休貪慾，我保教君入太虛。"]'),
('f1c7fb26-2f78-44a6-878b-5eeb4c1720c1','題壁二首  其二','胡叔陽子','宋','宋诗','song-poetry','','[]','奉崇香火若君難，莫把經文作戲言。',32,'全唐诗/poet.song.217000.json','["奉崇香火若君難，莫把經文作戲言。", "兒女損休都管盡，明春速入武當山。"]'),
('c054a8d9-5fa4-4f42-8dde-ea80de5e7177','挽文朝奉','李迪','宋','宋诗','song-poetry','','[]','散盡黄金爲買書，時人笑我太癡愚。',64,'全唐诗/poet.song.217000.json','["散盡黄金爲買書，時人笑我太癡愚。", "一朝有子如堯叟，何處無人說老蘇。", "可謂死而無憾者，孰云文不在茲乎。", "淵明地下聞君葬，也散黄花作淚珠。"]'),
('2ea121d8-e816-418b-86eb-dad1047c95a7','自題愛梅','李迪','宋','宋诗','song-poetry','','[]','我被梅花惱幾年，梅花纔發便詩顛。',32,'全唐诗/poet.song.217000.json','["我被梅花惱幾年，梅花纔發便詩顛。", "月明遶却梅花樹，直入梅花影裏眠。"]'),
('0059710c-90bb-4b6e-b901-8810aad671fe','萍','李迪','宋','宋诗','song-poetry','','[]','泥滓根萌淺，風波性質輕。',24,'全唐诗/poet.song.217000.json','["泥滓根萌淺，風波性質輕。", "晚來堆岸曲，猶得護蛙鳴。"]'),
('6ad1f782-a3fa-486c-9556-98a587f8525e','句','李迪','宋','宋诗','song-poetry','','[]','日烘麗萼紅縈火，雨過菖條綠噴烟。',16,'全唐诗/poet.song.217000.json','["日烘麗萼紅縈火，雨過菖條綠噴烟。"]'),
('22ce3e64-cd8b-4815-866f-5a75d9bbae96','爲子姪入宗學賦二首志喜  其一','趙必蒸','宋','宋诗','song-poetry','','[]','月露才華錦繡章，麟經家學獨誇長。',32,'全唐诗/poet.song.217000.json','["月露才華錦繡章，麟經家學獨誇長。", "笑談鏖戰聯三捷，此是男兒立志强。"]'),
('ea797044-fe9c-44b5-a857-046a61a81cb6','爲子姪入宗學賦二首志喜  其二','趙必蒸','宋','宋诗','song-poetry','','[]','采芹今已入宮牆，不負平生志氣昂。',32,'全唐诗/poet.song.217000.json','["采芹今已入宮牆，不負平生志氣昂。", "更擬來科應特奏，光榮宗室姓名香。"]'),
('91629ab9-efbd-42ae-8362-380c2bb39fd3','答賀文杏堂韻','趙必蒸','宋','宋诗','song-poetry','','[]','文杏堂開華渡西，九天雨露正來肥。',64,'全唐诗/poet.song.217000.json','["文杏堂開華渡西，九天雨露正來肥。", "漫誇奕葉光先宅，却羨新裁出故知。", "千載暖回唐苑樹，一時春足謝家枝。", "欲將俚語依金玉，把盞共論覺醉遲。"]'),
('bd709343-dc11-4fc7-bdb1-f91452ef0fc6','星渚趙侍郎霞城枉駕','趙必蒸','宋','宋诗','song-poetry','','[]','高情瀟灑出風塵，華轂傳呼下士頻。',32,'全唐诗/poet.song.217000.json','["高情瀟灑出風塵，華轂傳呼下士頻。", "獨愧迂疎無別技，鴻飛冥冥任吾真。"]'),
('b91acb92-09fc-4d7b-882f-3e3e9942a706','答資政趙庸齋','趙必蒸','宋','宋诗','song-poetry','','[]','樗櫟慚非梁棟材，自甘落拓困塵埃。',32,'全唐诗/poet.song.217000.json','["樗櫟慚非梁棟材，自甘落拓困塵埃。", "明公終日垂青眼，皓首窮年志欲灰。"]'),
('969f0abc-ff1c-46a3-821c-606de1174af9','憶業師劉夫子','趙必蒸','宋','宋诗','song-poetry','','[]','嚴風砭肌骨，怵然起遐思。',84,'全唐诗/poet.song.217000.json','["嚴風砭肌骨，怵然起遐思。", "哲人已久萎，誰可作聖儀。", "吾虞劉夫子，曰維百世師。", "秉直疾邪佞，是非無所私。", "依歸良有在，出處各以時。", "遭時復不偶，竟爾相睽違。", "四顧寂似闐，中心重凄其。"]'),
('d2e1c2a6-66a3-43af-84fb-4c956617807d','題榕陰圖','胡大用','宋','宋诗','song-poetry','','[]','權臣擅命久心傷，賊主之兄意未涼。',64,'全唐诗/poet.song.217000.json','["權臣擅命久心傷，賊主之兄意未涼。", "今日封章期救死，明朝削籍自投荒。", "九重偶眩誣賢舌，四海皆知疾惡腸。", "事久劃逢天一笑，錫知剛簡易名香。"]'),
('9c3f1c3a-aaf4-4978-89fb-533de32a4773','短歌行','羅與之','宋','宋诗','song-poetry','','[]','金谷桃李叢，畚插費培植。',72,'全唐诗/poet.song.217000.json','["金谷桃李叢，畚插費培植。", "寒冰猶未泮，花葉已薿薿。", "貞松生南山，石老厥土瘠。", "春回氣尚淺，生意幾欲息。", "東皇本無私，託根異形色。", "曾謂天地功，不及糞壤力。"]'),
('6621bdf0-a19d-4064-94eb-01dcca59ef90','寄衣曲  其一','羅與之','宋','宋诗','song-poetry','','[]','憶郎赴邊城，幾彀秋砧月。',24,'全唐诗/poet.song.217000.json','["憶郎赴邊城，幾彀秋砧月。", "若無鴻雁蜚，生離即死別。"]'),
('8b3b8061-1896-4509-b318-3598c6a479ae','寄衣曲  其二','羅與之','宋','宋诗','song-poetry','','[]','愁腸結欲斷，邊衣猶未成。',24,'全唐诗/poet.song.217000.json','["愁腸結欲斷，邊衣猶未成。", "寒窗剪刀落，疑是劍鐶聲。"]'),
('df015b8b-8db3-49c8-9c8c-85dfce8de8f5','寄衣曲  其三','羅與之','宋','宋诗','song-poetry','','[]','此身倘長在，敢恨歸無日。',24,'全唐诗/poet.song.217000.json','["此身倘長在，敢恨歸無日。", "但願郎防邊，似妾縫衣密。"]'),
('b3193783-1dfd-4966-b6fd-b17d7ae3f01c','舟次赤壁','羅與之','宋','宋诗','song-poetry','','[]','吳王峴畔泛川流，赤壁磯頭半日遊。',64,'全唐诗/poet.song.217000.json','["吳王峴畔泛川流，赤壁磯頭半日遊。", "勝地空餘豪傑迹，扁舟不載古今愁。", "極知風景終無異，莫念天時逝不留。", "傷事傷懷長太息，靜看江面沒浮漚。"]'),
('5e65858d-7bdc-4a4d-b63d-eeccf15a22cd','束擔','羅與之','宋','宋诗','song-poetry','','[]','束擔出荆扉，征塵染敝衣。',48,'全唐诗/poet.song.217000.json','["束擔出荆扉，征塵染敝衣。", "人憐雙鬢改，我悟半生非。", "抱璞今誰訴，知音古亦稀。", "尋思無一可，吾道欲安歸。"]'),
('b85662c4-9cdf-4477-9f86-3fb4f0f14f5b','旅思','羅與之','宋','宋诗','song-poetry','','[]','荏苒秋光老，空濛曉色奇。',48,'全唐诗/poet.song.217000.json','["荏苒秋光老，空濛曉色奇。", "霜嚴雀語澀，風定雁飛遲。", "旅思荒烟底，鄉心野水涯。", "夢歸歸未得，愁極祗顰眉。"]'),
('ef862f20-a522-44fb-b15e-3bbd7bfc1d63','送春','羅與之','宋','宋诗','song-poetry','','[]','政是風光欲別時，可堪烟外雨絲絲。',64,'全唐诗/poet.song.217000.json','["政是風光欲別時，可堪烟外雨絲絲。", "怕看太白餘春賦，嫌誦淵明止酒詩。", "晝短擬教持蠟炬，愁深悔不下書帷。", "自知無計能遮道，任作園林隔歲期。"]'),
('d9516b80-7821-49c6-9ddd-f2ee719ce854','黄鶴樓','羅與之','宋','宋诗','song-poetry','','[]','翬飛棟宇據城端，車馬塵中得異觀。',64,'全唐诗/poet.song.217000.json','["翬飛棟宇據城端，車馬塵中得異觀。", "雙眼莫供淮地闊，一江不盡蜀波寒。", "老仙橫笛月亭午，騷客懷鄉日欲殘。", "獨撫遺蹤增慨慕，徘徊不忍下層欄。"]'),
('cb210105-987b-4171-b68e-16deb2cc6823','玉梁道中雜詠  其一','羅與之','宋','宋诗','song-poetry','','[]','一別三會峰，轉燭閲半紀。',48,'全唐诗/poet.song.217000.json','["一別三會峰，轉燭閲半紀。", "山根石上苔，已沒舊屐齒。", "摩挲青青松，彼樹猶如此。", "睠言枕清流，爲洗囂塵耳。"]'),
('cf23c950-b2b8-4ab0-add8-3cd2abafc879','玉梁道中雜詠  其二','羅與之','宋','宋诗','song-poetry','','[]','清商從西來，剌剌滿林塢。',48,'全唐诗/poet.song.217000.json','["清商從西來，剌剌滿林塢。", "草木倏變衰，柯葉不相顧。", "昔時翳空雲，今作連山雨。", "菊花猶强項，籬邊爭媚嫵。"]'),
('ab11702a-d558-48b7-a9df-fb05c44ffe34','玉梁道中雜詠  其三','羅與之','宋','宋诗','song-poetry','','[]','片石能邀人，憇此兩足趼。',48,'全唐诗/poet.song.217000.json','["片石能邀人，憇此兩足趼。", "忽逢黄冠師，對語白雲巘。", "眼中景物饒，恨我蓬蓽遠。", "躊躇不忍去，泉石倘可剪。"]'),
('daadc8e4-879a-40ef-b5c7-781a85ec5a9b','玉梁道中雜詠  其四','羅與之','宋','宋诗','song-poetry','','[]','峭壁圍莽蒼，荒蹊人削跡。',48,'全唐诗/poet.song.217000.json','["峭壁圍莽蒼，荒蹊人削跡。", "時聞蘆葦叢，野鳥話岑寂。", "浮生雖有涯，幽討當無極。", "御風獨長嘯，此心謝鞿馽。"]'),
('d840207f-dce8-46e7-adb3-527055f5a490','玉梁道中雜詠  其五','羅與之','宋','宋诗','song-poetry','','[]','曉霜媒薄寒，巖壑失故綠。',48,'全唐诗/poet.song.217000.json','["曉霜媒薄寒，巖壑失故綠。", "輕飈振槁葉，唱徹陽關曲。", "秋光何足憐，嗟此歲事促。", "愁吟思無聊，日沒西山麓。"]'),
('c706f38b-1425-4f7e-b533-24d94a6cd92c','玉梁道中雜詠  其六','羅與之','宋','宋诗','song-poetry','','[]','泠泠澗底泉，破碎山根翠。',48,'全唐诗/poet.song.217000.json','["泠泠澗底泉，破碎山根翠。", "似欲留佳客，曲折二十四。", "我行無定止，蠟屐信所詣。", "偶來倏舍去，乘興聊復爾。"]'),
('c8879503-f371-41ab-9879-e955b3b1f9eb','玉梁道中雜詠  其七','羅與之','宋','宋诗','song-poetry','','[]','支枕郁木山，月色瑩如洗。',48,'全唐诗/poet.song.217000.json','["支枕郁木山，月色瑩如洗。", "林幽枕席清，景勝魂夢偉。", "丁當鳥忽啼，令我驚欲起。", "金丹事可期，永願供薪水。"]'),
('ccd5507a-d345-4cd8-9cbd-80ca446e3fe0','玉梁道中雜詠  其八','羅與之','宋','宋诗','song-poetry','','[]','乾坤掃陰霾，晴色敞幽谷。',48,'全唐诗/poet.song.217000.json','["乾坤掃陰霾，晴色敞幽谷。", "山川薦秋容，奇秀若可匵。", "千巖寄一筇，萬里付雙目。", "行行翠烟中，日與清景逐。"]'),
('7a7de452-45e5-41ed-b7eb-9887f11b794d','玉梁道中雜詠  其九','羅與之','宋','宋诗','song-poetry','','[]','濛鴻玉梁境，縹緲雲霞仙。',48,'全唐诗/poet.song.217000.json','["濛鴻玉梁境，縹緲雲霞仙。", "月壇白雲洞，遺址空依然。", "千年唯亂石，蹲踞秋山烟。", "徘徊莫可覓，酌盡丹井泉。"]'),
('6c5a9530-dc34-44c5-bd01-aa121ec49b41','玉梁道中雜詠  其一○','羅與之','宋','宋诗','song-poetry','','[]','塵坌不可耐，飄然入林坰。',48,'全唐诗/poet.song.217000.json','["塵坌不可耐，飄然入林坰。", "稍覺道心勝，漸至詩脾清。", "靜極生孤愁，耿耿難爲情。", "喧寂兩莫愜，吾意何由平。"]'),
('f9764934-b3bc-43fc-98d2-ff1c2d663a0b','春殘','羅與之','宋','宋诗','song-poetry','','[]','林端啼鴂損年芳，洞口空憐野水香。',64,'全唐诗/poet.song.217000.json','["林端啼鴂損年芳，洞口空憐野水香。", "人與落英兼寂寞，蝶隨飛絮兩彷徨。", "不因花事榮枯易，未覺春工代謝忙。", "却愛晚來風日暖，綠陰十丈漾橫塘。"]'),
('9bd61ff4-ed2a-4837-ad85-b7a09663178a','絕知','羅與之','宋','宋诗','song-poetry','','[]','羈旅日騷騷，人間事若毛。',48,'全唐诗/poet.song.217000.json','["羈旅日騷騷，人間事若毛。", "絕知操筆誤，深羨把犁高。", "百歲纔能幾，終朝强作勞。", "虛名竟何益，肯把換蒲萄。"]'),
('40037e96-6a65-4e68-98e2-9bbbd6b20f29','登玉笥山投龍洞','羅與之','宋','宋诗','song-poetry','','[]','捫蘿入幽谷，眼界益崢嶸。',48,'全唐诗/poet.song.217000.json','["捫蘿入幽谷，眼界益崢嶸。", "石壁斷人跡，泉流間鳥鳴。", "日高雲未散，秋晚草猶榮。", "坐久無歸意，悠然世念輕。"]'),
('707784c7-8d6c-4b92-a809-bf6ca2f7be45','閑立','羅與之','宋','宋诗','song-poetry','','[]','晚來閑立小溪邊，看徹遥峰入紫烟。',64,'全唐诗/poet.song.217000.json','["晚來閑立小溪邊，看徹遥峰入紫烟。", "四壁儘堪供我隠，一寒未至乞人憐。", "功名不與樽前事，時序寧知局上遷。", "可笑區區當世士，滿懷冰炭苦相煎。"]'),
('484063e2-84a9-42f0-a93f-f66ae462085e','下第西歸  其一','羅與之','宋','宋诗','song-poetry','','[]','拋却銀袍製芰荷，春風一曲紫芝歌。',32,'全唐诗/poet.song.217000.json','["拋却銀袍製芰荷，春風一曲紫芝歌。", "古來至寶多橫道，何事荆山泣卞和。"]'),
('61ed1e60-f155-471a-bbfa-ec0320a69b63','下第西歸  其二','羅與之','宋','宋诗','song-poetry','','[]','才難濟世甘避世，心不怨天唯樂天。',32,'全唐诗/poet.song.217000.json','["才難濟世甘避世，心不怨天唯樂天。", "林下山間深密處，曲肱飲水興悠然。"]'),
('0ea7fe38-9625-4c03-bace-9d81f6153745','江行阻風小市','羅與之','宋','宋诗','song-poetry','','[]','弭棹黄蘆外，江雲繞柂牙。',48,'全唐诗/poet.song.217000.json','["弭棹黄蘆外，江雲繞柂牙。", "寒深身軫粟，風急浪生花。", "日暮人收市，年窮客念家。", "倚篷無可奈，忍見後歸鴉。"]'),
('6e55e2e6-c586-45bc-ae49-70f210335fed','遊春','羅與之','宋','宋诗','song-poetry','','[]','春濃無處不相宜，草暖雲昏二月時。',64,'全唐诗/poet.song.217000.json','["春濃無處不相宜，草暖雲昏二月時。", "蝶舞花梢風細細，鶑啼柳底日遲遲。", "模將景物歸詩卷，判得光陰付酒巵。", "箇裏各隨人有得，五陵豪俠豈能私。"]'),
('879ce65d-bdb4-4dc3-8cc8-ccb883afd949','始見','羅與之','宋','宋诗','song-poetry','','[]','雪後寒猶勁，書窗怯暫開。',48,'全唐诗/poet.song.217000.json','["雪後寒猶勁，書窗怯暫開。", "因沽江畔酒，姑見竹間梅。", "歲月崢嶸去，衰頹次第來。", "誰能憂許事，杖屨且徘徊。"]'),
('57dd5116-7e04-47b8-992b-77fcbca4a280','山行  其一','羅與之','宋','宋诗','song-poetry','','[]','狂飈卷雨辨朝曦，似與新晴有會期。',32,'全唐诗/poet.song.217000.json','["狂飈卷雨辨朝曦，似與新晴有會期。", "秋水秋山秋草木，渾將乞與數篇詩。"]'),
('ccb38c77-448f-4ee2-b73f-51a80c941d44','山行  其二','羅與之','宋','宋诗','song-poetry','','[]','烟草凄迷露未晞，一筇伴我立晴暉。',32,'全唐诗/poet.song.217000.json','["烟草凄迷露未晞，一筇伴我立晴暉。", "丹楓雖老猶多態，散作漫山野蝶飛。"]'),
('2afb3ac0-c47b-49c1-9792-2a597a8b73be','山行  其三','羅與之','宋','宋诗','song-poetry','','[]','旆旆黄茆潑眼明，荒郊盡日絕人行。',32,'全唐诗/poet.song.217000.json','["旆旆黄茆潑眼明，荒郊盡日絕人行。", "誰知氣象蕭條處，賸有山川可鼎烹。"]'),
('309e8ee5-b0df-4694-a0aa-7db8554c0d09','山行  其四','羅與之','宋','宋诗','song-poetry','','[]','槁葉忘身絕澗流，蘆花摇手欲風休。',32,'全唐诗/poet.song.217000.json','["槁葉忘身絕澗流，蘆花摇手欲風休。", "羨渠山鳥渾無事，相對飛鳴草樹秋。"]'),
('6320a09a-0109-457f-abbf-7afdd837d34e','山行  其五','羅與之','宋','宋诗','song-poetry','','[]','片雲輕度半巖陰，巾屨俄驚翠靄深。',32,'全唐诗/poet.song.217000.json','["片雲輕度半巖陰，巾屨俄驚翠靄深。", "澗底寒泉知客懶，石根㶁㶁自長吟。"]'),
('c1e62f26-c277-4582-b5d7-b88ae7a77eec','山行  其六','羅與之','宋','宋诗','song-poetry','','[]','烏藤落手野烟開，水秀山明入望來。',32,'全唐诗/poet.song.217000.json','["烏藤落手野烟開，水秀山明入望來。", "舊日經行曾著語，試看石壁已莓苔。"]'),
('698913b1-62ec-4f2d-b5d4-c3882c1fb98b','山行  其七','羅與之','宋','宋诗','song-poetry','','[]','盡日留連興未闌，寒鴉背負夕陽還。',32,'全唐诗/poet.song.217000.json','["盡日留連興未闌，寒鴉背負夕陽還。", "遥知今夜空窗夢，只在江南水石間。"]'),
('d82f46ad-880c-435d-adcf-7ebce9a239ba','客裏','羅與之','宋','宋诗','song-poetry','','[]','客裏愁濃處，秋宵月欲斜。',48,'全唐诗/poet.song.217000.json','["客裏愁濃處，秋宵月欲斜。", "雁聲頻到枕，蝶夢未還家。", "世有多歧苦，人因一念差。", "遥思林下去，蓑笠釣烟沙。"]'),
('9ecfef03-4588-4350-9f07-64b1766b4f97','寄玉笥蕭高士','羅與之','宋','宋诗','song-poetry','','[]','滴露謄真誥，蕭然莫與群。',48,'全唐诗/poet.song.217000.json','["滴露謄真誥，蕭然莫與群。", "新詩高似月，世念薄於雲。", "俗走堪憐我，閑眠極羨君。", "唯餘綠綺韻，惆悵未曾聞。"]'),
('1963fb4f-2be9-4a7a-a4fd-4e5ab80fa895','尋芳','羅與之','宋','宋诗','song-poetry','','[]','尋芳自勒青絲鞚，日暖烟濃春意重。',32,'全唐诗/poet.song.217000.json','["尋芳自勒青絲鞚，日暖烟濃春意重。", "晚來被酒卧花陰，流鶑喚醒東風夢。"]'),
('61135514-55c3-42c3-9deb-5b691bf2dd13','桂花爛熳一夕敗於風雨呼僮掃落英以供香事戲作古句','羅與之','宋','宋诗','song-poetry','','[]','小山涼風高，秋意饒庭砌。',144,'全唐诗/poet.song.217000.json','["小山涼風高，秋意饒庭砌。", "江南山水秀，鍾此數叢桂。", "亭亭蒼虯蟠，磊磊栗玉綴。", "薰染風露香，擺脫脂粉媚。", "芙蓉已無秋，籬菊極羞愧。", "幽芳蕙百畝，香味亦瑣細。", "孰知標格奇，自取造物忌。", "狂風挾怪雨，族滅無噍類。", "纔憐金作屋，俄驚粟布地。", "姿容就枯槁，氣骨尚奇異。", "如彼死諸葛，凜凜有生意。", "試炷博山火，來參烟一燧。"]'),
('5a7da054-61fc-49b4-a3f4-0303d537f93a','喚我','羅與之','宋','宋诗','song-poetry','','[]','晴空喚我出柴扉，山色留人倚落暉。',64,'全唐诗/poet.song.217000.json','["晴空喚我出柴扉，山色留人倚落暉。", "春意已隨流水去，晚風忍挾亂花飛。", "尋思樂事唯心在，惆悵良辰與願違。", "尚有扁舟奇絕處，江南水暖鱖魚肥。"]'),
('7d0d49cf-c194-42b0-ba9d-5ca7dfa48226','客行','羅與之','宋','宋诗','song-poetry','','[]','客行困泥潦，山堠不勝長。',48,'全唐诗/poet.song.217000.json','["客行困泥潦，山堠不勝長。", "孰使雨點暴，更令風力狂。", "時危嫌店遠，日暮覺程忙。", "身世摧頹甚，艱難已備嘗。"]'),
('e64b24ab-02f9-4359-82d8-40a63ec55392','山居閑思  其一','羅與之','宋','宋诗','song-poetry','','[]','雲散山月吐，星稀山月高。',24,'全唐诗/poet.song.217000.json','["雲散山月吐，星稀山月高。", "相羊風露底，望月誦離騷。"]'),
('67ee4609-2e50-45a8-84dc-7d1cbaa828fe','山居閑思  其二','羅與之','宋','宋诗','song-poetry','','[]','菡萏兒女態，舂鋤金石交。',24,'全唐诗/poet.song.217000.json','["菡萏兒女態，舂鋤金石交。", "晚來微雨過，凉思滿蒲梢。"]'),
('bc2e2256-cb7b-4e2d-9d2c-9c2862c8b21f','山居閑思  其三','羅與之','宋','宋诗','song-poetry','','[]','雨作糟牀注，秋生鱸鱠思。',24,'全唐诗/poet.song.217000.json','["雨作糟牀注，秋生鱸鱠思。", "卷簾了清景，沉水裊烟絲。"]'),
('a6bea387-a836-4cb3-a670-79dfaffbe4ff','夢迴','羅與之','宋','宋诗','song-poetry','','[]','酒薄難成醉，輕寒襲破衾。',48,'全唐诗/poet.song.217000.json','["酒薄難成醉，輕寒襲破衾。", "夢迴孤客枕，聽徹草蟲吟。", "寂莫三秋夜，凄凉一片心。", "山林與朝市，底處豁愁襟。"]'),
('ac8f99ea-edbc-42f9-a11b-a8fad04cfe09','夏雨','羅與之','宋','宋诗','song-poetry','','[]','飄忽回風起，差池高鳥翔。',48,'全唐诗/poet.song.217000.json','["飄忽回風起，差池高鳥翔。", "雲攘千嶺碧，雨獻一天涼。", "飽意歸田畝，歡悰入醉鄉。", "忽思素秋氣，蕭瑟滿空堂。"]'),
('f9997312-f84a-4fb0-a455-e51976ed56d7','展轉','羅與之','宋','宋诗','song-poetry','','[]','郵亭徹夜聽秋聲，展轉藜牀直到明。',32,'全唐诗/poet.song.217000.json','["郵亭徹夜聽秋聲，展轉藜牀直到明。", "月白霜輕寒剪剪，築成萬里客愁城。"]'),
('6f611d9b-7a52-458d-ace9-aa05a2de4110','寄企梅兄','羅與之','宋','宋诗','song-poetry','','[]','朱墨叢中不憚勞，騞然聊試發硎刀。',64,'全唐诗/poet.song.217000.json','["朱墨叢中不憚勞，騞然聊試發硎刀。", "得時行道官無小，與物爲春政自高。", "閑對崆峒餐秀色，醉濡章貢助吟毫。", "自憐無計相從去，十八灘頭泛一舠。"]'),
('92603347-9d9c-468c-ae63-99652a3857ab','中秋步月  其一','羅與之','宋','宋诗','song-poetry','','[]','林間一葉秋，屏去三伏暑。',48,'全唐诗/poet.song.217000.json','["林間一葉秋，屏去三伏暑。", "淒然風露繁，絺綌莫能禦。", "炎涼相推移，胡爲遽如許。", "孰知秋已半，今夕四十五。"]'),
('c04dad3b-4a00-4e35-856f-66c836f678f2','中秋步月  其二','羅與之','宋','宋诗','song-poetry','','[]','幽人披襟來，步此一庭月。',48,'全唐诗/poet.song.217000.json','["幽人披襟來，步此一庭月。", "如渡滹沱冰，似泛山陰雪。", "誰將羌管急，間彼鄰杵切。", "冉冉秋思生，令人欲愁絕。"]'),
('9740b7f7-e9eb-4df9-a75c-782cfc1bdcec','中秋步月  其三','羅與之','宋','宋诗','song-poetry','','[]','空山本無塵，況復值良夜。',48,'全唐诗/poet.song.217000.json','["空山本無塵，況復值良夜。", "風清月色佳，圭璧不當價。", "徐行苔逕間，小立林影下。", "飄飄意欲仙，舉手人世謝。"]'),
('c3bd94fc-b403-4052-93b3-02870b34aa10','中秋步月  其四','羅與之','宋','宋诗','song-poetry','','[]','光陰若劈箭，行樂常恐遲。',48,'全唐诗/poet.song.217000.json','["光陰若劈箭，行樂常恐遲。", "人生百歲客，擾擾竟何爲。", "四美古難并，千年調亦癡。", "麵生不我棄，邀月聊自怡。"]'),
('b94fba7d-1bfe-4ccc-9fd2-b8f4dcfa0a6c','中秋步月  其五','羅與之','宋','宋诗','song-poetry','','[]','景物與意會，撚髯聲悲鳴。',48,'全唐诗/poet.song.217000.json','["景物與意會，撚髯聲悲鳴。", "一語得總持，萬狀就使令。", "以我詩思苦，賞此秋月明。", "今□月影裏，幾人同此情。"]'),
('cf1c36fb-4cce-46b9-a533-195e6a57256d','姑蘇道中','羅與之','宋','宋诗','song-poetry','','[]','滿眼菰蒲翠撲衣，雙雙沙鳥漾斜暉。',32,'全唐诗/poet.song.217000.json','["滿眼菰蒲翠撲衣，雙雙沙鳥漾斜暉。", "閑愁一段如冰釋，楊柳叢中出酒旗。"]'),
('c18c42be-645d-4fd6-a607-8220a97fc39e','信步','羅與之','宋','宋诗','song-poetry','','[]','信步獨幽尋，春山野霧深。',48,'全唐诗/poet.song.217000.json','["信步獨幽尋，春山野霧深。", "鳥啼如喚僕，泉響似鳴琴。", "日暖草爭秀，風狂花不禁。", "却嫌荒僻地，無酒與春斟。"]'),
('c17bfea3-9d1d-44ce-b7f4-9396f63027c9','泛舟秋懷','羅與之','宋','宋诗','song-poetry','','[]','白露消磨暑，丹楓點畫秋。',48,'全唐诗/poet.song.217000.json','["白露消磨暑，丹楓點畫秋。", "閑吟小山賦，歸思大江流。", "世盡營三窟，人誰樂一丘。", "篷窗有佳致，月朗政風休。"]'),
('5af28a79-0b0b-412d-9660-1c3a78119e45','木犀花  其一','羅與之','宋','宋诗','song-poetry','','[]','金粟如來澗壑姿，不隨桃李赴春期。',32,'全唐诗/poet.song.217000.json','["金粟如來澗壑姿，不隨桃李赴春期。", "江南花品秋居最，何況秋花中絕奇。"]'),
('fe18d9b9-a693-4dce-ad07-960b486ac609','木犀花  其二','羅與之','宋','宋诗','song-poetry','','[]','湯沐晴空顥露繁，清香十里壓旃檀。',32,'全唐诗/poet.song.217000.json','["湯沐晴空顥露繁，清香十里壓旃檀。", "紗窗夢覺秋風度，疑是移家住廣寒。"]'),
('04913624-73a1-4edb-a11a-2f66d9e1b70c','木犀花  其三','羅與之','宋','宋诗','song-poetry','','[]','秋影連蜷隠士攀，渾無蜂蝶涴林間。',32,'全唐诗/poet.song.217000.json','["秋影連蜷隠士攀，渾無蜂蝶涴林間。", "何人說與陶元亮，未必東籬勝小山。"]'),
('5700a5ba-47e5-4657-b37d-b343f398a932','山行愁思  其一','羅與之','宋','宋诗','song-poetry','','[]','日落烟欲橫，山寒翠將滴。',48,'全唐诗/poet.song.217000.json','["日落烟欲橫，山寒翠將滴。", "荒村渺愁人，跬步觸四塞。", "路遥兩髀酸，頗恨身不翼。", "舍策還悵然，倦倚松下石。"]'),
('4f67d103-a234-4283-95b6-71605bef4b00','山行愁思  其二','羅與之','宋','宋诗','song-poetry','','[]','明月印野水，暮色進旅愁。',48,'全唐诗/poet.song.217000.json','["明月印野水，暮色進旅愁。", "僕痡主亦疲，心口相怨尤。", "茅舍劣容膝，弛擔聊小休。", "會當理歸策，甘彼窮山囚。"]'),
('f1bff8fb-bd80-4475-b142-eb20ca1ede9b','夜宿郁木福地尚羊明月間遐想仙風得五十六字  其一','羅與之','宋','宋诗','song-poetry','','[]','騎氣乘雲事已灰，娟娟野月照蒼苔。',32,'全唐诗/poet.song.217000.json','["騎氣乘雲事已灰，娟娟野月照蒼苔。", "自憐不及壇前石，曾遇仙翁躡屐來。"]'),
('48a1e804-426e-41e9-97cb-a1b5a4c70e3d','夜宿郁木福地尚羊明月間遐想仙風得五十六字  其二','羅與之','宋','宋诗','song-poetry','','[]','淒涼風露濕人衣，猶自踟躇未忍歸。',32,'全唐诗/poet.song.217000.json','["淒涼風露濕人衣，猶自踟躇未忍歸。", "樹影忽來山月轉，悞驚鶴翅似輪飛。"]'),
('6ff427b4-f26f-4127-81a8-9478b01ef76b','閑居遣懷','羅與之','宋','宋诗','song-poetry','','[]','日暮掩松關，悠然謝往還。',48,'全唐诗/poet.song.217000.json','["日暮掩松關，悠然謝往還。", "停杯因待月，徙倚爲看山。", "貧悟道中樂，醉偷忙裏閑。", "耳根偏可意，風澗響潺潺。"]'),
('ae47da01-0f81-44d5-b677-2f20456f71d4','寂聊','羅與之','宋','宋诗','song-poetry','','[]','睡起和春倚小廊，寂聊情緒滿斜陽。',32,'全唐诗/poet.song.217000.json','["睡起和春倚小廊，寂聊情緒滿斜陽。", "園林已是花飛急，簾幕爭禁燕語忙。"]'),
('45f5d764-a8d2-4158-983c-2cb6e24f4856','書感','羅與之','宋','宋诗','song-poetry','','[]','設險重門未足憑，民心應自有長城。',64,'全唐诗/poet.song.217000.json','["設險重門未足憑，民心應自有長城。", "朝廷休戚視田野，宗社存亡非甲兵。", "氣實精神寧敝竭，本枯枝葉可敷榮。", "古人經理先觀勢，兩臂於韓孰重輕。"]'),
('79a957fa-1d3b-45c8-860d-a3a64c1ebe6d','蛾眉亭','羅與之','宋','宋诗','song-poetry','','[]','悠悠飛露滿汀洲，絕目蛾眉最上頭。',64,'全唐诗/poet.song.217000.json','["悠悠飛露滿汀洲，絕目蛾眉最上頭。", "對此江山還有月，知他世界盡無秋。", "情懷杜老鄜州夜，景物坡仙赤壁遊。", "長嘯劃然空谷應，風生浪涌不容留。"]'),
('347d040f-888a-4316-b8cc-1e2ce02993bf','動後','羅與之','宋','宋诗','song-poetry','','[]','莫作楊朱泣路岐，此心自被利名移。',64,'全唐诗/poet.song.217000.json','["莫作楊朱泣路岐，此心自被利名移。", "車奔寧是駕尼父，舟覆應非載伯夷。", "悔吝從來生動後，嘯歌元祗在閑時。", "可憐秦晉功成者，欲避危機已太遲。"]'),
('625e3c70-50fc-46c1-a2be-f2dbdfec13c5','文到','羅與之','宋','宋诗','song-poetry','','[]','簡編香外雨瓢翻，翰墨場中春日暄。',64,'全唐诗/poet.song.217000.json','["簡編香外雨瓢翻，翰墨場中春日暄。", "文到工時疑有助，道逢極處本無言。", "當年誰可輩任昉，後世人方怪屈原。", "勿謂詞章真小技，精粗徼妙豈殊根。"]'),
('99fe439a-ed15-4ef5-913b-0e6d24faecf0','臨流','羅與之','宋','宋诗','song-poetry','','[]','習習涼颸起素波，臨流解带小婆娑。',64,'全唐诗/poet.song.217000.json','["習習涼颸起素波，臨流解带小婆娑。", "秋光已共蘆花老，夜雨那勝落葉多。", "不覺儒酸同糾纏，極知妄想盡銷磨。", "笈中班史猶堪質，肯作商聲甯戚歌。"]'),
('9d7bb966-02b7-40b0-b66d-3f1c4335fe45','鳳凰臺閑眺臺前瞰軍壘有感而賦','羅與之','宋','宋诗','song-poetry','','[]','秋風携野客，杖屨鳳凰臺。',48,'全唐诗/poet.song.217000.json','["秋風携野客，杖屨鳳凰臺。", "忍見貔貅戍，更聞鴻雁來。", "時方憂大厦，世豈乏良才。", "何日覽輝至，龍文載九垓。"]'),
('459220fe-e161-4947-9c74-ecc5259732fb','爲言','羅與之','宋','宋诗','song-poetry','','[]','日薄寒濃春意微，花鬚柳眼尚依稀。',32,'全唐诗/poet.song.217000.json','["日薄寒濃春意微，花鬚柳眼尚依稀。", "爲言羯鼓休頻打，催得先開即早飛。"]'),
('4ba836ac-906e-404a-a8dc-c6816cbbd759','秋林','羅與之','宋','宋诗','song-poetry','','[]','秋晏玄雲瞀積陰，平蕪氣象極蕭森。',64,'全唐诗/poet.song.217000.json','["秋晏玄雲瞀積陰，平蕪氣象極蕭森。", "細看摇落風霜意，已見發生天地心。", "畢竟栽傾非外致，豈伊培覆自相尋。", "若教宋玉曾聞道，九辯悲思未遽深。"]'),
('58eaac52-0820-4241-8058-da5d5a31873e','卧疴','羅與之','宋','宋诗','song-poetry','','[]','六塵緣影政堪嗟，二豎乘虛勢益加。',64,'全唐诗/poet.song.217000.json','["六塵緣影政堪嗟，二豎乘虛勢益加。", "憶昔鼻頭能出火，即今眼底已生花。", "婦言伐性多因酒，醫戒傷生少試茶。", "悟罷本來安得病，角弓誰使認爲蛇。"]'),
('9f1f0a0d-da0a-4864-833a-f840723eb357','題采石李太白祠','羅與之','宋','宋诗','song-poetry','','[]','仙翁謫墮岷山下，逸氣如虹耿林罅。',176,'全唐诗/poet.song.217000.json','["仙翁謫墮岷山下，逸氣如虹耿林罅。", "萬言倚馬不作難，坐令神鬼皆驚嚇。", "翹翹車乘懸弓旌，疇咨時政肝膽明。", "和蕃書草金鑾殿，清平詞度沉香亭。", "聲華視漢媲黄綺，寶床賜食龍顔喜。", "掉頭歘作燕晉遊，却笑卿相紆朱紫。", "開元盈成亦已極，屏間山水代無逸。", "未必脫靴恨爾深，自是見幾不終日。", "錦袍錯落浮扁舟，呼兒買酒盟江鷗。", "天公似悔夜郎禍，明月已起烟波愁。", "采石青青三尺墓，至今祠祭勤呵護。"]'),
('a3334055-16ee-4db7-8b03-d284791416e7','長至書意','羅與之','宋','宋诗','song-poetry','','[]','萬草千花若死灰，陽和一氣已潜回。',32,'全唐诗/poet.song.217000.json','["萬草千花若死灰，陽和一氣已潜回。", "莫言舉世無先覺，幾處寒梢放野梅。"]'),
('e97a3f2d-9ea6-4b60-ab01-3edb49eb2cb1','商歌三首  其一','羅與之','宋','宋诗','song-poetry','','[]','東風滿天地，貧家獨無春。',24,'全唐诗/poet.song.217000.json','["東風滿天地，貧家獨無春。", "負薪花下過，燕語似譏人。"]'),
('ac30545a-e3ea-481d-8691-c8b99e21f56c','商歌三首  其二','羅與之','宋','宋诗','song-poetry','','[]','白屋釜生魚，青樓行細膾。',24,'全唐诗/poet.song.217000.json','["白屋釜生魚，青樓行細膾。", "靜思天地間，寧有私覆載。"]'),
('c4493b20-ffd8-4cf2-ba95-128951942ea2','商歌三首  其三','羅與之','宋','宋诗','song-poetry','','[]','門前桑柘枝，中有千錦機。',24,'全唐诗/poet.song.217000.json','["門前桑柘枝，中有千錦機。", "遊人不迴顧，桃李獨成蹊。"]'),
('bf78be6b-37f9-4b01-9b44-0699c5e402d5','却羨','羅與之','宋','宋诗','song-poetry','','[]','貴客寧知拂徵琴，郢人漫倚引商音。',64,'全唐诗/poet.song.217000.json','["貴客寧知拂徵琴，郢人漫倚引商音。", "那堪歲月化雙鬢，空有悲歡寄寸心。", "囊底有方餐白玉，牀頭無術致黄金。", "抗塵走俗曾何補，却羨鷦鷯託一林。"]'),
('092564fd-c827-49a7-bee7-a15b00fb5fbb','三高亭','羅與之','宋','宋诗','song-poetry','','[]','灼灼曾暉漸欲西，長橋弭棹倚欄時。',64,'全唐诗/poet.song.217000.json','["灼灼曾暉漸欲西，長橋弭棹倚欄時。", "湖光渺漭浮寒鑑，山色依稀抹黛眉。", "一舸功成非本志，三秋歸思亦何遲。", "始終唯有天隨子，笑却旌招理釣絲。"]'),
('0a67651b-e1e6-4070-8717-c979b1f3c988','花下歎','羅與之','宋','宋诗','song-poetry','','[]','人生何處較窮通，天意元難測始終。',32,'全唐诗/poet.song.217000.json','["人生何處較窮通，天意元難測始終。", "花落花開翻覆手，君看同此一春風。"]'),
('256cfa9e-a26f-465e-becd-91dd3f3e696e','林深','羅與之','宋','宋诗','song-poetry','','[]','林深氛雜不相關，衆建芳馨兩廡間。',64,'全唐诗/poet.song.217000.json','["林深氛雜不相關，衆建芳馨兩廡間。", "月榭琴彈新製曲，曉窗畫展舊遊山。", "凄凉風滿竹十箇，的皪春歸梅一班。", "可笑野人無繫累，機心猶在釣魚灣。"]'),
('8f9d18af-7c86-4839-8e9c-7b216562117d','纔是','羅與之','宋','宋诗','song-poetry','','[]','忍看繁紅委路塵，空餘野草綠無垠。',32,'全唐诗/poet.song.217000.json','["忍看繁紅委路塵，空餘野草綠無垠。", "人生憂樂何終極，纔是迎春又送春。"]'),
('23048b68-5147-4b43-9515-4938959f83a2','一夜','羅與之','宋','宋诗','song-poetry','','[]','潦收野水浄，雲陣布重陰。',48,'全唐诗/poet.song.217000.json','["潦收野水浄，雲陣布重陰。", "一夜西風急，千山落葉深。", "身猶衣暑服，耳已厭寒砧。", "對此無心者，還應雪滿簪。"]'),
('89293aa3-3297-41ec-884e-b0a808380fe5','寄遠詞','羅與之','宋','宋诗','song-poetry','','[]','寒梢蕭索風振林，蟪蛄切切語欲噤。',128,'全唐诗/poet.song.217000.json','["寒梢蕭索風振林，蟪蛄切切語欲噤。", "終宵展轉不能寐，遥憶良人戰場裏。", "陽關一別歸無期，翠烟幾度秋螢飛。", "當時手種合歡樹，今已蒼蒼雲雨垂。", "蜀錦裁書憑雁寄，那能道人意中事。", "深秋倘得未移軍，猶見幽閨數痕淚。", "居延城外刁斗聲，無定河邊霜月明。", "妾身雖老幸未死，何日中原賀太平。"]'),
('66a90e18-15a6-4539-b198-35e0e734e2ec','被酒','羅與之','宋','宋诗','song-poetry','','[]','人間笑口信難開，十事常嗟九不諧。',64,'全唐诗/poet.song.217000.json','["人間笑口信難開，十事常嗟九不諧。", "忙裏始知閑氣味，老來方見少情懷。", "清商憭慄歲無幾，玄髮蕭疏生有涯。", "誰謂伯倫聞見滅，却甘麯糵自沉埋。"]'),
('5ab36cfd-d0e4-4319-8aed-e52575574700','衛生','羅與之','宋','宋诗','song-poetry','','[]','屏去雞壅與豕零，試聽我誦衛生經。',64,'全唐诗/poet.song.217000.json','["屏去雞壅與豕零，試聽我誦衛生經。", "兩忘寵辱心源浄，一掃榮枯眼界明。", "酖毒不令生厚味，姦邪寧使出繁聲。", "冥鈞深養靈根固，四體調和血氣平。"]'),
('2b734835-6f8d-4047-bff3-bb551b8c471c','瀟湘道中','羅與之','宋','宋诗','song-poetry','','[]','客行適瀟湘，凄其歲云晏。',168,'全唐诗/poet.song.217000.json','["客行適瀟湘，凄其歲云晏。", "枯梢風騷勞，荒郊雲漶漫。", "摵摵雨聲急，皚皚雪花燦。", "抽縈泥途深，眇默山堠遠。", "日莫欲稅駕，天末扣孤館。", "米盡甑生塵，薪濕火不暖。", "此意對三閭，似結兩重案。", "人生如空華，百歲等抹電。", "那忍聽客塵，日夜苦相煎。", "懷安名所敗，飽食親孰顯。", "恭承古昔訓，險阻庸敢憚。", "信知有此身，乃是一大患。", "愁深不能寐，歌長未及亂。", "門前車鐸鳴，翰音復號旦。"]'),
('4d2f3212-9ea1-4047-98ba-9671c14fb184','看葉','羅與之','宋','宋诗','song-poetry','','[]','紅紫飄零草不芳，始宜撰杖向池塘。',32,'全唐诗/poet.song.217000.json','["紅紫飄零草不芳，始宜撰杖向池塘。", "看花應不如看葉，綠影扶疏意味長。"]'),
('34e36b4d-bb36-4b9d-803b-dccc33e6f877','談道','羅與之','宋','宋诗','song-poetry','','[]','休將視聽探希微，衆妙何嘗間險夷。',64,'全唐诗/poet.song.217000.json','["休將視聽探希微，衆妙何嘗間險夷。", "舍一而求非忽恍，自三以究豈支離。", "試看瓦礫道寧隠，若外筌蹄思益奇。", "熱即取凉寒向火，是中消息幾人知。"]'),
('34d25a15-7746-4047-95f1-8d7205dece07','己亥中秋','羅與之','宋','宋诗','song-poetry','','[]','此行不負中秋夜，采石江頭醉及晨。',64,'全唐诗/poet.song.217000.json','["此行不負中秋夜，采石江頭醉及晨。", "獨御涼風尋古跡，驚看明月照今人。", "詩騷寂寞雖云久，光景推移豈解陳。", "却怪悲鳴營度處，筆端何事竟無神。"]'),
('970a6918-93dc-4037-bdc6-abeae079c1de','虎溪','羅與之','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','衝飆吹客襟，飄拂虎溪渡。',120,'全唐诗/poet.song.217000.json','["衝飆吹客襟，飄拂虎溪渡。", "遠想三笑時，此意固有寓。", "孰知秘密藏，奚間笑默語。", "繩繩徹上下，綿綿貫今古。", "東林鐘聲幽，康廬山色嫮。", "是皆善知識，長時相警悟。", "世人自合塵，兩耳聾莫覷。", "百千微妙義，墮在一毫許。", "我行發深省，如重睡忽寤。", "向人欲舉似，有舌不能吐。"]'),
('1ce43cb4-6595-4b10-9f1d-de08c9c47f36','默坐','羅與之','宋','宋诗','song-poetry','','[]','厭調鞍馬佩金壺，默坐空窗氣晏如。',64,'全唐诗/poet.song.217000.json','["厭調鞍馬佩金壺，默坐空窗氣晏如。", "已覺胸襟忘得喪，那知花草就榮枯。", "絃何庸絕琴寧有，聲未曾銷塵本無。", "此語倘教遊子聽，料應誚我一何愚。"]'),
('a0c06c31-00f1-41c3-a70a-0f1266e6ade4','倦倚','羅與之','宋','宋诗','song-poetry','','[]','蟬聲燕語細相和，池面纔浮點點荷。',32,'全唐诗/poet.song.217000.json','["蟬聲燕語細相和，池面纔浮點點荷。", "倦倚闌干消永日，葡萄陰薄柳風多。"]'),
('9b5e7eb1-597d-4416-bc50-8ee123bbbd81','此悟','羅與之','宋','宋诗','song-poetry','','[]','遑遑偶偶亦堪悲，桀死堯生畢竟齊。',64,'全唐诗/poet.song.217000.json','["遑遑偶偶亦堪悲，桀死堯生畢竟齊。", "空羨駝峰烹翠釜，漫思鱸膾拌金齏。", "榮華代謝看荆棘，今古推遷望澗溪。", "造化密移於此悟，長歌拾穗任天倪。"]'),
('2269b0bb-b2c7-41ee-b72a-9ec4e50bb1c0','東冶亭','朱大德','宋','宋诗','song-poetry','','[]','東冶亭聯白下門，問誰走馬謝公墩。',32,'全唐诗/poet.song.217000.json','["東冶亭聯白下門，問誰走馬謝公墩。", "梅炎一樣摇蒲扇，惟有清風後代存。"]'),
('1208dc59-654d-41dc-89c4-579359de1e5e','靈巖','何子舉','宋','宋诗','song-poetry','','[]','靈巖之境最超卓，高隠翠微浸碧落。',324,'全唐诗/poet.song.217000.json','["靈巖之境最超卓，高隠翠微浸碧落。", "迢迢一逕倒青松，壁立危門敞虛閣。", "敞虛閣，見寥廓，萬疊青山連海角。", "山田疎密布棋文，行看遠近分鳬雀。", "入虛堂，真邃寞，太古以來天所鑿。", "上如屈曲老龍腰，下似空明巨鰲殻。", "豁然平鋪如琢削，低不礙人高可摸。", "洞徹中開隠籟傳，虛通遠映飛光鑠。", "煙嵐前後如簾幙，洞戶東西迢鎖鑰。", "明月宵涵兩玉壺，白雲曉度長銀索。", "壺天春秋長不惡，瓊室夏涼冬燠若。", "老僧雪夜不新爐，童子炎天尚狐貉。", "夜靜風清冰露薄，天碧境寒河漢爍。", "泠泠風吹叱斗牛，浩浩清聲生萬壑。", "我欲飛王喬之鳬，呼丁令之鶴。", "架羽仗之輕車，奏靈臺之妙樂。", "披星機繪素以爲衣，舉金莖沆瀣以爲酌。", "呼羣仙以遨遊，休此巖而宴樂。", "酒容漁父參，棋許樵夫著。", "不知烏之東飛，兔之西躍。", "相將遠逐無窮濱，逍遥永脫塵緣縛。"]'),
('e69491eb-bb6b-4840-9d31-a2ec62095d82','清渭八景 清渭晴嵐','何子舉','宋','宋诗','song-poetry','','[]','清渭盤旋似太行，嵐光過雨鬰蒼蒼。',64,'全唐诗/poet.song.217000.json','["清渭盤旋似太行，嵐光過雨鬰蒼蒼。", "氤氳如霧淩空起，縹緲隨風到處揚。", "谷轉孤村芳樹綠，水流雙澗落花香。", "興來秣馬尋高隠，泉石徜徉樂更長。"]'),
('a24d5dc1-660b-42c8-84eb-5d0aada7f932','清渭八景 箭山晚翠','何子舉','宋','宋诗','song-poetry','','[]','日落啣山照畫屏，箭山鬰鬰歲寒青。',64,'全唐诗/poet.song.217000.json','["日落啣山照畫屏，箭山鬰鬰歲寒青。", "昂霄巨榦成梁棟，裂石盤根長茯苓。", "風撼碧濤驚鶴夢，雷轟鐵鎖悅龍形。", "由來秀蔭觀音廟，血食千年顯電靈。"]'),
('a5670420-65ac-48ce-b8a3-d51b53a69f9e','清渭八景 北澗雙流','何子舉','宋','宋诗','song-poetry','','[]','華溪有水綠如苔，迎會雙溪右澗來。',64,'全唐诗/poet.song.217000.json','["華溪有水綠如苔，迎會雙溪右澗來。", "二派合流川兩道，四山環擁翠千堆。", "尋源未許停漁棹，修禊應堪泛羽杯。", "夾岸桃花開爛漫，落紅隨浪泛天台。"]'),
('d96e02c8-0d1d-43a7-a76d-0e8cfe5d2ceb','清渭八景 指崖一覽','何子舉','宋','宋诗','song-poetry','','[]','指崖屹立鎮山川，萬丈巍巍勢插天。',64,'全唐诗/poet.song.217000.json','["指崖屹立鎮山川，萬丈巍巍勢插天。", "風日雙清時有限，乾坤一覽景無邊。", "東西兩峴丹青獻，南北羣峰紫翠連。", "我欲淩風登絕頂，一聲鐵笛叫飛仙。"]'),
('484955ee-b985-4af9-8540-db20af1572e7','清渭八景 桐畈犁耕','何子舉','宋','宋诗','song-poetry','','[]','村北村南布穀聲，豳風歌罷足關情。',64,'全唐诗/poet.song.217000.json','["村北村南布穀聲，豳風歌罷足關情。", "携朋日向東園酌，佩犢時從谷口耕。", "花雨一犁春信早，稼雲萬頃歲功成。", "君王正此招賢用，胡不當初顯姓名。"]'),
('52e511bb-ddeb-413d-b5cd-1ba0549041bd','清渭八景 派溪釣隠','何子舉','宋','宋诗','song-poetry','','[]','派溪有水碧無瑕，結屋臨溪釣隠家。',64,'全唐诗/poet.song.217000.json','["派溪有水碧無瑕，結屋臨溪釣隠家。", "穉子敲鍼依柳樹，扁舟罷釣泊蘆花。", "子陵辭漢千年遠，尚父歸周兩鬢華。", "祇恐客星難障掩，一竿未足了生涯。"]'),
('ed333db1-6e4f-4efd-9ad2-271615b50693','清渭八景 大隴秋雲','何子舉','宋','宋诗','song-poetry','','[]','迢迢大隴似眠牛，多少村莊築此丘。',64,'全唐诗/poet.song.217000.json','["迢迢大隴似眠牛，多少村莊築此丘。", "玄室幽深埋玉樹，曉雲飛遶護松楸。", "栖遲每入林閒渺，變化長從海上浮。", "正是蒼生多渴望，作爲霖雨濟田疇。"]'),
('250a0fdb-2f74-4433-ad2e-673422b3fea4','清渭八景 高村夜月','何子舉','宋','宋诗','song-poetry','','[]','緩步高村納晚涼，徘徊更覺景難忘。',64,'全唐诗/poet.song.217000.json','["緩步高村納晚涼，徘徊更覺景難忘。", "一輪月照碧梧影，萬壑風飄丹桂香。", "蘇子何須遊赤壁，羣仙正好泛瓊觴。", "洞簫吹徹東方白，玉兔還留不夜光。"]'),
('08efbc0e-f689-492f-9c86-00bf51799d08','大滌洞','王成','宋','宋诗','song-poetry','','[]','得得籃輿躡紫烟，青山買斷不勞錢。',64,'全唐诗/poet.song.217000.json','["得得籃輿躡紫烟，青山買斷不勞錢。", "孤峰峭聳雲間柱，大滌深藏洞裏天。", "一派飛泉成舞翠，千尋秀石屢來賢。", "上方猶有奇觀在，更欲捫蘿到絕巔。"]'),
('0876e331-8932-4bad-95c0-bf85fd7ff923','出郊即事  其一','朱子恭','宋','宋诗','song-poetry','','[]','水滿牛耕犢後隨，早田大半已翻犁。',32,'全唐诗/poet.song.217000.json','["水滿牛耕犢後隨，早田大半已翻犁。", "趁時浸穀清明近，次第秧針綠又齊。"]'),
('f32c8ab3-b061-4e81-b5b7-0e2cbb76980a','出郊即事  其二','朱子恭','宋','宋诗','song-poetry','','[]','經行阡陌日遲遲，桑柘纔方吐綠枝。',32,'全唐诗/poet.song.217000.json','["經行阡陌日遲遲，桑柘纔方吐綠枝。", "只爲峭寒交節晚，村家却是拂蠶時。"]'),
('7ea40027-5406-4167-84cb-6f030fe6df0d','招義驛','朱子恭','宋','宋诗','song-poetry','','[]','霜林紅葉趁桐花，路轉崖根百尺斜。',32,'全唐诗/poet.song.217000.json','["霜林紅葉趁桐花，路轉崖根百尺斜。", "霽日斷雲成徙倚，湘南秋盡未還家。"]');
